  values
    ('era_divided_kingdom', '엘리야 승천: 겉옷의 계승', '엘리야는 떠나고, 엘리사는 겉옷과 사명을 이어받는다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「엘리야 승천」을 다룹니다.', '["길갈에서 늙은 엘리야가 엘리사에게 머물라고 말하지만, 젊은 엘리사는 엘리야의 겉옷을 붙잡고 끝까지 따르겠다는 단호한 얼굴로 선다", "요단강가에서 엘리야가 거친 털 겉옷으로 물을 치자 강물이 갈라지고, 엘리사와 선지자의 제자들은 놀라 바라본다", "불말과 불수레가 회오리바람 속에서 엘리야를 하늘로 데려가고, 엘리사는 슬픔과 경외로 손을 뻗는다. 엘리야의 부상이나 죽음은 보이지 않는다", "엘리사가 떨어진 엘리야의 겉옷을 들어 엘리야의 옷으로 요단 물을 치고, 갈라진 물길 속을 안전하게 건너는 장면"]'::jsonb, '["엘리사는 떠나는 엘리야에게 머물러 달라고 요청한다", "엘리야가 옷으로 물을 치자 강물이 갈라진다", "불말과 불수레가 회오리바람 속에서 엘리야를 하늘로 데려간다", "엘리사가 떨어진 엘리야의 겉옷을 들어 엘리야의 옷으로 요단 물을 치자 물이 갈라진다"]'::jsonb, '[["elijah", "elisha"], ["elijah", "elisha"], ["elijah", "elisha"], ["elisha"]]'::jsonb, ARRAY['elijah', 'elisha']::text[], '[{"book": "왕하", "from": "2:1", "to": "2:14"}]'::jsonb, -850, -850, 'approx', 16, 'divided_elijah_ahab_word', '엘리야 시대: 아합 집과 참 말씀', 2, 'lm_div_jordan_river', 'published'),
    ('era_exile_return', '율법 낭독: 울음에서 기쁨으로', '말씀이 낭독되자 백성은 울고, 지도자들은 ‘기쁨이 힘’이라 격려한다.', '포로와 귀환 시대는 바벨론 포로와 페르시아 때의 귀환을 다룹니다. 이 이야기는 「율법 낭독」을 다룹니다.', '["예루살렘 수문 앞 광장에서 에스라가 높은 나무 강단 위에 서서 율법 두루마리를 펼치고, 백성은 새벽부터 귀를 기울인다. 두루마리 글자는 읽히지 않는다", "율법을 들은 백성이 울기 시작하자 느헤미야와 레위 사람들이 손을 내밀어 그들을 다독이는 모습", "에스라와 느헤미야와 백성들이 음식을 나누어 먹고 몫이 없는 사람에게도 보내며, 울음이 기쁨으로 바뀐 얼굴들이 분명히 보인다"]'::jsonb, '["예루살렘 수문 앞 광장에서 에스라가 높은 나무 강단 위에 서서 율법 두루마리를 읽는다", "율법을 들은 백성이 울기 시작하자 느헤미야와 레위 사람들이 손을 내밀어 그들을 다독인다", "에스라와 느헤미야와 백성들이 음식을 나누어 먹고 몫이 없는 사람에게도 보낸다"]'::jsonb, '[["ezra"], ["nehemiah", "ezra"], ["ezra", "nehemiah"]]'::jsonb, ARRAY['ezra', 'nehemiah']::text[], '[{"book": "느", "from": "8:1", "to": "8:18"}]'::jsonb, -444, -444, 'approx', 16, 'exile_ezra_nehemiah_community', '에스라와 느헤미야의 공동체 회복', 3, 'lm_exi_jerusalem', 'published'),
    ('era_nt_post_apostolic', '인간의 죄와 하나님의 심판', '바울은 로마 성도들에게 모든 사람이 죄 아래 있으며 하나님의 의로운 심판 앞에 선다고 설명한다.', '로마서는 바울이 로마 방문을 앞두고, 유대인과 이방인이 함께 있던 로마 교회에 복음과 선교 계획을 설명하려고 쓴 편지입니다. 이 이야기는 「인간의 죄와 하나님의 심판」을 다룹니다.', '["바울이 고린도 숙소에서 로마로 보낼 편지를 쓰며, 무거운 표정으로 인간의 죄와 우상 숭배의 어두운 모습을 떠올리는 말풍선", "로마 거리의 화려한 조각상과 시장 앞에서 사람들은 자기 길을 자랑하지만, 바울은 멀리서 엄숙한 얼굴로 마음의 어둠을 바라본다", "유대인과 이방인 성도들이 나란히 서 있고, 바울은 두 무리 모두 하나님의 판단 앞에 선다는 듯 공평하게 양쪽을 바라본다. 바울의 위에는 십자가에 균형을 이루고 있는 저울이 나타난다"]'::jsonb, '["바울이 불의로 진리를 막는 자들의 불경건과 불의에 대해 하나님이 진노하심을 말한다", "불의와 악행과 탐욕과 악의로 가득찬 사람들에 대해 말한다", "바울은 결국 하나님의 심판 앞에 서게 됨을 말한다"]'::jsonb, '[["paul"], ["paul"], ["paul"]]'::jsonb, ARRAY['paul']::text[], '[{"book": "롬", "from": "1:8", "to": "2:29"}]'::jsonb, 57, 57, 'approx', 16, 'paul_churches_problems_hope', '바울이 세운 교회들의 문제와 소망', 2, 'lm_nt_post_rome', 'published'),
    ('era_nt_apostolic', '1차 전도 여행: 구브로 살라미와 바보', '바나바와 사울은 구브로에서 말씀을 전하고 바보에서 거짓 선지자의 방해를 넘어 총독이 믿게 된다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「차 전도 여행」을 다룹니다.', '["바나바와 사울과 마가 요한이 구브로 살라미의 회당 안에서 두루마리 성경을 펼쳐 유대인들에게 말씀을 전하고, 세 사람은 먼 길을 시작한 긴장과 결심이 담긴 표정이다", "바보의 총독 관저에서 엘루마가 총독 앞을 가로막고, 바울은 먼지 묻은 여행복 차림으로 한 손을 들어 단호하게 그를 꾸짖는다", "바울과 바나바가 지켜보는 앞에서 엘루마가 갑자기 앞을 보지 못해 손을 더듬고, 총독 서기오 바울은 두려움과 놀라움으로 몸을 뒤로 물린다", "총독 서기오 바울이 놀라 무릎을 굽히며 믿음을 받아들이고, 바울과 바나바는 먼지 묻은 여행복 차림으로 감사와 안도가 섞인 표정으로 선다"]'::jsonb, '["바나바와 사울과 마가 요한이 구브로 살라미의 회당 안에서 두루마리 성경을 펼쳐 유대인들에게 말씀을 전한다", "바보의 총독 관저에서 엘루마가 총독 앞을 가로막고 바울은 단호히 그를 꾸짖는다", "바울과 바나바가 지켜보는 앞에서 엘루마가 갑자기 앞을 보지 못해 손을 더듬다", "총독 서기오 바울이 놀라 무릎을 굽히며 믿음을 받아들인다"]'::jsonb, '[["paul", "barnabas", "john_mark"], ["paul", "barnabas"], ["paul", "barnabas"], ["paul", "barnabas"]]'::jsonb, ARRAY['paul', 'barnabas', 'john_mark']::text[], '[{"book": "행", "from": "13:4", "to": "13:12"}]'::jsonb, 46, 46, 'approx', 17, 'paul_first_journey', '바울의 1차 전도 여행', 2, 'lm_nt_ap_cyprus_salamis_paphos', 'published'),
    ('era_exodus', '가나안 정탐: 믿음과 두려움의 갈림길', '정탐꾼들의 보고 앞에서 백성은 두려움에 흔들리지만, 하나님은 믿음 없는 세대의 광야 길을 선언하신다.', '출애굽과 광야 여정은 이스라엘이 애굽을 떠나 시내산과 광야를 지나는 시기입니다. 이 이야기는 「가나안 정탐」을 다룹니다.', '["가데스 바네아 진영에서 모세가 가나안 땅을 정탐할 대표들을 보내고, 여호수아와 갈렙과 여러 정탐꾼들이 광야 길을 향해 출발한다", "여호수아와 갈렙을 포함한 정탐꾼들이 에스골 골짜기에서 큰 포도송이를 장대에 매달아 둘이 함께 들고 돌아오고, 멀리 가나안의 풍성한 골짜기가 보인다", "두려움에 찬 정탐꾼들이 견고한 성읍과 거대한 사람들을 손짓으로 설명하자 백성이 술렁이고, 여호수아와 갈렙은 옷을 찢으며 하나님을 따르라고 하는 모습", "밤의 진영에서 백성이 낙심해 웅성거리고, 회막에는 하나님의 영광이 밝게 임하며, 모세가 백성을 위해 엎드려 중보한다. 하나님의 영광에서 나오는 큰 말풍선 안에는 광야 길에서 이스라엘 백성들이 오래 고생하며 걷고 장막 곁에서 지쳐 쉬는 상징 그림이 글자 없이 담겨 있다"]'::jsonb, '["가데스 바네아 진영에서 모세가 가나안 땅을 정탐할 대표들을 보낸다", "여호수아와 갈렙을 포함한 정탐꾼들이 포도송이를 매달아 돌아온다", "정탐꾼들의 보고에 백들이 술렁이고 여호수아와 갈렙은 진정시킨다", "모세는 중보하고, 하나님은 백성들이 광야에서 돌아야함을 말씀하신다"]'::jsonb, '[["moses", "joshua", "caleb"], ["joshua", "caleb"], ["joshua", "moses", "caleb"], ["god", "moses"]]'::jsonb, ARRAY['moses', 'god', 'joshua', 'caleb']::text[], '[{"book": "민", "from": "13:1", "to": "14:45"}]'::jsonb, -1445, -1445, 'approx', 17, 'exodus_wilderness_covenant', '광야의 삶과 언약 훈련', 2, 'lm_exo_eshcol_valley', 'published'),
    ('era_monarchy', '나단의 책망: 그 사람이라', '나단은 비유로 다윗의 죄를 드러내고, 다윗은 아이를 위해 하나님 앞에 엎드린다.', '통일왕국 시대는 사울, 다윗, 솔로몬이 이스라엘 전체를 다스리던 시기입니다. 이 이야기는 「나단의 책망」을 다룹니다.', '["예루살렘 왕궁에서 나단 선지자가 다윗 앞에 서서 비유를 들려주고, 큰 글자 없는 말풍선 안에는 많은 양을 가진 부자가 가난한 사람의 작은 어린 양을 빼앗아 가는 그림이 담겨 있다", "다윗이 왕좌에서 일어나 의로운 분노로 나단에게 그 부자는 잘못했고 네 배로 갚아야 한다고 말하며, 큰 글자 없는 말풍선 안에는 부자가 가난한 사람에게 어린 양 네 마리를 돌려주는 그림이 담겨 있다", "나단이 다윗을 향해 단호하게 손가락질하며 책망하고, 다윗은 충격으로 굳어 있다. 큰 글자 없는 말풍선 안에는 병든 아기를 상징하는 어두운 빈 요람과 꺼져 가는 작은 등불이 보인다. 죽음이나 시신은 직접 보이지 않는다", "다윗이 왕궁 바닥에 엎드려 금식하며 하나님께 아이를 살려 달라고 밤새 기도하고, 신하들은 멀리서 걱정스럽게 지켜본다. 위쪽에는 사람 형상 없는 하나님의 조용한 빛이 드리운다, 그 말의 뜻을 보여 주는 글자 없는 말풍선 안에는 잘못된 길에서 돌이키라는 경고와 멈춰 선 사람들이 보이는 장면이 작은 그림처럼 보인다"]'::jsonb, '["예루살렘 왕궁에서 나단 선지자가 다윗 앞에 서서 비유를 들려준다", "다윗이 왕좌에서 일어나 의로운 분노로 나단에게 그 부자는 잘못했고 네 배로 갚아야 한다고 말한다", "나단이 다윗을 향해 단호하게 손가락질하며 그게 바로 당신이라고, 아이가 죽을 것임을 말한다", "다윗이 왕궁 바닥에 엎드려 금식하며 하나님께 아이를 살려 달라고 밤새 기도한다"]'::jsonb, '[["david", "nathan"], ["david", "nathan"], ["david", "nathan"], ["david", "god"]]'::jsonb, ARRAY['david', 'nathan', 'god']::text[], '[{"book": "삼하", "from": "12:1", "to": "12:23"}]'::jsonb, -990, -990, 'approx', 17, 'monarchy_david_covenant_fracture', '다윗 왕국: 언약과 집안의 균열', 2, 'lm_mon_jerusalem', 'published'),
    ('era_patriarch', '라반의 집: 레아와 라헬', '야곱은 라헬을 사랑하지만 속임수로 레아와도 결혼하게 된다.', '족장 시대는 아브라함, 이삭, 야곱, 요셉의 가족 이야기가 중심입니다. 이 이야기는 「라반의 집」을 다룹니다.', '["우물가에서 젊은 라헬이 양 떼를 몰고 오자 야곱이 큰 돌을 옮기며 라헬에게 반한 얼굴로 그녀를 맞이한다", "나이 많은 라반이 장막 앞에서 야곱과 칠 년 봉사 계약을 맺고, 라헬은 뒤에서 이를 바라본다", "혼인 다음 아침, 얼굴을 가린 신부가 레아였음을 알아차린 야곱이 충격을 받고, 라반은 곤란하지만 계산적인 표정으로 서 있다. 성적 장면은 없다", "야곱 라헬과 결혼을 준비하고 레아는 뒤에서 씁쓸한 모습으로 서있다"]'::jsonb, '["야곱이 큰 돌이 덮인 우물물 앞에서 양 떼를 몰고오는 라헬을 만난다", "라반과 야곱이 라헬의 결혼을 위해 칠 년 봉사 계약을 맺는다", "혼인 다음 아침, 얼굴을 가린 신부가 레아였음을 알아차린 야곱이 충격을 받는다", "야곱이 라헬과 혼인을 위해 7년을 더 일하고 라헬을 아내로 맞는다"]'::jsonb, '[["jacob", "rachel"], ["laban", "jacob", "rachel"], ["jacob", "laban", "leah"], ["jacob", "rachel", "leah"]]'::jsonb, ARRAY['jacob', 'laban', 'leah', 'rachel']::text[], '[{"book": "창", "from": "29:1", "to": "29:30"}]'::jsonb, -1984, -1977, 'approx', 17, 'patriarch_jacob_israel', '야곱: 이스라엘이 되다', 2, 'lm_pat_haran', 'published'),
    ('era_nt_post_apostolic', '믿음으로 의롭다 하심', '바울은 예수 그리스도를 믿음으로 의롭다 하심을 받는 복음과 아브라함의 믿음을 설명한다.', '로마서는 바울이 로마 방문을 앞두고, 유대인과 이방인이 함께 있던 로마 교회에 복음과 선교 계획을 설명하려고 쓴 편지입니다. 이 이야기는 「믿음으로 의롭다 하심」을 다룹니다.', '["바울이 로마 성도들의 모임 앞에서 율법 두루마리를 내려놓고 빈 손을 펴 보이며, 믿음으로 받는 의를 차분히 설명한다", "아브라함을 떠올리게 하는 늙은 순례자의 실루엣을 배경으로, 바울은 별빛 아래 약속을 믿는 자세를 성도들에게 보여 준다"]'::jsonb, '["바울이 법이나 행위가 아닌 오직 믿음으로의 법에 대해 이야기 한다", "바울은 예수 그리스도를 믿음으로 의롭다 하심을 받는 복음과 아브라함의 믿음을 설명한다"]'::jsonb, '[["paul"], ["paul"]]'::jsonb, ARRAY['paul']::text[], '[{"book": "롬", "from": "3:21", "to": "4:25"}]'::jsonb, 57, 57, 'approx', 17, 'paul_churches_problems_hope', '바울이 세운 교회들의 문제와 소망', 2, 'lm_nt_post_rome', 'published'),
    ('era_nt_public_ministry', '백부장의 종과 나인성 과부의 아들', '예수님은 백부장의 믿음을 칭찬하며 종을 고치시고, 나인성 과부의 죽은 아들을 살리신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「백부장의 종과 나인성 과부의 아들」을 다룹니다.', '["가버나움에서 장로들이 예수님께 병든 종을 고쳐 달라고 정중히 간청한다. 장로들 머리 위에는 침상에 누워있는 종이 그려진 말풍선", "백부장의 친구들이 예수님께 나아와서 말씀만 하시라고 간청하는 모습", "예수님이 손짓하며 명령하자 멀리 있는 집에서 종이 살아나고 백부장이 즐거워 하는 모습", "예수님이 관에 손을 대시자 죽었던 청년이 몸을 일으키고, 과부는 믿기지 않는 기쁨으로 아들에게 다가간다"]'::jsonb, '["가버나움에서 장로들이 예수님께 병든 종을 고쳐 달라고 정중히 간청한다", "백부장의 친구들이 예수님께 나아와서 말씀만 하시라고 간청한다", "멀리 있는 집에서 종이 살아나고 백부장이 즐거워 한다", "예수님이 관에 손을 대시자 죽었던 청년이 몸을 일으킨다"]'::jsonb, '[["jesus"], ["jesus"], ["jesus"], ["jesus"]]'::jsonb, ARRAY['jesus']::text[], '[{"book": "마", "from": "8:5", "to": "8:13"}, {"book": "눅", "from": "7:1", "to": "7:17"}]'::jsonb, 28, 28, 'approx', 17, 'galilee_ministry', '갈릴리 사역', 2, 'rgn_galilee', 'published'),
    ('era_divided_kingdom', '엘리사의 첫 표징: 물과 경고', '엘리사는 엘리야의 계승자로 인정받고, 물을 고치며 하나님의 권위를 가볍게 여긴 조롱에 경고를 드러낸다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「엘리사의 첫 표징」을 다룹니다.', '["여리고의 선지자 제자들이 엘리사에게 엘리야를 찾아보자고 간청하지만, 엘리사는 엘리야의 겉옷을 붙든 채 단호히 거절하는 장면", "여리고 사람들이 물을 고쳐 달라고 하자 엘리사가 새 그릇의 소금을 물 근원에 조금 뿌리고, 탁했던 물이 맑고 깨끗하게 변하는 장면", "벧엘로 올라가는 길에서 아이들이 엘리사를 놀려대자 엘리사가 엄중히 꾸짖고, 숲에서 곰 두 마리가 뛰어나와 아이들을 따라가고, 아이들이 공포에 흩어지는 장면. 피나 상처나 시신은 보이지 않는다"]'::jsonb, '["예언자의 제자들이 엘리사에게 엘리야를 찾아보자고 간청하지만 거절한다", "엘리사가 새 그릇의 소금을 물 근원에 조금 뿌리고, 탁했던 물이 맑고 깨끗하게 변한다", "아이들이 엘리사를 놀려대자 엘리사가 꾸짖고, 숲에서 곰이 나와 아이들을 잡아먹는다"]'::jsonb, '[["elisha"], ["elisha"], ["elisha"]]'::jsonb, ARRAY['elisha']::text[], '[{"book": "왕하", "from": "2:15", "to": "2:25"}]'::jsonb, -850, -850, 'approx', 17, 'divided_elisha_jehu_judgment', '엘리사와 예후: 표징과 심판', 3, 'lm_div_jericho', 'published'),
    ('era_nt_apostolic', '1차 전도 여행: 비시디아 안디옥 설교', '바울과 바나바는 비시디아 안디옥 회당에서 예수님의 부활을 전하고 이방인들은 기뻐한다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「차 전도 여행」을 다룹니다.', '["바울과 바나바가 비시디아 안디옥 회당에 앉아 있고 회당장들이 말씀할 기회를 주며 사람들이 집중한다", "바울이 이스라엘 역사와 예수님의 부활을 담대한 표정으로 설명하고 듣는 이들은 진지하게 귀 기울인다", "다음 안식일에 온 성이 모여 말씀을 들으려 하자 유대인들은 시기 어린 얼굴로 반박한다", "이방인들이 영생을 주시는 말씀을 기뻐하며 바울과 바나바는 추방당해도 기쁨을 잃지 않는다"]'::jsonb, '["바울과 바나바가 비시디아 안디옥 회당에 앉아 있고 회당장들이 말씀할 기회를 주며 사람들이 집중한다", "바울이 이스라엘 역사와 예수님의 부활을 담대한 표정으로 설명한다", "다음 안식일에 온 성이 모여 말씀을 들으려 하자 유대인들은 시기 어린 얼굴로 반박한다", "이방인들이 영생을 주시는 말씀을 기뻐하며 바울과 바나바는 추방당해도 기쁨을 잃지 않는다"]'::jsonb, '[["paul", "barnabas"], ["paul"], ["paul", "barnabas"], ["paul", "barnabas"]]'::jsonb, ARRAY['paul', 'barnabas']::text[], '[{"book": "행", "from": "13:14", "to": "13:52"}]'::jsonb, 46, 46, 'approx', 18, 'paul_first_journey', '바울의 1차 전도 여행', 2, 'lm_nt_ap_pisidian_antioch', 'published'),
    ('era_nt_public_ministry', '갈릴리 호수의 기적들', '예수님은 풍랑을 잠잠케 하시고 귀신 들린 사람과 병든 이들, 야이로의 딸과 혈루증 여인을 고치신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「갈릴리 호수의 기적들」을 다룹니다.', '["갈릴리 호수의 거센 풍랑 속에서 젖은 어부 옷의 제자들이 배 밧줄과 노를 붙잡고 두려워하며, 예수님은 흔들리는 배 안에서 바람과 바다를 꾸짖으신다", "거라사 들판에서 헝클어진 머리와 찢어진 옷의 사람이 예수님 앞에 쓰러지고, 악한 영이 떠나 돼지 떼가 낭떠러지를 향해 달려가자 주변 사람들은 겁에 질린다", "무리 속에서 오래 앓아 지친 혈루증 여인이 떨리는 손으로 예수님의 옷자락을 만지고, 예수님은 그녀를 찾듯 돌아보신다", "야이로의 집에서 예수님이 죽은 딸의 손을 잡아 일으키시고, 회당장 야이로와 가족들 그리고 베드로와 야고보와 요한은 침상 곁에서 숨을 죽인 채 놀라 다가온다"]'::jsonb, '["갈릴리 호수의 거센 풍랑 속에서 젖은 제자들이 배 밧줄과 노를 붙잡고 두려워한다", "거라사 들판에서 사람에게서 귀신을 내쫓아 군대가 돼지에게 들어간다", "무리 속에서 혈루증 여인이 떨리는 손으로 예수님의 옷자락을 만져 치유 받는다", "야이로의 집에서 예수님이 죽은 딸의 손을 잡아 일으키시다"]'::jsonb, '[["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["jesus"], ["jesus"], ["jesus", "peter", "james_zebedee", "john", "jairus"]]'::jsonb, ARRAY['jesus', 'jairus', 'peter', 'andrew', 'james_zebedee', 'john', 'philip', 'bartholomew', 'matthew', 'thomas', 'james_alphaeus', 'thaddaeus', 'simon_zealot', 'judas']::text[], '[{"book": "마", "from": "8:23", "to": "8:34"}, {"book": "마", "from": "9:27", "to": "9:34"}, {"book": "막", "from": "4:35", "to": "5:43"}, {"book": "눅", "from": "8:22", "to": "8:56"}]'::jsonb, 28, 29, 'approx', 18, 'galilee_ministry', '갈릴리 사역', 2, 'rgn_galilee', 'published'),
    ('era_exodus', '고라의 반역: 권위에 맞서다', '거룩한 직분을 둘러싼 반역 속에서 하나님은 공동체의 질서를 분명히 세우신다.', '출애굽과 광야 여정은 이스라엘이 애굽을 떠나 시내산과 광야를 지나는 시기입니다. 이 이야기는 「고라의 반역」을 다룹니다.', '["고라가 지도자들과 함께 모세와 아론에게 맞서며 회막 앞에서 거만하게 손을 들고, 팔십 세 모세는 얼굴을 땅에 대고 엎드려 하나님께 맡긴다", "고라와 반역한 사람들이 향로를 들고 회막 앞에 서 있고, 아론은 제사장 옷을 입은 채 떨리는 손으로 향로를 붙들며 모세는 하나님의 판단을 기다린다", "땅이 갈라져 고라의 반역이 심판받는 장면을 멀리서 상징적으로 보이고, 백성은 두려움으로 물러선다. 직접적인 추락, 시신, 잔혹 묘사는 없다"]'::jsonb, '["고라가 250명의 지도자들과 함께 모세와 아론에게 맞서며 회막 앞에서 거만하게 손을 든다", "고라와 반역한 사람들, 아론과 모세가 향로를 들고 회막 앞에서 하나님의 뜻을 기다린다", "땅이 갈라져 고라와 반역자들이 심판 받는다"]'::jsonb, '[["moses", "aaron", "korah"], ["moses", "aaron", "korah"], ["korah"]]'::jsonb, ARRAY['moses', 'god', 'aaron', 'korah']::text[], '[{"book": "민", "from": "16:1", "to": "16:50"}]'::jsonb, -1445, -1445, 'approx', 18, 'exodus_wilderness_covenant', '광야의 삶과 언약 훈련', 2, 'lm_exo_kadesh_barnea', 'published'),
    ('era_nt_post_apostolic', '성령 안에서 끊을 수 없는 사랑', '바울은 그리스도 예수 안에 결코 정죄함이 없고 성령 안에서 하나님의 사랑이 끊어지지 않는다고 선포한다.', '로마서는 바울이 로마 방문을 앞두고, 유대인과 이방인이 함께 있던 로마 교회에 복음과 선교 계획을 설명하려고 쓴 편지입니다. 이 이야기는 「성령 안에서 끊을 수 없는 사랑」을 다룹니다.', '["육신의 정욕에서 해방되어 내면에 성령 받아 기뻐하는 성도의 모습과, 바울은 깊은 안도와 기쁨으로 정죄함이 없다는 소식을 가리킨다", "바울이 폭풍과 칼과 높은 절벽을 배경으로도 두 팔을 굳게 벌리고 서며, 어떤 것도 하나님의 사랑에서 끊을 수 없다는 확신을 드러낸다. 바울의 위에는 십자가와 사랑의 상징"]'::jsonb, '["바울은 그리스도 예수 안에 결코 정죄함이 없고 성령 안에서 하나님의 사랑이 끊어지지 않는다고 선포한다", "바울이 하나님의 사랑이 우리를 어떤 상황에서도 이기게 함을 말한다"]'::jsonb, '[["paul"], ["paul"]]'::jsonb, ARRAY['paul']::text[], '[{"book": "롬", "from": "8:1", "to": "8:39"}]'::jsonb, 57, 57, 'approx', 18, 'paul_churches_problems_hope', '바울이 세운 교회들의 문제와 소망', 2, 'lm_nt_post_rome', 'published'),
    ('era_monarchy', '암논과 다말: 압살롬의 분노', '암논의 죄와 다말의 눈물은 압살롬의 분노로 이어지고, 다윗의 집에는 깊은 상처가 남는다.', '통일왕국 시대는 사울, 다윗, 솔로몬이 이스라엘 전체를 다스리던 시기입니다. 이 이야기는 「암논과 다말」을 다룹니다.', '["예루살렘 왕궁 뜰, 다윗의 아들 암논이 20대 왕자 모습으로 다말을 집요하게 바라보며 따라가고, 20대 공주 다말은 화려한 채색 긴 옷을 입고 불편한 표정으로 거리를 두는 장면. 성적 묘사는 전혀 보이지 않는다", "암논이 병든 척 침대에 누워 있고, 다말이 구운 빵과 과자를 들고 방 안으로 들어오자 암논이 손목을 붙잡아 침상 쪽으로 끌어당기려 하며 다말은 놀라 뒤로 물러나는 장면. 침실 장면은 위협의 순간만 보이고 성폭력 행위나 노출은 직접 보이지 않는다", "머리에 재를 얹고 찢어진 채색 옷을 붙든 다말이 압살롬의 집으로 와서 울고, 20대 후반의 압살롬은 긴 머리와 왕자 복장으로 다말을 보호하듯 감싸며 분노를 억누르는 장면", "세로 3등분 구도: 위에는 바알하솔 잔치에서 압살롬의 부하들이 암논에게 포도주를 권하고 암논이 취해 앉아 있는 모습, 가운데에는 부하들이 암논에게 달려들어 심판이 벌어지는 순간을 멀리서 보여주되 피와 상처는 보이지 않는 모습, 아래에는 60대 초반 다윗이 궁전에서 소식을 듣고 옷을 찢으며 통곡하고, 긴 머리의 압살롬은 먼 길로 도망하는 모습"]'::jsonb, '["모습으로 다말을 집요하게 바라보며 따라간다", "암논이 병든 척 침대에 누워 있다가 다말을 범한다", "다말이 압살롬의 집으로 와서 울고 압살롬은 분노한다", "바알하솔 잔치에서 압살롬이 암논을 죽인다"]'::jsonb, '[[], [], ["absalom"], ["david", "absalom"]]'::jsonb, ARRAY['david', 'absalom']::text[], '[{"book": "삼하", "from": "13:1", "to": "13:39"}]'::jsonb, -987, -985, 'approx', 18, 'monarchy_david_covenant_fracture', '다윗 왕국: 언약과 집안의 균열', 2, 'lm_mon_jerusalem', 'published'),
    ('era_divided_kingdom', '엘리사의 기적들: 기름과 생명과 양식', '엘리사는 가난한 집의 기름, 죽은 아이의 회복, 독이 사라진 국, 적은 떡으로 먹인 무리를 통해 하나님의 돌보심을 보여 준다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「엘리사의 기적들」을 다룹니다.', '["엘리사가 가난한 선지자의 아내에게 빈 그릇을 많이 모아 기름을 부으라 하자, 여인이 집 안에서 여러 그릇에 기름을 가득 채우는 장면", "수넴 여인의 집에서 침대에 누워 있던 아이를 위해 엘리사가 간절히 기도하자 아이가 다시 살아나 앉고, 어머니가 놀라며 기뻐하는 장면. 죽음의 세부 묘사는 보이지 않는다", "길갈에서 사람들이 큰 솥의 독이 든 국을 두려워하자, 엘리사가 밀가루를 넣고 국이 안전해져 사람들이 안심하고 먹을 수 있게 되는 장면", "엘리사가 보리빵 스무 개와 햇곡식 조금으로 백 명을 먹이고, 사람들이 배불리 먹은 뒤에도 음식이 남아 있는 장면"]'::jsonb, '["엘리사가 가난한 선지자의 집에서 여러 그릇에 기름을 가득 채우는 기적을 행한다", "수넴 여인의 집에서 죽은 아이를 위해 엘리사가 기도하자 아이가 다시 살아나 앉는다", "독이 든 국에 엘리사가 밀가루를 넣자 국이 안전해진다", "엘리사가 보리빵 스무 개와 햇곡식 조금으로 백 명을 먹이다"]'::jsonb, '[["elisha"], ["elisha"], ["elisha"], ["elisha"]]'::jsonb, ARRAY['elisha']::text[], '[{"book": "왕하", "from": "4:1", "to": "4:44"}]'::jsonb, -845, -845, 'approx', 18, 'divided_elisha_jehu_judgment', '엘리사와 예후: 표징과 심판', 3, 'lm_div_gilgal', 'published'),
    ('era_patriarch', '열두 아들의 시작: 이름에 담긴 마음', '경쟁과 상처 속에서도 열두 지파의 뿌리가 형성된다.', '족장 시대는 아브라함, 이삭, 야곱, 요셉의 가족 이야기가 중심입니다. 이 이야기는 「열두 아들의 시작」을 다룹니다.', '["레아가 여러 아들들과 딸 디나를 돌보며 분주한 장막 안에 서 있고, 야곱의 큰 가정이 복잡하게 늘어나는 모습이 보인다", "라헬이 마음 아픈 얼굴로 시녀 빌하를 자기 가정 안에 들이고, 뒤쪽에는 빌하가 낳은 두 아들이 작은 요람 곁에 보인다. 침실이나 성적 장면은 보이지 않는다", "레아가 시녀 실바를 자기 가정 안에 들이고, 뒤쪽에는 실바가 낳은 두 아들이 가족들 사이에 함께 서 있다. 침실이나 성적 장면은 보이지 않는다", "하나님이 라헬을 기억하신 뒤 라헬이 갓난 요셉을 품에 안고 안도의 숨을 쉬며, 야곱은 곁에서 감사한 얼굴로 바라본다"]'::jsonb, '["레아가 여러 아들들과 딸 디나를 돌보며 분주한 장막 안에 서 있다", "라헬이 마음 아픈 얼굴로 시녀 빌하와 야곱사이에서 아이를 얻는다", "경쟁과 상처 속에서도 열두 지파의 뿌리가 형성된다", "하나님이 라헬을 기억하신 뒤 라헬이 갓난 요셉을 품에 안고 안도의 숨을 쉬다"]'::jsonb, '[["leah", "jacob"], ["rachel"], ["leah"], ["rachel", "joseph", "jacob"]]'::jsonb, ARRAY['jacob', 'leah', 'rachel', 'joseph']::text[], '[{"book": "창", "from": "29:31", "to": "30:24"}]'::jsonb, -1977, -1965, 'approx', 18, 'patriarch_jacob_israel', '야곱: 이스라엘이 되다', 2, 'lm_pat_haran', 'published'),
    ('era_nt_apostolic', '1차 전도 여행: 이고니온과 루스드라와 더베', '바울과 바나바는 여러 도시에서 표적과 박해를 겪고 제자들을 굳게 세우며 장로들을 세운다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「차 전도 여행」을 다룹니다.', '["이고니온에서 바울과 바나바가 담대하게 말하고 많은 사람이 믿지만 반대자들은 굳은 얼굴로 선동한다", "루스드라에서 걷지 못하던 사람이 일어나자 무리가 놀라 두 사람을 신들처럼 대하려 한다", "바울이 돌에 맞아 성 밖에 쓰러지고 제자들은 두려움과 슬픔이 가득한 얼굴로 그를 둘러선다", "바울과 바나바가 다시 일어나 더베와 여러 도시의 제자들을 격려하며 장로들을 세운다"]'::jsonb, '["이고니온에서 바울과 바나바가 담대하게 말하고 많은 사람이 믿지만 반대자들은 선동한다", "루스드라에서 걷지 못하던 사람이 일어나자 무리가 놀라 두 사람을 신들처럼 대하려 한다", "바울이 돌에 맞아 성 밖에 쓰러지고 제자들은 두려움과 슬픔이 가득한 얼굴로 그를 둘러선다", "바울과 바나바가 다시 일어나 더베와 여러 도시의 제자들을 격려하며 장로들을 세운다"]'::jsonb, '[["paul", "barnabas"], ["paul", "barnabas"], ["paul"], ["paul", "barnabas"]]'::jsonb, ARRAY['paul', 'barnabas']::text[], '[{"book": "행", "from": "14:1", "to": "14:23"}]'::jsonb, 47, 47, 'approx', 19, 'paul_first_journey', '바울의 1차 전도 여행', 2, 'lm_nt_ap_lystra_derbe', 'published'),
    ('era_divided_kingdom', '나아만: 요단의 일곱 번', '자존심을 내려놓을 때 치유가 찾아온다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「나아만」을 다룹니다.', '["아람 군대 장관 나아만이 말과 병거를 거느리고 엘리사의 집 문 앞에 서지만, 얼굴에는 병 때문에 괴로움과 자존심이 함께 보인다", "엘리사의 심부름꾼이 요단강에 일곱 번 씻으라는 말을 전하자 나아만은 분노해 돌아서고, 그 말의 뜻을 보여 주는 글자 없는 말풍선 안에는 요단강에 일곱 번 몸을 담근 나아만이 깨끗하게 일어나는 장면이 작은 그림처럼 보인다", "나아만은 자존심을 내려놓는 얼굴로 요단강 물가에 서서 겉옷을 벗어 둘 준비를 한다. 노출은 절제한다", "나아만이 요단강에서 일곱 번째 올라오자 피부가 깨끗해진 것을 보고 놀란다"]'::jsonb, '["아람 군대 장관 나아만이 말과 병거를 거느리고 엘리사의 집 문 앞에 선다", "엘리사의 심부름꾼이 요단강에 일곱 번 씻으라는 말을 전하자 나아만은 분노해 돌아선다", "나아만은 자존심을 내려놓는 얼굴로 요단강 물가에 서서 들어갈 준비를 한다", "나아만이 피부가 깨끗해진 것을 보고 놀란다"]'::jsonb, '[["naaman", "elisha"], ["naaman", "elisha"], ["naaman"], ["naaman"]]'::jsonb, ARRAY['naaman', 'elisha']::text[], '[{"book": "왕하", "from": "5:1", "to": "5:14"}]'::jsonb, -845, -845, 'approx', 19, 'divided_elisha_jehu_judgment', '엘리사와 예후: 표징과 심판', 3, 'lm_div_samaria', 'published'),
    ('era_exodus', '므리바 물: 바위를 치다', '물 없는 광야에서 하나님은 반석의 물을 주시지만, 모세와 아론은 하나님의 거룩함을 드러내지 못한다.', '출애굽과 광야 여정은 이스라엘이 애굽을 떠나 시내산과 광야를 지나는 시기입니다. 이 이야기는 「므리바 물」을 다룹니다.', '["백성들이 광야 진영에서 모세와 아론을 향해 물이 없다고 불평하며 몰려오고, 모세는 노년의 지도자 모습으로, 모세의 형 아론은 흰수염을 가진 더 나이 든 대제사장 모습으로 제사장복과 흉패를 입은 채 근심스러운 얼굴로 서 있다", "회막 앞에 하나님의 영광이 밝게 임하고, 하나님이 모세에게 지팡이를 들고 바위에 말하면 물이 나올 것임을 큰 글자 없는 말풍선 속 그림으로 보여 주신다. 모세의 형 아론은 흰수염을 가진 노년 대제사장으로 제사장복과 흉패를 입고 조용히 곁에 선다", "모세가 지팡이로 바위를 두 번 내리치자 물이 바위에서 세차게 터져 나오고, 흰수염의 노년 대제사장 아론은 제사장복과 흉패 차림으로 충격과 근심이 섞인 얼굴로 바라보며, 백성과 가축들이 놀라 물가로 모여든다", "하나님의 영광이 모세와 흰수염의 노년 대제사장 아론 앞에 임하고, 큰 글자 없는 말풍선 안에는 젖과 꿀이 흐르는 풍성한 땅이 멀리 보이지만, 모세와 아론은 경계선 밖에서 고개를 숙인 채 멈춰 서 있는 상징 그림이 담겨 있다"]'::jsonb, '["백성들이 광야 진영에서 모세와 아론을 향해 물이 없다고 불평하며 몰려온다", "물 없는 광야에서 하나님은 모세에게 바위를 향해 말하라고 말씀하신다", "모세가 바위를 지팡이로 두번 내리치자 물이 바위에서 세차게 터져 나온다", "하나님이 모세와 아론에게 명령을 어김에 따라 땅에 들어가지 못할 것을 말씀하신다"]'::jsonb, '[["moses", "aaron"], ["god", "moses", "aaron"], ["moses", "aaron"], ["god", "moses", "aaron"]]'::jsonb, ARRAY['moses', 'god', 'aaron']::text[], '[{"book": "민", "from": "20:1", "to": "20:13"}]'::jsonb, -1408, -1408, 'approx', 19, 'exodus_wilderness_covenant', '광야의 삶과 언약 훈련', 2, 'lm_exo_kadesh_barnea', 'published'),
    ('era_nt_post_apostolic', '복음에 합당한 공동체와 시민의 삶', '바울은 몸을 산 제물로 드리는 삶, 서로 다른 지체의 섬김, 권세와 이웃 사랑을 가르친다.', '로마서는 바울이 로마 방문을 앞두고, 유대인과 이방인이 함께 있던 로마 교회에 복음과 선교 계획을 설명하려고 쓴 편지입니다. 이 이야기는 「복음에 합당한 공동체와 시민의 삶」을 다룹니다.', '["성도들이 각자 가진 빵과 도구와 겉옷을 가져와 서로 섬기고, 또 어떤이는 가르치는 일로 섬기고, 어떤이는 도와주는 일로 섬긴다. 바울은 기쁜 얼굴로 이들을 바라본다", "박해하는 사람에게 되갚지 않으려는 성도가 주먹을 풀고 고개를 숙이며 박해하는 사람들에게서 등을 돌려 바울에게 온다, 바울은 절제된 표정으로 선으로 악을 이기라고 손을 얹는다. 바울의 위에는 선이 악을 이기는 상징", "바울이 성도들에게 말한다. 바울의 말풍선에는 성도가 빛의 갑옷을 입고 어둠을 이기는 장면"]'::jsonb, '["바울이 믿음의 분량대로 서로 섬길 것을 이야기한다", "악을 갚지말고 선으로 악을 이겨야 함을 이야기한다", "바울은 오직 예수 그리스도로 옷 입고 육신의 일을 이길 것을 강조한다"]'::jsonb, '[["paul"], ["paul"], ["paul"]]'::jsonb, ARRAY['paul']::text[], '[{"book": "롬", "from": "12:1", "to": "13:14"}]'::jsonb, 57, 57, 'approx', 19, 'paul_churches_problems_hope', '바울이 세운 교회들의 문제와 소망', 2, 'lm_nt_post_rome', 'published'),
    ('era_monarchy', '압살롬의 귀환: 멀어진 아버지', '요압의 계책과 드고아 여인의 비유를 통해 압살롬은 돌아오지만, 부자의 관계는 쉽게 회복되지 않는다.', '통일왕국 시대는 사울, 다윗, 솔로몬이 이스라엘 전체를 다스리던 시기입니다. 이 이야기는 「압살롬의 귀환」을 다룹니다.', '["상복을 입은 드고아의 젊은 지혜로운 여인이 60대 초반 다윗 왕 앞에 엎드려 슬픈 얼굴로 자기 사정을 말하고, 큰 글자 없는 말풍선 안에는 들판에서 한 아들이 다른 아들을 쓰러뜨린 뒤 도망가는 그림이 담겨 있다. 폭력의 세부 묘사는 보이지 않는다", "60대 초반의 다윗이 왕좌에서 드고아 여인에게 손을 들어 보호를 약속하고, 큰 글자 없는 말풍선 안에는 도망간 아들이 안전하게 집으로 돌아오며 왕의 보호 빛 아래 서 있는 그림이 담겨 있다", "드고아 여인이 60대 초반의 다윗을 향해 조심스럽지만 단호하게 손짓하며 말하고, 큰 글자 없는 말풍선 안에는 긴 머리의 압살롬을 예루살렘으로 데려와야 한다는 상징 그림이 담겨 있다. 다윗은 깨달은 표정으로 굳어 있다", "예루살렘 왕궁 안, 60대 초반의 다윗이 30대의 긴 머리 압살롬을 불러 끌어안고 입맞추며 맞이하지만, 두 사람 사이에는 아직 어색한 침묵과 거리감이 남아 있는 장면"]'::jsonb, '["상복을 입은 드고아의 지혜로운 여인이 초반 다윗 왕 앞에 엎드려 슬픈 얼굴로 자기 사정을 말한다", "초반의 다윗이 왕좌에서 드고아 여인에게 손을 들어 보호를 약속한다", "드고아 여인은 다윗에게 압살롬을 데려올 것을 말한다", "예루살렘 왕궁 안, 다윗이 머리 압살롬을 불러 끌어안고 입맞추며 맞이한다"]'::jsonb, '[["david"], ["david"], ["david", "absalom"], ["david", "absalom"]]'::jsonb, ARRAY['david', 'absalom']::text[], '[{"book": "삼하", "from": "14:1", "to": "14:33"}]'::jsonb, -984, -982, 'approx', 19, 'monarchy_david_covenant_fracture', '다윗 왕국: 언약과 집안의 균열', 2, 'lm_mon_jerusalem', 'published'),
    ('era_patriarch', '야곱의 번성: 양떼의 기묘한 계약', '야곱은 라반의 집에서 번성하고 라반과 갈등이 깊어진다.', '족장 시대는 아브라함, 이삭, 야곱, 요셉의 가족 이야기가 중심입니다. 이 이야기는 「야곱의 번성」을 다룹니다.', '["야곱이 장막 앞에서 떠나겠다고 말하자 라반이 손을 들어 붙잡고, 뒤에는 야곱의 가족과 양 떼가 길 떠날 준비를 하고 있다", "야곱과 라반이 양 떼의 얼룩지고 아롱진 표식을 두고 계약을 정하며, 야곱은 표식 있는 양들을 조심스럽게 따로 세운다", "야곱의 얼룩진 양 떼가 크게 늘어나고, 라반과 그의 아들들은 굳은 얼굴로 그 풍성함을 바라본다", "야곱이 레아와 라헬에게 낮은 목소리로 떠날 때가 되었다고 알린다"]'::jsonb, '["야곱이 떠나겠다고 하고 라반이 손을 들어 붙잡다", "야곱과 라반이 양 떼의 얼룩지고 아롱진 표식을 두고 계약을 정한다", "야곱의 얼룩진 양 떼가 크게 늘어난다, 라반과 그의 아들들은 굳은 얼굴로 그 풍성함을 바라본다", "야곱이 레아와 라헬에게 낮은 목소리로 떠날 때가 되었다고 알린다"]'::jsonb, '[["jacob", "laban"], ["jacob", "laban"], ["jacob", "laban"], ["jacob", "leah", "rachel"]]'::jsonb, ARRAY['jacob', 'laban', 'leah', 'rachel']::text[], '[{"book": "창", "from": "30:25", "to": "31:16"}]'::jsonb, -1965, -1961, 'approx', 19, 'patriarch_jacob_israel', '야곱: 이스라엘이 되다', 2, 'lm_pat_haran', 'published'),
    ('era_nt_public_ministry', '열두 제자 파송', '예수님은 열두 제자에게 권능과 지침을 주시고 하나님 나라를 전하며 병을 고치도록 보내신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「열두 제자 파송」을 다룹니다.', '["예수님이 열두 제자를 가까이 부르시고, 제자들은 먼지 묻은 샌들과 단순한 여행복 차림으로 더러운 영과 병을 고칠 권능을 받는다", "열두 제자가 둘씩 짝을 지어 여벌 옷과 돈주머니 없이 지팡이와 샌들만 갖춘 간소한 차림으로 갈릴리 마을길을 떠난다", "제자들이 마을집 앞에서 복음을 전하고, 병든 사람을 고치며 가족들은 간절한 표정으로 지켜본다", "헤롯 왕이 화를 내고 그 앞에 신하들이 이야기를 전하는 모습 신하들의 이야기 말풍선에는 제자들이 사람들을 고쳐주는 모습"]'::jsonb, '["예수님은 열두 제자에게 권능과 지침을 주시고 하나님 나라를 전하며 병을 고치도록 보내신다", "제자들이 여벌 옷과 돈주머니 없이 지팡이와 샌들만 갖춘 간소한 차림으로 갈릴리 마을길을 떠난다", "제자들이 마을집 앞에서 복음을 전한다, 병든 사람을 고친다", "헤롯 왕이 화를 내고 그 앞에 신하들이 이야기를 전한다"]'::jsonb, '[["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["herod"]]'::jsonb, ARRAY['jesus', 'peter', 'andrew', 'james_zebedee', 'john', 'philip', 'bartholomew', 'matthew', 'thomas', 'james_alphaeus', 'thaddaeus', 'simon_zealot', 'judas', 'herod']::text[], '[{"book": "마", "from": "10:1", "to": "10:42"}, {"book": "막", "from": "6:7", "to": "6:13"}, {"book": "눅", "from": "9:1", "to": "9:6"}]'::jsonb, 29, 29, 'approx', 19, 'galilee_ministry', '갈릴리 사역', 2, 'rgn_galilee', 'published')
)
insert into events (era_id, title, summary, background_context, story_scenes, scene_captions, scene_characters, character_codes, bible_refs, start_year, end_year, time_precision, story_index, unit_code, unit_title, unit_order, landmark_id, status)
select
  e.id,
  s.title,
  s.summary,
  s.background_context,
  s.story_scenes,
  s.scene_captions,
  s.scene_characters,
  s.character_codes,
  s.bible_refs,
  s.start_year,
  s.end_year,
  s.time_precision,
  s.story_index,
  s.unit_code,
  s.unit_title,
  s.unit_order,
  lm.id,
  s.status
from seed_events s
join eras e on e.code = s.era_code
join landmarks lm on lm.code = s.landmark_code
on conflict (era_id, story_index) do update set
  title = excluded.title,
  summary = excluded.summary,
  background_context = excluded.background_context,
  story_scenes = excluded.story_scenes,
  scene_captions = excluded.scene_captions,
  scene_characters = excluded.scene_characters,
  character_codes = excluded.character_codes,
  bible_refs = excluded.bible_refs,
  start_year = excluded.start_year,
  end_year = excluded.end_year,
  time_precision = excluded.time_precision,
  unit_code = excluded.unit_code,
  unit_title = excluded.unit_title,
  unit_order = excluded.unit_order,
  landmark_id = excluded.landmark_id,
  status = excluded.status
;

with seed_events (era_code, title, summary, background_context, story_scenes, scene_captions, scene_characters, character_codes, bible_refs, start_year, end_year, time_precision, story_index, unit_code, unit_title, unit_order, landmark_code, status) as (
  values
    ('era_nt_post_apostolic', '그리스도 안의 새 공동체', '바울은 감옥에서도 에베소 성도들에게 그리스도 안에서 유대인과 이방인이 한 새 사람으로 세워졌다고 가르친다.', '에베소서는 바울이 감옥에서, 에베소와 주변 성도들에게 유대인과 이방인이 그리스도 안에서 한 몸임을 전한 편지입니다. 이 이야기는 「그리스도 안의 새 공동체」를 다룹니다.', '["로마 감옥의 낮은 빛 속에서 바울이 쇠사슬을 찬 채 편지를 쓰고, 얼굴에는 갇힘보다 감사와 확신이 더 크게 드러난다", "에베소 성도들 가운데 유대인과 이방인이 서로 조심스럽게 손을 맞잡고, 바울의 편지를 읽는 사람은 벅찬 표정으로 화평을 전한다", "무너진 담돌 사이로 성도들이 함께 집을 세우듯 서 있고, 바울은 멀리 감옥 안에서 그들이 성전처럼 세워지는 모습을 소망스럽게 바라본다"]'::jsonb, '["로마 감옥의 낮은 빛 속에서 바울이 쇠사슬을 찬 채 편지를 쓰다", "바울이 이방인들과 유대인 상관없이 예수 그리스도의 피로 가까워 짐을 이야기한다", "친히 모퉁잇돌 되신 예수와 우리가 성령 안에서 함께 세워져 감을 이야기한다"]'::jsonb, '[["paul"], [], ["paul"]]'::jsonb, ARRAY['paul']::text[], '[{"book": "엡", "from": "2:1", "to": "2:22"}]'::jsonb, 62, 62, 'approx', 20, 'roman_prison_churches', '로마 감옥에서도 세워지는 교회', 3, 'lm_nt_post_ephesus', 'published'),
    ('era_exodus', '놋뱀: 바라보라', '원망 속에서 고통이 번지지만, 하나님은 ‘바라봄’으로 살 길을 주신다.', '출애굽과 광야 여정은 이스라엘이 애굽을 떠나 시내산과 광야를 지나는 시기입니다. 이 이야기는 「놋뱀」을 다룹니다.', '["광야 진영에서 백성이 모세를 둘러싸고 원망하고 모세는 하나님께 기도하는 장면", "불뱀들이 진영에 나타나 백성이 공포에 빠져 서로를 부축하고, 피나 상처는 직접 보이지 않는다", "모세가 하나님의 지시를 따라 장대 위에 놋뱀 표징을 높이 세우고, 겁먹은 백성은 고개를 들어 바라보기 시작한다", "병들었던 사람들이 장대 위 표징을 바라본 뒤 안정을 되찾고 가족들이 눈물 어린 안도감으로 그들을 부축한다"]'::jsonb, '["광야 진영에서 백성이 모세를 둘러싸고 원망하고 모세는 하나님께 기도한다", "불뱀들이 진영에 나타나 백성이 공포에 빠진다", "모세가 하나님의 지시를 따라 장대 위에 놋뱀 표징을 높이 세운다", "병들었던 사람들이 장대 위 표징을 바라본 뒤 회복을 얻는다"]'::jsonb, '[["moses", "god"], [], ["moses"], []]'::jsonb, ARRAY['moses']::text[], '[{"book": "민", "from": "21:4", "to": "21:9"}]'::jsonb, -1408, -1408, 'approx', 20, 'exodus_wilderness_covenant', '광야의 삶과 언약 훈련', 2, 'lm_exo_edom_road', 'published'),
    ('era_divided_kingdom', '도단의 불 말과 불 전차: 눈이 열리다', '아람 군대가 도단을 에워싸지만, 하나님은 엘리사 곁의 불 말과 불 전차를 보이시고 원수에게 자비를 베풀게 하신다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「도단의 불 말과 불 전차」를 다룹니다.', '["밤의 도단 성 밖, 아람 왕이 보낸 많은 말과 병거와 군대가 엘리사를 붙잡아 해치려는 명령을 받고 성을 조용히 에워싸며, 성 안은 아직 어둠 속에 잠겨 있는 장면", "새벽 도단 성에서 엘리사가 두려워하는 청년을 위해 기도하자, 청년의 눈이 열려 엘리사 주변 산마다 불 말과 불 전차가 가득한 것을 보는 장면", "엘리사가 성 밖 아람 군대를 향해 기도하자 군사들이 눈앞을 더듬으며 길을 잃고 혼란스러워하는 장면.", "사마리아 진영에서 엘리사가 아람 군대에게 먹을 것과 마실 것을 베풀게 한 뒤, 그들이 평화롭게 자기 나라 진영으로 돌아가도록 길을 열어 주는 장면"]'::jsonb, '["아람 왕이 보낸 많은 말과 병거와 군대가 엘리사를 붙잡으려 성을 에워싼다", "엘리사가 두려워하는 청년을 위해 기도하자, 청년이 불말과 전차를 본다", "엘리사의 기도에 군사들이 눈앞을 더듬으며 길을 잃고 혼란스러워한다", "엘리사가 아람 군대에게 먹을 것과 마실 것을 베푼 뒤 돌아가게 한다"]'::jsonb, '[[], ["elisha", "god"], ["elisha"], ["elisha"]]'::jsonb, ARRAY['elisha', 'god']::text[], '[{"book": "왕하", "from": "6:8", "to": "6:23"}]'::jsonb, -845, -845, 'approx', 20, 'divided_elisha_jehu_judgment', '엘리사와 예후: 표징과 심판', 3, 'lm_div_dothan', 'published'),
    ('era_patriarch', '도피와 언약: 라반과의 마지막', '야곱은 라반을 떠나고, 추격 끝에 언약으로 갈등을 마무리한다.', '족장 시대는 아브라함, 이삭, 야곱, 요셉의 가족 이야기가 중심입니다. 이 이야기는 「도피와 언약」을 다룹니다.', '["야곱이 밤에 가족과 가축과 짐을 조용히 모아 라반의 집을 떠나고, 라헬은 숨긴 드라빔 때문에 불안한 얼굴로 장막 꾸러미를 붙든다", "라반이 분노한 얼굴로 야곱의 행렬을 따라잡아 추궁하고, 야곱은 가족을 지키려 긴장한 자세로 맞선다", "라반이 라헬의 장막 안을 수색하고, 라헬은 낙타 안장 위에 앉아 긴장된 얼굴로 침착한 척한다. 드라빔은 노골적으로 보이지 않는다", "야곱과 라반이 돌무더기를 세워 서로 해치지 않겠다는 언약을 맺고, 가족들은 긴장 끝의 안도와 피로가 섞인 표정으로 바라본다"]'::jsonb, '["야곱이 밤에 가족과 가축과 짐을 조용히 모아 라반의 집을 떠나다. 라헬을 드라빔을 들고 있다", "라반이 분노한 얼굴로 야곱의 행렬을 따라잡아 인사 없이 떠난것과 드라빔을 가져간 것을 추궁한다", "라반이 라헬의 장막 안을 수색한다, 라헬은 낙타 안장 위에 드라빔을 숨기고 앉아 있다", "야곱과 라반이 돌무더기를 세워 서로 해치지 않겠다는 언약을 맺다"]'::jsonb, '[["jacob", "rachel", "leah"], ["laban", "jacob"], ["laban", "rachel"], ["laban", "rachel", "leah", "jacob"]]'::jsonb, ARRAY['jacob', 'laban', 'leah', 'rachel']::text[], '[{"book": "창", "from": "31:17", "to": "31:55"}]'::jsonb, -1961, -1961, 'approx', 20, 'patriarch_jacob_israel', '야곱: 이스라엘이 되다', 2, 'lm_pat_gilead', 'published'),
    ('era_monarchy', '압살롬의 반역: 감람산의 눈물', '압살롬은 백성의 마음을 빼앗아 반역을 일으키고, 다윗은 눈물로 예루살렘을 떠난다.', '통일왕국 시대는 사울, 다윗, 솔로몬이 이스라엘 전체를 다스리던 시기입니다. 이 이야기는 「압살롬의 반역」을 다룹니다.', '["헤브론 성문 근처, 30대의 긴 머리 압살롬이 병거와 말과 따르는 사람들을 세우고 몰래 반역을 도모하며, 주변 사람들의 손을 잡아 주지만 얼굴에는 사악하고 계산적인 미소가 드러나는 장면. 왕이 되었다는 글자나 깃발 문구는 보이지 않는다", "예루살렘을 떠나는 60대 초반 다윗이 가족과 충성스러운 신하들과 함께 슬픈 표정으로 도망가고, 사독과 아비아달 제사장도 침통한 얼굴로 언약궤를 메고 서 있으며, 다윗이 제사장들에게 성쪽을 가리키며 언약궤를 다시 성으로 돌아가게 하라고 손짓하는 장면", "감람산 길, 침통한 표정의 백성들이 다윗과 함께 울며 산을 오르고, 60대 초반 다윗은 신하 후새를 향해 침통하지만 단호한 표정으로 손으로 막아서며 예루살렘 궁전 방향을 가리키며 돌아가 압살롬 곁에서 아히도벨의 모략을 막아 달라고 부탁하는 장면", "예루살렘 궁정 회의에서 노년의 신하 후새와 아히도벨이 압살롬 앞에서 조언한다. 후새의 마음속에는 다윗이 희미한 투명 이미지로 보이고, 압살롬은 악한 표정으로 후새의 조언을 선택한다. 곁의 아히도벨은 낙담한 표정을 짓는다. 죽음 장면은 보이지 않는다"]'::jsonb, '["헤브론 성문 근처, 압살롬이 병거와 말과 따르는 사람들을 세우고 몰래 반역을 도모한다", "압살롬은 백성의 마음을 빼앗아 반역을 일으키고, 다윗은 눈물로 예루살렘을 떠난다", "감람산 길, 다윗은 후새에게 궁으로 돌아가서 압살롬을 막아줄 것을 부탁한다", "예루살렘 궁정 회의에서 후새와 아히도벨이 압살롬 앞에서 조언하고 압살롬은 후새를 택한다"]'::jsonb, '[["absalom"], ["david"], ["david"], ["absalom"]]'::jsonb, ARRAY['david', 'absalom']::text[], '[{"book": "삼하", "from": "15:1", "to": "15:37"}, {"book": "삼하", "from": "17:1", "to": "17:23"}]'::jsonb, -979, -979, 'approx', 20, 'monarchy_david_covenant_fracture', '다윗 왕국: 언약과 집안의 균열', 2, 'lm_mon_jerusalem', 'published'),
    ('era_nt_apostolic', '예루살렘 회의와 두 번째 여정의 갈림길', '예루살렘 회의는 이방 신자들에게 은혜의 길을 확인하고, 바울과 바나바는 갈라져 각각 새 여정을 시작한다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「예루살렘 회의와 두 번째 여정의 갈림길」을 다룹니다.', '["예루살렘에서 제자들은 유다 사람들이 이방 신자 문제를 두고 잘못된 가르침을 전하여 그 사람들과 논쟁한다", "베드로와 야고보가 하나님의 은혜와 이방인 구원을 설명하자 회의장의 긴장이 누그러진다", "교회가 편지를 보내고 유다와 실라가 안디옥 성도들에게 권면하자 사람들은 위로받은 얼굴로 기뻐한다", "바울과 바나바가 마가 요한 문제로 심히 다투고 서로 아픈 표정으로 다른 길을 택한다"]'::jsonb, '["예루살렘에서 제자들은 유다 사람들이 이방 신자 문제를 두고 잘못된 가르침을 전하여 그 사람들과 논쟁한다", "베드로와 야고보가 하나님의 은혜와 이방인 구원을 설명하자 회의장의 긴장이 누그러진다", "교회가 편지를 보내고 유다와 실라가 안디옥 성도들에게 권면한다", "바울과 바나바가 마가 요한 문제로 심히 다투고 서로 다른 길을 택한다"]'::jsonb, '[["peter", "james", "paul", "barnabas"], ["peter", "james"], ["barnabas", "silas"], ["paul", "barnabas", "john_mark"]]'::jsonb, ARRAY['paul', 'barnabas', 'peter', 'james', 'john_mark', 'silas']::text[], '[{"book": "행", "from": "15:1", "to": "15:41"}]'::jsonb, 49, 49, 'approx', 20, 'paul_second_journey', '바울의 2차 전도 여행', 3, 'lm_nt_ap_jerusalem', 'published'),
    ('era_nt_public_ministry', '오병이어와 물 위를 걸으심', '예수님은 오병이어로 큰 무리를 먹이시고 밤바다 위를 걸어 제자들에게 오신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「오병이어와 물 위를 걸으심」을 다룹니다.', '["빈 들판에 큰 무리가 앉아 있고 예수님이 떡 다섯 개와 물고기 두 마리를 받으신다", "예수님이 축사하시고 제자들이 떡과 물고기를 나누자 모두가 배부르게 먹는다", "밤바다에서 제자들의 배가 바람에 흔들리고 예수님이 물 위로 걸어오신다"]'::jsonb, '["빈 들판에 큰 무리가 앉아 있고 예수님이 떡 다섯 개와 물고기 두 마리를 받으신다", "예수님이 축사하시고 떡과 물고기로 모두가 배부르게 먹는다", "밤바다에서 제자들의 배가 바람에 흔들리고 예수님이 물 위로 걸어오신다"]'::jsonb, '[["jesus"], ["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"]]'::jsonb, ARRAY['jesus', 'peter', 'andrew', 'james_zebedee', 'john', 'philip', 'bartholomew', 'matthew', 'thomas', 'james_alphaeus', 'thaddaeus', 'simon_zealot', 'judas']::text[], '[{"book": "마", "from": "14:13", "to": "14:33"}, {"book": "막", "from": "6:30", "to": "6:52"}, {"book": "눅", "from": "9:10", "to": "9:17"}, {"book": "요", "from": "6:1", "to": "6:21"}]'::jsonb, 29, 29, 'approx', 20, 'galilee_ministry', '갈릴리 사역', 2, 'lm_nt_pm_bethsaida', 'published'),
    ('era_nt_apostolic', '2차 전도 여행: 디모데 합류와 교회들을 굳게 함', '바울은 디모데를 동역자로 세우고 여러 교회에 예루살렘 회의의 결정을 전해 믿음을 굳게 한다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「차 전도 여행」을 다룹니다.', '["바울과 실라가 더베와 루스드라에 이르고 디모데는 겸손하지만 기대 어린 얼굴로 두 사람을 맞는다", "바울 일행이 디모데에게 할례를 행한다", "교회들이 믿음이 굳어지고 수가 늘어나고 믿는 자들이 늘어나며, 바울과 동역자들은 감사와 결심이 담긴 얼굴로 길을 간다"]'::jsonb, '["바울과 실라가 더베와 루스드라에 이르고 디모데는 두 사람을 맞는다", "바울 일행이 디모데에게 할례를 행한다", "교회들이 믿음이 굳어지고 수가 늘어나고 믿는 자들이 늘어난다"]'::jsonb, '[["paul", "silas", "timothy"], ["paul", "silas", "timothy"], ["paul", "silas", "timothy"]]'::jsonb, ARRAY['paul', 'silas', 'timothy']::text[], '[{"book": "행", "from": "16:1", "to": "16:5"}]'::jsonb, 49, 49, 'approx', 21, 'paul_second_journey', '바울의 2차 전도 여행', 3, 'lm_nt_ap_lystra_derbe', 'published'),
    ('era_nt_post_apostolic', '감옥 속 기쁨과 그리스도의 마음', '바울은 감옥에서도 빌립보 성도들에게 기쁨과 겸손한 그리스도의 마음을 품으라고 권면한다.', '빌립보서는 바울이 감옥에서, 복음 동역과 후원을 이어 온 빌립보 교회에 기쁨과 겸손을 권하려고 쓴 편지입니다. 이 이야기는 「감옥 속 기쁨과 그리스도의 마음」을 다룹니다.', '["바울과 디모데가 감옥 곁에서 빌립보 성도들을 위해 기도하며, 바울은 쇠사슬에도 밝은 미소를 잃지 않는다", "바울의 편지에는 빌립보 성도들이 서로 낮은 자리에서 발을 씻기듯 섬기며, 그리스도의 겸손한 마음을 배우는 진지한 표정이 나타난다", "바울의 편지에는 빌립보 성도들이 반짝 반짝 빛나고 그 위에는 십자가가 있고, 외부 인들은 어두우며 위에 십자가가 없고 지친 표정"]'::jsonb, '["바울과 디모데가 감옥 곁에서 빌립보 성도들을 위해 기도한다", "바울이 하나님과 동등되지 않고 친히 우리에게 내려오신 예수님에 대해 이야기한다", "바울이 하나님의 자녀들로서 별처럼 빛나는 삶에 대해 이야기한다"]'::jsonb, '[["paul", "timothy"], [], []]'::jsonb, ARRAY['paul', 'timothy']::text[], '[{"book": "빌", "from": "1:12", "to": "2:18"}]'::jsonb, 62, 62, 'approx', 21, 'roman_prison_churches', '로마 감옥에서도 세워지는 교회', 3, 'lm_nt_post_philippi', 'published'),
    ('era_exodus', '바알브올: 언약을 더럽히다', '이스라엘은 모압 평지에서 유혹과 우상 제사에 흔들리지만, 하나님은 언약의 거룩함을 다시 세우신다.', '출애굽과 광야 여정은 이스라엘이 애굽을 떠나 시내산과 광야를 지나는 시기입니다. 이 이야기는 「바알브올」을 다룹니다.', '["이스라엘 백성이 모압 평지에서 바알브올 제사와 잔치에 끌려가 우상 앞에 앉고, 팔십세 모세와 장로들은 진영 입구에서 슬픔과 분노로 바라본다. 성적 장면은 보이지 않는다", "비느하스가 제사장 가문 젊은이의 단호한 얼굴로 진영 안 죄악을 막으러 달려가고, 주변 백성은 놀라 물러선다. 폭력은 암시만 하고 피나 시신은 보이지 않는다", "비느하스가 창을 내려놓고 무릎 꿇어 하나님의 진노가 멈춘 것을 바라보며, 모세와 백성은 두려움 속에 정결을 회복하려 한다"]'::jsonb, '["이스라엘 백성이 모압 평지에서 바알브올 제사와 잔치에 끌려가 우상 앞에 앉는다", "비느하스가 제사장 가문 젊은이의 진영 안 죄악을 막으러 창을 들고 달려간다", "모세와 비느하스가 창을 내려놓고 무릎 꿇어 하나님의 진노가 멈춘 것을 바라본다"]'::jsonb, '[["moses"], ["phinehas"], ["moses", "phinehas", "god"]]'::jsonb, ARRAY['moses', 'god', 'phinehas']::text[], '[{"book": "민", "from": "25:1", "to": "25:18"}]'::jsonb, -1408, -1408, 'approx', 21, 'exodus_wilderness_covenant', '광야의 삶과 언약 훈련', 2, 'lm_exo_baal_peor', 'published'),
    ('era_nt_public_ministry', '생명의 떡 말씀', '예수님은 자신이 하늘에서 내려온 생명의 떡이라고 말씀하시고, 베드로는 영생의 말씀이 주께 있다고 고백한다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「생명의 떡 말씀」을 다룹니다.', '["가버나움 회당에서 사람들이 예수님을 둘러서고, 예수님은 말씀을 전하신다. 예수님의 말풍선에는 사람들이 하나님을 바라보고 하나님은 하늘에서 빛나는 빵(하나)을 내려주시는 그림", "예수님이 자신을 생명의 떡으로 밝히시자 사람들이 서로 수군거린다", "예수님은 제자들에게 물어보시고 베드로가 영생의 말씀이 주께 있다고 고백하며 예수님 곁에 선다. 베드로의 말풍선에는 예수님이 말씀을 들고 뒤에서 밝은 빛이 나오는 모습"]'::jsonb, '["가버나움 회당에서 사람들이 예수님을 둘러선다, 예수님은 참 떡을 내려주심을 말씀하신다", "예수님이 자신을 생명의 떡으로 밝히시자 사람들이 서로 수군거린다", "예수님은 제자들에게 물어보시고 베드로가 영생의 말씀이 주께 있다고 고백하며 예수님 곁에 선다"]'::jsonb, '[["jesus"], ["jesus"], ["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot"]]'::jsonb, ARRAY['jesus', 'peter', 'andrew', 'james_zebedee', 'john', 'philip', 'bartholomew', 'matthew', 'thomas', 'james_alphaeus', 'thaddaeus', 'simon_zealot', 'judas']::text[], '[{"book": "요", "from": "6:22", "to": "6:71"}]'::jsonb, 29, 29, 'approx', 21, 'galilee_ministry', '갈릴리 사역', 2, 'lm_nt_pm_capernaum', 'published'),
    ('era_monarchy', '압살롬의 최후: 다윗의 통곡', '압살롬의 반역은 수풀에서 끝나고, 다윗은 원수보다 아들로 그를 통곡한다.', '통일왕국 시대는 사울, 다윗, 솔로몬이 이스라엘 전체를 다스리던 시기입니다. 이 이야기는 「압살롬의 최후」를 다룹니다.', '["마하나임 성문 앞, 60대 초반 다윗이 전쟁터로 나갈 군대를 정비해 요압과 지휘관들에게 나누어 보내며, 압살롬을 죽이지 말고 반드시 생포해 데려오라고 단호하게 명령하는 장면.", "에브라임 수풀의 큰 상수리나무 아래, 30대 압살롬의 긴 머리털이 굵은 가지에 걸려 공중에 매달리고 노새는 아래로 달아나며, 멀리 다윗의 군사들이 조심스럽게 다가오는 장면. 피와 상처는 보이지 않는다", "요압이 상수리나무에 머리가 걸려있는 압살롬에게 창을 겨누며 다가간다", "성문 위 방으로 올라간 60대 초반 다윗에게 전령이 압살롬의 죽음 소식을 전하고, 다윗은 얼굴을 가리며 무너져 통곡하는 장면. 주변 신하들은 침묵하며 슬퍼한다"]'::jsonb, '["마하나임 성문 앞, 다윗이 지휘관들에게 압살롬을 죽이지 말고 생포해 올 것을 명령한다", "압살롬이 머리털이 굵은 가지에 걸려 매달리고 노새를 달아난다", "요압이 상수리나무 아래 압살롬을 죽인다", "다윗에게 전령이 압살롬의 죽음 소식을 전한다"]'::jsonb, '[["david"], ["absalom"], ["absalom"], ["david"]]'::jsonb, ARRAY['david', 'absalom']::text[], '[{"book": "삼하", "from": "18:5", "to": "18:33"}]'::jsonb, -978, -978, 'approx', 21, 'monarchy_david_covenant_fracture', '다윗 왕국: 언약과 집안의 균열', 2, 'lm_mon_ephraim_forest', 'published'),
    ('era_patriarch', '얍복강 씨름: 이스라엘', '야곱은 밤새 씨름하며 새 이름 ‘이스라엘’을 받는다.', '족장 시대는 아브라함, 이삭, 야곱, 요셉의 가족 이야기가 중심입니다. 이 이야기는 「얍복강 씨름」을 다룹니다.', '["얍복강 밤 어둠 속에서 야곱이 가족과 소유를 먼저 건너보낸 뒤 혼자 남아 숨을 고르며 두려운 얼굴로 서 있다", "천사 같은 신비한 존재가 야곱을 붙잡고 밤새 씨름을 시작하며, 야곱은 온몸으로 버티고 얼굴에는 절박함이 드러난다", "신비한 존재가 야곱의 허벅지를 치자 야곱이 쓰러지면서 고통 속에서도 신비한 존재를 붙잡는다", "새벽빛 속에서 이름을 받은 중년의 야곱이 다리를 절며 가족에게 돌아오고, 얼굴에는 고통과 새 정체성을 얻은 경외감이 함께 보인다"]'::jsonb, '["얍복강 밤 어둠 속에서 야곱이 가족과 소유를 먼저 보내고 두려운 얼굴로 서 있다", "천사 같은 신비한 존재가 야곱을 붙잡고 밤새 씨름을 시작한다", "야곱이 쓰러지면서 고통 속에서도 신비한 존재를 붙잡는다", "새벽빛 속에서 이름을 받은 중년의 야곱이 다리를 절며 가족에게 돌아온다"]'::jsonb, '[["jacob"], ["jacob"], ["jacob"], ["jacob"]]'::jsonb, ARRAY['jacob']::text[], '[{"book": "창", "from": "32:24", "to": "32:32"}]'::jsonb, -1960, -1960, 'approx', 21, 'patriarch_jacob_israel', '야곱: 이스라엘이 되다', 2, 'lm_pat_jabbok', 'published'),
    ('era_divided_kingdom', '여호람의 남유다: 아합 집의 길', '남유다 여호람은 아합 집과 연결되어 악한 길을 걷고, 에돔과 립나의 반역 속에서 나라가 흔들린다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「여호람의 남유다」를 다룹니다.', '["남유다 왕 여호람이 예루살렘 왕궁에서 왕위에 오르고, 신하들이 왕관과 왕복을 준비하지만 분위기는 밝지 않고 긴장되어 있는 장면", "여호람이 아합의 딸을 아내로 맞아들이고 아합 집의 길을 따르기 시작하자, 예루살렘 위에는 하나님의 거룩한 빛이 엄중하게 비치며 분노를 나타내는 장면. 아내는 이름 없는 왕비로 보이고, 우상 문양이 은근히 배경에 보인다", "에돔과 립나가 유다를 배반하여 여호람의 군대와 맞서고, 여호람이 병거와 군사들을 이끌고 전쟁터에서 혼란스럽게 싸우는 장면. 전투는 먼 거리로 보이고 피와 시신은 보이지 않는다", "여호람이 예루살렘 왕궁 침상에서 죽음을 맞고, 신하들이 침상 주변에서 슬퍼하는 장면. 평화로운 죽음 장면이며 시신의 세부 묘사는 보이지 않는다"]'::jsonb, '["남유다 왕 여호람이 예루살렘 왕궁에서 왕위에 오른다", "남유다 여호람은 아합 딸을 아내로 맞아 하나님이 노하신다", "에돔과 립나가 유다를 배반하여 여호람의 군대와 맞선다", "여호람이 예루살렘 왕궁 침상에서 죽음을 맞다, 신하들이 침상 주변에서 슬퍼한다"]'::jsonb, '[["jehoram_judah"], ["jehoram_judah", "god"], ["jehoram_judah"], ["jehoram_judah"]]'::jsonb, ARRAY['jehoram_judah', 'god']::text[], '[{"book": "왕하", "from": "8:16", "to": "8:24"}]'::jsonb, -848, -841, 'approx', 21, 'divided_elisha_jehu_judgment', '엘리사와 예후: 표징과 심판', 3, 'lm_div_jerusalem_jehoram', 'published'),
    ('era_nt_apostolic', '2차 전도 여행: 마게도냐 환상', '성령께서 길을 막으시는 가운데 바울은 드로아에서 마게도냐 사람의 환상을 보고 복음의 새 문을 확신한다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「차 전도 여행」을 다룹니다.', '["바울과 실라와 디모데가 아시아로 가려 하지만 예수의 영이 막아 길이 막히자 긴장한 얼굴로 멈춰 선다", "무시아 앞에서 비두니아로 가려는 계획도 막히자 일행은 조용히 하나님의 뜻을 찾는다", "드로아 밤에 바울이 마게도냐 사람이 건너와 도우라 부르는 환상을 보고 놀란 얼굴로 깨어난다", "일행이 하나님이 마게도냐로 부르셨음을 확신하고 결심한 표정으로 배를 준비한다"]'::jsonb, '["바울과 실라와 디모데가 아시아로 가려 하지만 예수의 영이 막아 길이 막힌다", "무시아 앞에서 비두니아로 가려는 계획도 막히자 일행은 조용히 하나님의 뜻을 찾는다", "드로아 밤에 바울이 마게도냐 사람이 건너와 도우라 부르는 환상을 본다", "일행이 하나님이 마게도냐로 부르셨음을 확신하고 결심한 표정으로 배를 준비한다"]'::jsonb, '[["paul", "silas", "timothy"], ["paul", "silas", "timothy"], ["paul"], ["paul", "silas", "timothy"]]'::jsonb, ARRAY['paul', 'silas', 'timothy']::text[], '[{"book": "행", "from": "16:6", "to": "16:10"}]'::jsonb, 49, 49, 'approx', 22, 'paul_second_journey', '바울의 2차 전도 여행', 3, 'lm_nt_ap_troas', 'published'),
    ('era_nt_post_apostolic', '그리스도의 충만과 거짓 가르침 경계', '바울은 골로새 성도들에게 그리스도의 충만을 높이고 사람의 전통과 거짓 가르침을 경계하라고 권면한다.', '골로새서는 바울이 감옥에서, 거짓 가르침의 영향을 받을 수 있던 골로새 교회에 그리스도의 충분함을 전한 편지입니다. 이 이야기는 「그리스도의 충만과 거짓 가르침 경계」를 다룹니다.', '["바울과 디모데가 감옥 밖에서 온 소식을 듣고 골로새 성도들을 위해 담대한 얼굴로 두루마리 편지를 준비한다", "바울의 편지에는 세상의 권력과 권세와 학문을 따르지 말고 오직 하나님만을 따르라는 그림이 담겨있다", "바울의 편지를 받은 성도들이 그리스도를 중심에 모시듯 서로 모여 서고, 거짓 가르침을 밀어내는 단호하고 평안한 표정을 짓는다"]'::jsonb, '["바울과 디모데가 감옥 밖에서 온 소식을 듣고 골로새 성도들을 위해 두루마리 편지를 준비한다", "바울이 세상의 권력과 권세와 학문을 따르지 말고 오직 하나님만을 따르라고 말한다", "바울이 그리스도를 중심에 두고, 거짓 가르침과 초등학문을 밀어내는 삶에 대해 말한다"]'::jsonb, '[["paul", "timothy"], [], []]'::jsonb, ARRAY['paul', 'timothy']::text[], '[{"book": "골", "from": "1:24", "to": "2:23"}]'::jsonb, 62, 62, 'approx', 22, 'roman_prison_churches', '로마 감옥에서도 세워지는 교회', 3, 'lm_nt_post_colossae', 'published'),
    ('era_exodus', '모압 언약: 마음을 돌이키라', '모세는 새 세대에게 광야 길을 돌아보게 하고, 하나님께 마음을 돌이켜 언약의 길을 걷도록 권면한다.', '출애굽과 광야 여정은 이스라엘이 애굽을 떠나 시내산과 광야를 지나는 시기입니다. 이 이야기는 「모압 언약」을 다룹니다.', '["늙은 흰 머리의 모세가 모압 평지에서 백성들에게 광야 생활을 하나님이 인도하셨음을 말하고, 큰 글자 없는 말풍선 안에는 하나님이 백성을 먹이시고 전쟁에서 이기게 하신 장면들이 그림으로 보인다", "늙은 흰 머리의 모세가 백성들에게 우상을 만들지 말고 오직 하나님만 따르라고 말하고, 큰 글자 없는 말풍선 안에는 송아지 모양과 은금 우상이 흐릿하게 막혀 있는 상징 그림이 담겨 있다", "늙은 흰 머리의 모세가 백성들에게 오직 하나님만 따르라고 말하고, 큰 글자 없는 말풍선 안에는 하나님이 복을 주셔서 이스라엘 백성들이 풍요롭고 행복하게 사는 그림이 담겨 있다"]'::jsonb, '["모세가 모압 평지에서 백성들에게 광야 생활을 하나님이 인도하셨음을 말한다", "모세가 백성들에게 우상을 만들지 말고 오직 하나님만 따르라고 말한다", "모세가 백성들에게 오직 하나님만 따르면 하나님이 풍요를 약속하심을 말한다"]'::jsonb, '[["god", "moses"], ["moses"], ["god", "moses"]]'::jsonb, ARRAY['moses', 'god']::text[], '[{"book": "신", "from": "29:1", "to": "30:10"}]'::jsonb, -1406, -1406, 'approx', 22, 'exodus_wilderness_covenant', '광야의 삶과 언약 훈련', 2, 'lm_exo_plains_moab', 'published'),
    ('era_patriarch', '에서와 화해: 달려오는 형', '두려움으로 맞이한 재회는 포옹과 눈물로 풀린다.', '족장 시대는 아브라함, 이삭, 야곱, 요셉의 가족 이야기가 중심입니다. 이 이야기는 「에서와 화해」를 다룹니다.', '["야곱이 가족과 가축을 여러 무리로 나누어 앞세우고, 멀리 붉은 사냥꾼 같은 에서가 많은 사람들과 다가오자 야곱의 얼굴에 두려움이 번진다", "야곱이 에서 앞에서 일곱 번 몸을 낮추어 절하고, 에서는 예상과 달리 무기를 내리지 않은 채 달려오지만 얼굴에는 분노보다 그리움이 드러난다", "에서가 야곱을 끌어안고 울고 야곱도 울음을 삼키며, 두 형제의 옷차림과 체형 차이가 뚜렷하게 보인다. 뒤쪽 가족들은 안도의 표정으로 바라본다"]'::jsonb, '["야곱이 가족과 가축을 여러 무리로 나누어 앞세운다", "야곱이 에서 앞에서 일곱 번 몸을 낮추어 절한다", "에서가 야곱을 끌어안고 울고 야곱도 울음을 삼키다"]'::jsonb, '[["jacob", "esau"], ["jacob", "esau"], ["jacob", "esau"]]'::jsonb, ARRAY['jacob', 'esau']::text[], '[{"book": "창", "from": "33:1", "to": "33:11"}]'::jsonb, -1960, -1960, 'approx', 22, 'patriarch_jacob_israel', '야곱: 이스라엘이 되다', 2, 'lm_pat_jabbok', 'published'),
    ('era_divided_kingdom', '유다 아하시야: 길르앗 라못의 상처', '유다의 아하시야는 아합 집의 길을 따라 북이스라엘 요람과 함께 전쟁에 나아가고, 요람은 이스르엘에서 상처를 치료한다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「유다 아하시야」를 다룹니다.', '["스물두 살의 유다 왕 아하시야가 예루살렘에서 왕위에 오르고, 젊은 왕의 얼굴에는 자신감과 불안이 함께 보이는 장면", "길르앗 라못 전쟁터에서 유다 왕 아하시야와 북이스라엘 왕 요람이 함께 아람 군대와 싸우고, 요람이 전투 중 부상을 입어 병거 안에서 고통스러워하는 장면. 상처와 피의 세부 묘사는 보이지 않는다", "이스르엘의 방 안에서 북이스라엘 왕 요람이 상처를 치료받으며 누워 있고, 유다 왕 아하시야가 찾아와 곁에서 위로하는 장면. 두 왕의 동맹과 불안한 분위기가 분명히 보인다"]'::jsonb, '["스물두 살의 유다 왕 아하시야가 예루살렘에서 왕위에 오른다", "유다 왕 아하시야와 북이스라엘 왕 요람이 함께 아람 군대와 싸우다 요람이 부상당한다", "이스르엘의 방 안에서 북이스라엘 왕 요람이 상처를 치료받으며 누워 있고 아하시야가 방문한다"]'::jsonb, '[["ahaziah_judah"], ["ahaziah_judah", "joram_israel"], ["ahaziah_judah", "joram_israel"]]'::jsonb, ARRAY['ahaziah_judah', 'joram_israel']::text[], '[{"book": "왕하", "from": "8:25", "to": "8:29"}]'::jsonb, -841, -841, 'approx', 22, 'divided_elisha_jehu_judgment', '엘리사와 예후: 표징과 심판', 3, 'lm_div_ramoth_jezreel', 'published'),
    ('era_monarchy', '인구조사와 제단: 다윗의 선택', '잘못된 자랑이 재앙을 부르고, 다윗은 값을 치르고 제단을 세운다.', '통일왕국 시대는 사울, 다윗, 솔로몬이 이스라엘 전체를 다스리던 시기입니다. 이 이야기는 「인구조사와 제단」을 다룹니다.', '["늙은 왕 다윗이 예루살렘 왕궁에서 요압과 군사 지휘관들에게 이스라엘과 유다의 수를 세라고 명령하고, 요압은 걱정스러운 얼굴로 왕을 바라본다", "선견자 갓이 하얀 머리와 수염의 늙은 다윗에게 와서 하나님의 책망과 세 가지 재앙의 선택을 전하고, 다윗은 바닥에 엎드려 울며 괴로워하는 장면.", "단에서부터 브엘세바까지 이스라엘 전역에 온역의 어두운 기운이 퍼지고 수많은 집과 마을이 비통해하는 장면. 위쪽에는 사람 형상 없는 하나님의 엄중한 심판 빛이 드리우며, 칠만 명의 죽음을 상징하되 시신과 피는 직접 보이지 않는다", "늙은 왕 다윗이 아라우나의 타작마당 제단 앞에서 손을 들고 기도하며, 하늘에서 불이 제물을 사르고 재앙이 멈추는 빛이 예루살렘 위에 퍼진다"]'::jsonb, '["왕 다윗이 예루살렘 왕궁에서 요압과 군사 지휘관들에게 이스라엘과 유다의 수를 세라고 명령한다", "갓이 다윗에게 와서 하나님의 책망과 세 가지 재앙의 선택을 전한다", "하나님의 진노로 단에서부터 브엘세바까지 이스라엘 전역에서 7만명이 죽는다", "왕 다윗이 아라우나의 타작마당 제단 앞에서 손을 들고 기도하고 하나님의 진노가 그친다"]'::jsonb, '[["david"], ["david"], ["god"], ["david", "god"]]'::jsonb, ARRAY['david', 'god']::text[], '[{"book": "삼하", "from": "24:10", "to": "24:25"}]'::jsonb, -970, -970, 'approx', 22, 'monarchy_david_covenant_fracture', '다윗 왕국: 언약과 집안의 균열', 2, 'lm_mon_jerusalem', 'published'),
    ('era_nt_public_ministry', '장로들의 전통과 정결 논쟁', '예수님은 사람을 더럽게 하는 것은 손의 의식이 아니라 마음에서 나오는 악이라고 가르치신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「장로들의 전통과 정결 논쟁」을 다룹니다.', '["예루살렘에서 온 지도자들이 제자들이 장로들의 전통대로 손을 씻지 않는다고 따진다", "예수님이 장로들의 전통을 따지는 지도자들 앞에서 한 손으로 성경 두루마리를 가리키며 하나님의 계명을 강조하신다", "예수님이 무리를 불러 사람을 더럽게 하는 것이 마음에서 나온다고 가르치신다. 예수님의 말풍선에는 겉보기에 멀쩡하지만 마음속이 시커먼 사람의 주변에 냄새가 나고 파리가 꼬이는 모습"]'::jsonb, '["예루살렘에서 온 지도자들이 제자들이 장로들의 전통대로 손을 씻지 않는다고 따진다", "예수님은 사람을 더럽게 하는 것은 손의 의식이 아니라 마음에서 나오는 악이라고 가르치신다", "예수님이 무리를 불러 사람을 더럽게 하는 것이 마음에서 나온다고 가르치신다"]'::jsonb, '[["peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["jesus"], ["jesus"]]'::jsonb, ARRAY['jesus', 'peter', 'andrew', 'james_zebedee', 'john', 'philip', 'bartholomew', 'matthew', 'thomas', 'james_alphaeus', 'thaddaeus', 'simon_zealot', 'judas']::text[], '[{"book": "마", "from": "15:1", "to": "15:20"}, {"book": "막", "from": "7:1", "to": "7:23"}]'::jsonb, 29, 29, 'approx', 22, 'galilee_ministry', '갈릴리 사역', 2, 'rgn_galilee', 'published'),
    ('era_nt_apostolic', '2차 전도 여행: 빌립보 사역', '빌립보에서 루디아가 마음을 열고, 감옥의 밤에는 찬송과 지진을 통해 간수가 구원의 길을 묻는다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「차 전도 여행」을 다룹니다.', '["강가 기도처에서 자주색 천 장사를 하는 루디아가 고운 자주색 천 꾸러미 곁에 앉아 열린 마음과 집중한 얼굴로 바울의 말을 듣고, 바울은 차분히 복음을 전한다", "바울이 지치고 억눌린 점치는 여종에게서 귀신을 내쫓자, 돈을 잃은 주인들은 분노한 얼굴로 바울과 실라의 옷을 붙잡아 끌고 간다", "밤중 깊은 감옥에서 매 맞아 상처 입은 바울과 실라가 발에 차꼬를 찬 채 평안한 얼굴로 기도하고 찬송한다", "지진 뒤 감옥 문이 열린 가운데 간수가 떨리는 얼굴로 무릎 꿇어 구원을 묻고, 바울과 실라는 상처 입은 몸으로도 그에게 주 예수를 전한다"]'::jsonb, '["강가 기도처에서 루디아가 고운 자주색 천 꾸러미 곁에 앉아 바울의 말을 듣는다", "바울이 점치는 여종에게서 귀신을 내쫓자 돈을 잃은 주인들이 바울과 실라를 끌고 간다", "밤중 깊은 감옥에서 매 맞아 상처 입은 바울과 실라가 평안한 얼굴로 기도하고 찬송한다", "지진 뒤 감옥 문이 열린 가운데 간수가 떨리는 얼굴로 무릎 꿇어 구원을 묻는다"]'::jsonb, '[["paul", "lydia"], ["paul", "silas"], ["paul", "silas"], ["paul", "silas"]]'::jsonb, ARRAY['paul', 'silas', 'timothy', 'lydia']::text[], '[{"book": "행", "from": "16:11", "to": "16:40"}]'::jsonb, 50, 50, 'approx', 23, 'paul_second_journey', '바울의 2차 전도 여행', 3, 'lm_nt_ap_philippi', 'published'),
    ('era_nt_post_apostolic', '교회 리더십과 거짓 가르침 경계', '바울은 디모데에게 교회 리더십의 자격과 거짓 가르침을 경계하는 목회자의 책임을 당부한다.', '디모데전서는 바울이 에베소에 남겨 둔 디모데에게 거짓 교훈을 막고 교회 질서를 세우라고 맡긴 편지입니다. 이 이야기는 「교회 리더십과 거짓 가르침 경계」를 다룹니다.', '["바울이 디모데에게 담대히 말하는 장면. 말풍선에는 장로는 돈이나 폭력을 멀리하고 겸손하며 사랑이 넘치는 온유한 사람이어야 함을 보여준다", "바울이 디모데에게 담대히 말하는 장면. 말풍선에는 거짓 가르침을 전하는 사람이 낯선 규칙을 내세우자, 디모데는 단호한 표정으로 성도들 앞에 서서 바른 가르침을 지킨다"]'::jsonb, '["바울이 디모데에게 장로는 돈이나 폭력을 멀리하고 겸손하며 사랑이 넘치는 온유한 사람이어야 함을 말한다", "바울이 디모데에게 거짓 가르침을 전하는 사람이 낯선 규칙을 주의할 것을 말한다"]'::jsonb, '[["paul", "timothy"], ["paul", "timothy"]]'::jsonb, ARRAY['paul', 'timothy']::text[], '[{"book": "딤전", "from": "3:1", "to": "4:16"}]'::jsonb, 64, 64, 'approx', 23, 'next_generation_suffering_church', '다음 세대와 고난받는 교회', 4, 'lm_nt_post_ephesus', 'published'),
    ('era_patriarch', '벧엘 귀환: 라헬의 죽음', '야곱의 가정은 이동 중 큰 상실을 겪고도 약속의 길을 이어간다.', '족장 시대는 아브라함, 이삭, 야곱, 요셉의 가족 이야기가 중심입니다. 이 이야기는 「벧엘 귀환」을 다룹니다.', '["하나님의 빛이 야곱에게 임하고 야곱은 가족에게 우상을 버리고 길을 준비하라고 엄숙히 손짓한다. 가족들은 이방 신상들을 야곱에게 건낸다", "베들레헴 길 위에서 라헬이 해산의 고통으로 누워 있고, 야곱은 초조하게 곁을 지키며 산파는 갓난아이를 조심히 받는다. 직접적인 출산 묘사는 없다", "야곱이 라헬의 무덤 기둥을 세우고 오래 서 있으며, 품에 안긴 갓난 베냐민과 가족들은 먼지 묻은 여행복으로 조용히 애도한다"]'::jsonb, '["야곱은 하나님의 명령을 따라 가지고 있던 우상들을 제거한다", "베들레헴 길 위에서 라헬이 해산의 고통으로 누워 있고 베냐민이 나온다", "야곱이 아기 베냐민을 들고 라헬의 무덤 기둥을 세우고 슬퍼한다"]'::jsonb, '[["god", "jacob"], ["rachel", "jacob", "benjamin"], ["jacob", "benjamin"]]'::jsonb, ARRAY['jacob', 'rachel', 'benjamin']::text[], '[{"book": "창", "from": "35:1", "to": "35:20"}]'::jsonb, -1955, -1955, 'approx', 23, 'patriarch_jacob_israel', '야곱: 이스라엘이 되다', 2, 'lm_pat_bethlehem', 'published')
)
insert into events (era_id, title, summary, background_context, story_scenes, scene_captions, scene_characters, character_codes, bible_refs, start_year, end_year, time_precision, story_index, unit_code, unit_title, unit_order, landmark_id, status)
select
  e.id,
  s.title,
  s.summary,
  s.background_context,
  s.story_scenes,
  s.scene_captions,
  s.scene_characters,
  s.character_codes,
  s.bible_refs,
  s.start_year,
  s.end_year,
  s.time_precision,
  s.story_index,
  s.unit_code,
  s.unit_title,
  s.unit_order,
  lm.id,
  s.status
from seed_events s
join eras e on e.code = s.era_code
join landmarks lm on lm.code = s.landmark_code
on conflict (era_id, story_index) do update set
  title = excluded.title,
  summary = excluded.summary,
  background_context = excluded.background_context,
  story_scenes = excluded.story_scenes,
  scene_captions = excluded.scene_captions,
  scene_characters = excluded.scene_characters,
  character_codes = excluded.character_codes,
  bible_refs = excluded.bible_refs,
  start_year = excluded.start_year,
  end_year = excluded.end_year,
  time_precision = excluded.time_precision,
  unit_code = excluded.unit_code,
  unit_title = excluded.unit_title,
  unit_order = excluded.unit_order,
  landmark_id = excluded.landmark_id,
  status = excluded.status
;

with seed_events (era_code, title, summary, background_context, story_scenes, scene_captions, scene_characters, character_codes, bible_refs, start_year, end_year, time_precision, story_index, unit_code, unit_title, unit_order, landmark_code, status) as (
  values
    ('era_monarchy', '솔로몬 즉위: 왕의 노새', '밧세바와 나단의 요청 뒤에 다윗은 솔로몬을 왕으로 세우고, 솔로몬은 아도니야를 단호하지만 절제 있게 대한다.', '통일왕국 시대는 사울, 다윗, 솔로몬이 이스라엘 전체를 다스리던 시기입니다. 이 이야기는 「솔로몬 즉위」를 다룹니다.', '["나이 든 왕모 밧세바가 깊은 청색 너울과 단정한 왕궁 옷차림으로 매우 늙고 쇠약한 다윗 왕의 침상 곁에 다가와, 아도니야가 스스로 왕위에 오르려 잔치를 벌이는 위험을 손짓으로 알린다. 다윗은 약해 보이지만 정신을 차려 듣는다, 그 말의 뜻을 보여 주는 글자 없는 말풍선 안에는 나누어진 떡과 한 식탁에서 서로를 돌보는 사람들이 보이는 장면이 작은 그림처럼 보인다", "기혼 샘 근처, 젊은 솔로몬이 다윗 왕의 노새를 타고 왕으로 세워지며 사독과 나단이 기름을 붓고, 백성들이 양각 나팔 소리와 함께 크게 환호하는 장면", "아도니야가 두려워 제단 뿔을 붙잡고 떨고 있고, 젊은 솔로몬은 왕좌 앞에서 아도니야를 해치지 않겠다고 단호하지만 절제 있게 말하는 장면. 폭력이나 피는 보이지 않는다"]'::jsonb, '["밧세바가 다윗에게 다가와 아도니야의 소식을 전하고 솔로몬을 왕으로 세울 것을 요청한다", "기혼 샘 근처, 솔로몬이 다윗 왕의 노새를 타고 왕으로 세워지며 사독과 나단이 기름을 붓다", "아도니야가 솔로몬 앞에서 떨고 솔로몬은 해치지 않겠다고 이야기한다"]'::jsonb, '[["david", "bathsheba"], ["solomon"], ["solomon"]]'::jsonb, ARRAY['solomon', 'david', 'bathsheba']::text[], '[{"book": "왕상", "from": "1:1", "to": "1:53"}]'::jsonb, -970, -970, 'approx', 23, 'monarchy_solomon_temple_fall', '솔로몬 시대: 지혜와 성전, 타락', 3, 'lm_mon_jerusalem', 'published'),
    ('era_exodus', '여호수아 위임: 강하고 담대하라', '모세는 마지막 때에 여호수아를 다음 지도자로 세우고, 백성에게 말씀을 끝까지 붙들라고 당부한다.', '출애굽과 광야 여정은 이스라엘이 애굽을 떠나 시내산과 광야를 지나는 시기입니다. 이 이야기는 「여호수아 위임」을 다룹니다.', '["120세의 흰 머리 모세가 여호수아와 백성들이 있는 자리에서 여호수아를 다음 리더로 세우고, 여호수아는 겸손하지만 담대하게 선다", "120세의 모세와 여호수아가 회막에서 하나님의 거룩한 구름기둥 앞에 엎드려 말씀을 듣는다. 구름기둥은 하늘에서 회막 입구까지 내려온 크고 밝은 수직 기둥이며, 안쪽에서 순백색과 금빛 빛이 흘러나와 회막과 두 사람을 환하게 비춘다. 사람 형상이나 얼굴은 없고, 빛나는 구름 자체가 하나님의 임재처럼 느껴진다", "120세의 흰 머리 모세가 이스라엘 백성들에게 하나님을 끝까지 믿으라고 마지막으로 당부하고, 백성들은 조용히 귀 기울인다"]'::jsonb, '["120세 모세가 여호수아와 백성들이 있는 자리에서 여호수아를 다음 리더로 세운다", "모세와 여호수아가 회막에서 하나님의 거룩한 구름기둥 앞에 엎드려 말씀을 듣는다", "모세가 이스라엘 백성들에게 하나님을 끝까지 믿으라고 마지막으로 당부한다"]'::jsonb, '[["moses", "joshua"], ["god", "moses", "joshua"], ["moses", "joshua"]]'::jsonb, ARRAY['moses', 'god', 'joshua']::text[], '[{"book": "신", "from": "31:1", "to": "31:29"}]'::jsonb, -1406, -1406, 'approx', 23, 'exodus_wilderness_covenant', '광야의 삶과 언약 훈련', 2, 'lm_exo_plains_moab', 'published'),
    ('era_divided_kingdom', '예후의 기름부음: 아합 집의 심판', '예후는 기름부음을 받고 아합 집에 임한 하나님의 심판을 실행한다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「예후의 기름부음」을 다룹니다.', '["엘리사가 선지자의 제자들 가운데 한 사람을 불러 길르앗 라못으로 가서 예후에게 기름을 부으라고 말하고, 큰 글자 없는 말풍선 안에는 기름병과 예후가 왕으로 세워지는 상징 그림이 담겨 있다", "북이스라엘의 장군 예후가 군사 복장을 하고 길르앗 라못에서 군대 장관들과 함께 앉아 있는데, 엘리사의 제자가 도착해 예후의 머리에 기름을 붓는 장면", "북이스라엘 왕 요람과 유다 왕 아하시야가 각각 전차를 타고 도망가고, 예후가 전차 위에서 활을 겨누어 두 왕을 쓰러뜨리는 장면. 화살과 전차의 긴장감은 보이지만 피와 상처와 시신의 세부 묘사는 보이지 않는다", "이스르엘 성에서 이세벨이 창가에 서 있고, 예후의 명령으로 그녀가 성 아래로 떨어지는 순간을 먼 거리에서 보여준다. 아래에는 개들이 그 장면을 바라보고 있으며, 피와 시신의 세부 묘사는 보이지 않는다"]'::jsonb, '["엘리사가 한 사람을 불러 길르앗 라못으로 가서 예후에게 기름을 부으라고 말한다", "예후는 기름부음을 받고 아합 집에 임한 하나님의 심판을 실행한다", "북이스라엘 왕 요람과 유다 왕 아하시야가 각각 전차를 타고 도망간다", "이세벨이 창문에서 떨어지고 아래는 개들이 기다리고 있다"]'::jsonb, '[["elisha"], ["jehu"], ["jehu", "joram_israel", "ahaziah_judah"], ["jehu", "jezebel"]]'::jsonb, ARRAY['elisha', 'jehu', 'joram_israel', 'ahaziah_judah', 'jezebel']::text[], '[{"book": "왕하", "from": "9:1", "to": "9:37"}]'::jsonb, -841, -841, 'approx', 23, 'divided_elisha_jehu_judgment', '엘리사와 예후: 표징과 심판', 3, 'lm_div_jezreel_jehu', 'published'),
    ('era_nt_public_ministry', '이방 땅에서 베푸신 치유', '예수님은 가나안 여인의 딸을 고치시고, 데가볼리와 갈릴리 주변의 여러 병자를 치유하신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「이방 땅에서 베푸신 치유」를 다룹니다.', '["예수님이 여인의 믿음을 칭찬하시자 여인은 눈물 어린 안도로 고개를 들고, 멀리 집 안의 딸은 침상에서 평온을 되찾는다", "데가볼리에서 친구들이 귀먹고 말 더듬는 사람을 부축해 예수님께 데려오고, 예수님은 그를 따로 세워 귀와 입을 고쳐 주려는 다정한 손짓을 하신다"]'::jsonb, '["예수님이 여인의 믿음을 칭찬하시자 여인은 눈물 어린 안도로 고개를 든다", "데가볼리에서 친구들이 귀먹고 말 더듬는 사람을 부축해 예수님께 데려온다"]'::jsonb, '[["jesus"], ["jesus"]]'::jsonb, ARRAY['jesus']::text[], '[{"book": "마", "from": "15:21", "to": "15:31"}, {"book": "막", "from": "7:24", "to": "7:37"}]'::jsonb, 29, 29, 'approx', 23, 'galilee_ministry', '갈릴리 사역', 2, 'lm_nt_pm_tyre', 'published'),
    ('era_nt_apostolic', '2차 전도 여행: 데살로니가 사역', '바울은 데살로니가 회당에서 그리스도의 고난과 부활을 설명하고, 반대자들의 소동 속에서도 믿는 사람들이 생긴다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「차 전도 여행」을 다룹니다.', '["바울이 세 안식일 동안 회당에서 성경을 강론하고 실라와 디모데는 진지한 얼굴로 곁에 선다", "시기한 유대인들이 불량한 사람들을 모아 성을 소동하게 하고 야손의 집 앞은 긴장으로 가득하다", "야손과 형제들이 끌려가 보석을 내고 풀려나며 두려움 속에서도 믿음을 지키려는 얼굴을 한다"]'::jsonb, '["바울이 세 안식일 동안 회당에서 성경을 강론한다", "시기한 유대인들이 불량한 사람들을 모아 성을 소동하게 하고 야손의 집 앞은 긴장으로 가득하다", "야손과 형제들이 끌려가 보석을 내고 풀려난다"]'::jsonb, '[["paul", "silas", "timothy"], ["paul", "silas"], ["paul", "silas"]]'::jsonb, ARRAY['paul', 'silas', 'timothy']::text[], '[{"book": "행", "from": "17:1", "to": "17:9"}]'::jsonb, 50, 50, 'approx', 24, 'paul_second_journey', '바울의 2차 전도 여행', 3, 'lm_nt_ap_thessalonica', 'published'),
    ('era_monarchy', '다윗의 마지막 명령: 나라를 굳게 하다', '다윗은 마지막으로 솔로몬에게 하나님을 따르라고 당부하고, 솔로몬은 흔들리는 왕권을 바로 세운다.', '통일왕국 시대는 사울, 다윗, 솔로몬이 이스라엘 전체를 다스리던 시기입니다. 이 이야기는 「다윗의 마지막 명령」을 다룹니다.', '["늙은 다윗 왕이 침상에 누워 젊은 솔로몬에게 마지막으로 당부하고, 큰 글자 없는 말풍선 안에는 솔로몬이 하나님만 따르고 율법의 길을 지키면 왕국이 견고해지는 상징 그림이 담겨 있다. 솔로몬은 무겁게 고개를 끄덕인다", "나이 든 왕모 밧세바가 솔로몬 왕에게 아도니야의 요청을 전하러 오고, 장면 뒤쪽의 작은 그림 구역에는 아도니야와 아비삭이 함께 서 있는 상징 모습만 보인다. 솔로몬은 왕좌에서 화가 난 표정으로 단호하게 거절한다", "솔로몬이 군사 지휘관에게 명령을 내리고, 먼 배경에서는 아도니야가 칼의 심판받는 장면이 처리된다. 직접적인 칼질, 피, 상처, 시신은 보이지 않고, 솔로몬의 단호한 왕권 확립이 강조된다", "솔로몬이 브니야에게 명령을 내려 시므이가 칼의 심판을 받는다. 직접적인 칼질, 피, 상처, 시신은 보이지 않고, 솔로몬의 단호한 왕권 확립이 강조된다"]'::jsonb, '["다윗 왕이 침상에 누워 솔로몬에게 마지막으로 당부한다", "왕모 밧세바가 솔로몬 왕에게 아도니야의 요청(수넴 여인 아비삭을 달라)을 전하러 온다", "솔로몬이 군사 지휘관에게 명령을 내려 아도니야가 칼의 심판받는다", "솔로몬이 군사 지휘관에게 명령을 내려 시므이가 칼의 심판을 받는다"]'::jsonb, '[["david", "solomon"], ["solomon", "bathsheba"], ["solomon"], ["solomon"]]'::jsonb, ARRAY['david', 'solomon', 'bathsheba']::text[], '[{"book": "왕상", "from": "2:1", "to": "2:46"}]'::jsonb, -970, -970, 'approx', 24, 'monarchy_solomon_temple_fall', '솔로몬 시대: 지혜와 성전, 타락', 3, 'lm_mon_jerusalem', 'published'),
    ('era_nt_post_apostolic', '말세의 어려움과 바울의 마지막 부탁', '바울은 마지막 감옥에서 디모데에게 어려운 때를 견디고 말씀을 전하라는 마지막 부탁을 남긴다.', '디모데후서는 바울이 마지막 투옥 중, 동역자 디모데에게 고난 속에서도 말씀과 사명을 지키라고 쓴 편지입니다. 이 이야기는 「말세의 어려움과 바울의 마지막 부탁」을 다룹니다.', '["바울이 디모데에게 쓴 편지에는 사람들이 돈을 좋아하고 무모하고 자만하고 폭력적이지만 디모데는 그들과 떨어져서 하나님만을 섬기는 모습이 담겨있다", "바울이 디모데에게 쓴 편지에는 디모데가 악을 사랑하는 자들에게 담대하고 단호하게 예수를 전하는 장면"]'::jsonb, '["바울이 마지막 때에는 사람들이 돈을 좋아하고 무모하고 자만하고 폭력적일 것임을 말한다", "바울이 디모데에게 담대하고 단호하게 예수를 전할 것을 말한다"]'::jsonb, '[["paul", "timothy"], ["paul", "timothy"]]'::jsonb, ARRAY['paul', 'timothy']::text[], '[{"book": "딤후", "from": "3:1", "to": "4:8"}]'::jsonb, 67, 67, 'approx', 24, 'next_generation_suffering_church', '다음 세대와 고난받는 교회', 4, 'lm_nt_post_rome', 'published'),
    ('era_exodus', '모세의 마지막: 느보산과 축복', '모세는 느보산에서 약속의 땅을 바라보고 지파들을 축복한 뒤, 하나님 앞에서 사명을 마친다.', '출애굽과 광야 여정은 이스라엘이 애굽을 떠나 시내산과 광야를 지나는 시기입니다. 이 이야기는 「모세의 마지막」을 다룹니다.', '["느보산 정상에서 120세의 모세가 가나안 땅을 바라보며 하나님의 말씀을 듣고, 멀리 요단과 약속의 땅이 펼쳐져 있다", "120세의 흰 머리 모세가 기력이 쇠하지 않은 채로 여호수아에게 안수하고, 여호수아는 겸손히 고개를 숙인다", "모압 땅 벧브올 맞은편 골짜기, 모세의 무덤은 보이지 않는다. 앞쪽에는 모세가 쓰던 지팡이와 겉옷이 빈자리처럼 놓여 있고, 여호수아와 장로들과 백성들이 그 앞에 무릎 꿇고 얼굴을 가리며 통곡한다. 멀리 느보산 능선에는 모세가 마지막으로 서 있던 듯한 따뜻한 빛만 남아 있어, 백성이 모세의 죽음을 애도하는 장면임이 분명하다"]'::jsonb, '["느보산 정상에서 모세가 가나안 땅을 바라보며 하나님의 말씀을 듣는다", "모세가 기력이 쇠하지 않은 채로 여호수아에게 안수한다", "모압 땅 벧브올 맞은편 골짜기, 앞쪽에는 모세가 쓰던 지팡이와 겉옷이 빈자리처럼 놓여 있다"]'::jsonb, '[["god", "moses"], ["moses", "joshua"], ["joshua"]]'::jsonb, ARRAY['moses', 'god', 'joshua']::text[], '[{"book": "신", "from": "34:1", "to": "34:12"}]'::jsonb, -1406, -1406, 'approx', 24, 'exodus_wilderness_covenant', '광야의 삶과 언약 훈련', 2, 'lm_exo_mt_nebo', 'published'),
    ('era_divided_kingdom', '예후의 열심과 한계: 바알 신전과 금송아지', '예후는 바알 숭배를 무너뜨리지만, 여로보암의 금송아지 죄에서는 떠나지 못한다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「예후의 열심과 한계」를 다룹니다.', '["예후가 바알을 섬기는 사람들을 모두 큰 바알 신전으로 불러 모으고, 수많은 사람들이 바알에게 절하고 제사하려고 신전 안으로 들어오는 장면. 신전에는 큰 바알 우상이 보이지만 글자는 보이지 않는다", "예후가 호위병과 장교들에게 명령하자 그들이 바알 신전 안에 불을 질러 성전 안의 사람들을 심판하고, 바알 신전과 목상들이 불타 무너지는 장면. 폭력의 결과는 멀리서 절제해 보이고 피와 시신의 세부 묘사는 보이지 않는다", "예후가 바알을 없앤 뒤에도 벧엘과 단의 금송아지 앞에서 섬기는 장면. 예후는 왕복을 입었지만 마음이 완전히 하나님께 돌아오지 못한 듯 어두운 표정이고, 금송아지 우상이 뚜렷하게 보인다", "세월이 지나 예후가 사마리아에서 죽고, 그의 아들 여호아하스가 북이스라엘의 새 왕이 되는 장면. 예후의 침상 주변에는 신하들이 조용히 애도하고, 여호아하스는 왕으로 세워진다"]'::jsonb, '["예후가 바알을 섬기는 사람들을 모두 큰 바알 신전으로 불러 모은다", "예후가 그들이 제사 지낼 때 바알 신전 안에 불을 질러 성전 안의 사람들을 심판한다", "예후가 바알을 없앤 뒤에도 벧엘과 단의 금송아지까지 모두 제거하지는 못했다", "세월이 지나 예후가 사마리아에서 죽고, 그의 아들 여호아하스가 북이스라엘의 새 왕이 된다"]'::jsonb, '[["jehu"], ["jehu"], ["jehu"], ["jehu", "jehoahaz_israel"]]'::jsonb, ARRAY['jehu', 'jehoahaz_israel']::text[], '[{"book": "왕하", "from": "10:1", "to": "10:36"}]'::jsonb, -841, -814, 'approx', 24, 'divided_elisha_jehu_judgment', '엘리사와 예후: 표징과 심판', 3, 'lm_div_samaria_baal_temple', 'published'),
    ('era_patriarch', '요셉의 꿈: 형제들의 시기', '요셉의 꿈과 편애가 형제들의 마음을 뒤틀리게 한다.', '족장 시대는 아브라함, 이삭, 야곱, 요셉의 가족 이야기가 중심입니다. 이 이야기는 「요셉의 꿈」을 다룹니다.', '["17세 안팎의 어린 요셉이 채색옷을 입고 형들 사이를 지나가자, 르우벤과 유다를 비롯한 형들은 질투와 거리감이 섞인 얼굴로 서로 눈짓한다", "17세 안팎의 어린 요셉이 형들에게 곡식단 꿈을 이야기하고, 말풍선 안에는 중앙 곡식단에게 주변 곡식단들이 절하는 그림이 글자 없이 보인다. 형들의 표정은 차갑게 굳는다", "늙어서 머리가 하얀 야곱이 17세 안팎의 어린 요셉을 꾸짖지만, 말풍선 안의 해와 달과 별들이 요셉에게 절하는 그림을 보며 마음속에 그 말을 담아둔다"]'::jsonb, '["채색옷을 입을 요셉을 형제들이 시기한다", "17세 안팎의 어린 요셉이 형들에게 곡식단 꿈을 이야기한다", "야곱이 17세 안팎의 어린 요셉을 꾸짖지만 이야기를 마음에 담아둔다"]'::jsonb, '[["joseph", "reuben", "judah"], ["joseph", "reuben", "simeon", "levi", "judah"], ["jacob", "joseph"]]'::jsonb, ARRAY['joseph', 'jacob', 'reuben', 'simeon', 'levi', 'judah', 'naphtali', 'gad', 'asher', 'issachar', 'zebulun']::text[], '[{"book": "창", "from": "37:1", "to": "37:11"}]'::jsonb, -1915, -1915, 'approx', 24, 'patriarch_joseph_egypt', '요셉: 애굽으로 이어진 구원', 3, 'lm_pat_hebron', 'published'),
    ('era_nt_public_ministry', '표적 요구와 누룩 경고', '지도자들은 하늘의 표적을 요구하지만 예수님은 그들의 누룩을 경계하라고 하시며 벳새다의 맹인을 고치신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「표적 요구와 누룩 경고」를 다룹니다.', '["바리새인과 사두개인들이 예수님께 하늘로부터 오는 표적을 요구한다", "배 안에서 제자들이 빈 빵 바구니를 보며 걱정하고, 예수님은 이전에 오병이어 사건을 떠올리게 하신다", "벳새다에서 예수님이 맹인의 눈을 만져 점차 밝히 보게 하신다"]'::jsonb, '["바리새인과 사두개인들이 예수님께 하늘로부터 오는 표적을 요구한다", "배 안에서 제자들이 빈 빵 바구니를 보며 걱정하고, 예수님은 오병이어 사건을 말씀하신다", "벳새다에서 예수님이 맹인의 눈을 만져 점차 밝히 보게 하신다"]'::jsonb, '[["jesus"], ["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["jesus"]]'::jsonb, ARRAY['jesus', 'peter', 'andrew', 'james_zebedee', 'john', 'philip', 'bartholomew', 'matthew', 'thomas', 'james_alphaeus', 'thaddaeus', 'simon_zealot', 'judas']::text[], '[{"book": "마", "from": "16:1", "to": "16:12"}, {"book": "막", "from": "8:11", "to": "8:26"}]'::jsonb, 29, 29, 'approx', 24, 'galilee_ministry', '갈릴리 사역', 2, 'lm_nt_pm_bethsaida', 'published'),
    ('era_nt_apostolic', '2차 전도 여행: 베뢰아 사람들', '베뢰아 사람들은 간절한 마음으로 말씀을 받고 날마다 성경을 살피며, 소동이 일어나자 바울은 아덴으로 떠난다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「차 전도 여행」을 다룹니다.', '["밤에 바울과 실라가 베뢰아로 보내지고 두 사람은 지친 얼굴이지만 사명을 붙들고 담대한 표정으로 회당으로 들어간다", "베뢰아 사람들이 간절한 얼굴로 말씀을 받고 두루마리를 펼쳐 날마다 성경을 상고한다", "데살로니가에서 온 사람들이 무리를 선동하자 성도들의 얼굴에 긴장이 번진다", "형제들이 바울을 바다까지 보내고 바울은 실라와 디모데를 베뢰아에서 데려오라고 형제에게 지시한다."]'::jsonb, '["밤에 바울과 실라가 베뢰아로 보내지고 둘은 회당으로 들어간다", "베뢰아 사람들이 간절한 얼굴로 말씀을 받고 두루마리를 펼쳐 날마다 성경을 상고한다", "데살로니가에서 온 사람들이 무리를 선동하고 성도들이 긴장한다", "형제들이 바울을 바다까지 보내고 바울은 실라와 디모데를 베뢰아에서 데려오라고 형제에게 지시한다"]'::jsonb, '[["paul", "silas"], ["paul", "silas"], ["paul", "silas"], ["paul", "silas", "timothy"]]'::jsonb, ARRAY['paul', 'silas', 'timothy']::text[], '[{"book": "행", "from": "17:10", "to": "17:15"}]'::jsonb, 50, 50, 'approx', 25, 'paul_second_journey', '바울의 2차 전도 여행', 3, 'lm_nt_ap_berea', 'published'),
    ('era_exodus', '라합과 두 정탐꾼: 붉은 줄', '여리고 성 안에서 라합은 두 정탐꾼을 숨기고, 붉은 줄로 구원의 표를 매단다.', '출애굽과 광야 여정은 이스라엘이 애굽을 떠나 시내산과 광야를 지나는 시기입니다. 이 이야기는 「라합과 두 정탐꾼」을 다룹니다.', '["여호수아가 싯딤 진영에서 두 정탐꾼을 여리고로 보내며, 두 사람은 밤길 여행복과 작은 짐을 챙겨 성읍 쪽을 조심스럽게 바라본다", "여리고 성 안 라합의 집 안에서 라합이 두 정탐꾼을 맞아 조용히 숨겨 주며, 그녀는 모래색 머릿수건과 청록색 겉옷을 입고 긴장하지만 담대한 표정이다. 붉은 줄은 아직 보이지 않는다", "라합이 집 지붕 위 삼대 더미 속에 두 정탐꾼을 숨기고, 여리고 군사들에게 성문 밖 방향을 손짓하며 침착하게 말하는 자세를 보인다, 그 말의 뜻을 보여 주는 글자 없는 말풍선 안에는 말을 들은 사람들이 어두운 길에서 밝은 길로 돌아서는 장면이 작은 그림처럼 보인다", "라합이 여리고 성벽 집 창문에 붉은 줄을 매달고, 가족들을 집 안으로 모으기 위해 급히 손짓한다. 아래로 성벽과 길이 보인다"]'::jsonb, '["여호수아가 싯딤 진영에서 두 정탐꾼을 여리고로 보낸다", "여리고 성 안 라합의 집 안에서 라합이 두 정탐꾼을 맞아 조용히 숨겨 준다", "라합이 집 지붕 위 삼대 더미 속에 두 정탐꾼을 숨긴다", "라합이 여리고 성벽 집 창문에 붉은 줄을 매단다"]'::jsonb, '[["joshua"], ["rahab"], ["rahab"], ["rahab"]]'::jsonb, ARRAY['god', 'joshua', 'rahab']::text[], '[{"book": "수", "from": "2:1", "to": "2:24"}]'::jsonb, -1406, -1406, 'approx', 25, 'exodus_canaan_joshua', '가나안 입성과 여호수아', 3, 'lm_jud_jericho', 'published'),
    ('era_nt_public_ministry', '베드로의 신앙고백과 첫 수난 예고', '베드로가 예수님을 그리스도로 고백하고, 예수님은 고난과 죽음과 부활을 처음으로 분명히 예고하신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「베드로의 신앙고백과 첫 수난 예고」를 다룹니다.', '["가이사랴 빌립보 길에서 예수님이 제자들에게 사람들이 자신을 누구라 하는지 물으신다", "베드로가 예수님은 그리스도시며 살아 계신 하나님의 아들이라고 고백한다. 베드로의 말풍선에는 하나님과 빛이 예수님에게 있다", "예수님이 고난과 죽음과 부활을 예고하시자 제자들은 길가에서 서로 굳은 얼굴로 물러서고, 예수님은 예루살렘 쪽을 향해 결연히 서신다", "예수님이 자신의 죽음을 부인하는 베드로를 향해 호통치신다. 베드로는 놀란 얼굴이고 주변의 제자들도 함께 놀란다."]'::jsonb, '["가이사랴 빌립보 길에서 예수님이 제자들에게 사람들이 자신을 누구라 하는지 물으신다", "베드로가 예수님은 그리스도시며 살아 계신 하나님의 아들이라고 고백한다", "예수님이 고난과 죽음과 부활을 예고하시자 제자들은 길가에서 서로 굳은 얼굴로 물러선다", "예수님이 자신의 죽음을 부인하는 베드로를 향해 호통치신다"]'::jsonb, '[["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"]]'::jsonb, ARRAY['jesus', 'peter', 'andrew', 'james_zebedee', 'john', 'philip', 'bartholomew', 'matthew', 'thomas', 'james_alphaeus', 'thaddaeus', 'simon_zealot', 'judas']::text[], '[{"book": "마", "from": "16:13", "to": "16:28"}, {"book": "막", "from": "8:27", "to": "9:1"}, {"book": "눅", "from": "9:18", "to": "9:27"}]'::jsonb, 29, 29, 'approx', 25, 'journey_teaching_to_jerusalem', '길 위의 가르침과 예루살렘으로', 3, 'lm_nt_pm_caesarea_philippi', 'published'),
    ('era_nt_post_apostolic', '산 소망과 거룩한 나그네', '베드로는 흩어진 성도들에게 산 소망과 거룩한 나그네의 삶을 권면한다.', '베드로전서는 베드로가 소아시아 여러 지역에서 고난과 사회적 압박을 겪던 성도들에게 소망을 전한 편지입니다. 이 이야기는 「산 소망과 거룩한 나그네」를 다룹니다.', '["60대의 베드로가 성도들에게 권면하는 편지. 내용은 은과 금이 썩어져있고 성도가 빛나는 예수님을 믿음으로 바라보고 있는 장면", "60대의 베드로가 성도들에게 권면하는 편지. 내용은 성도들이 제사장 복을 입고 빛의 하나님을 바라보는 장면"]'::jsonb, '["베드로는 은과 금보다 더 귀한 예수 그리스도께 구원 받는 삶에 대해 이야기한다", "베드로는 순종하며 은혜를 끝까지 바라 보는 삶을 권면한다"]'::jsonb, '[["peter"], ["peter"]]'::jsonb, ARRAY['peter']::text[], '[{"book": "벧전", "from": "1:1", "to": "2:17"}]'::jsonb, 64, 64, 'approx', 25, 'next_generation_suffering_church', '다음 세대와 고난받는 교회', 4, 'lm_nt_post_asia_minor_network', 'published'),
    ('era_monarchy', '솔로몬의 지혜: 참 어머니를 가리다', '솔로몬은 하나님께 지혜를 구하고, 어려운 재판으로 그 지혜를 온 이스라엘 앞에 드러낸다.', '통일왕국 시대는 사울, 다윗, 솔로몬이 이스라엘 전체를 다스리던 시기입니다. 이 이야기는 「솔로몬의 지혜」를 다룹니다.', '["밤의 꿈속, 솔로몬이 하나님 앞에 겸손히 무릎 꿇고 백성을 재판할 지혜를 구하며, 사람 형상 없는 하나님의 밝은 빛은 솔로몬의 구함을 기뻐하는 듯 따뜻하게 비추는 장면", "예루살렘 왕궁 재판 자리, 서로 다른 옷차림의 두 여자가 같은 아기를 두고 서로 자기 아이라고 주장하며 솔로몬 앞에 서 있고, 솔로몬은 집중해서 듣는 장면. 아기는 포대기에 싸여 안전하게 보인다", "솔로몬이 두 여자와 포대기에 싸인 아기를 앞에 두고 신하에게 칼을 가져오라고 단호하게 명령하자, 한 여자는 아기를 살려 달라는 듯 놀라 울고 다른 여자는 차갑게 굳어 있는 장면. 칼은 신하 손에만 보이고 아기에게 닿지 않는다", "솔로몬이 울며 아기를 살려 달라 한 여자가 참 어머니라고 판결하고 아기를 그 여자에게 돌려주며, 옆의 다른 여자는 속마음이 들켜 놀라 굳어 있는 장면. 궁정 사람들은 솔로몬의 지혜에 경외하는 표정이다"]'::jsonb, '["밤의 꿈속, 솔로몬이 하나님 앞에 겸손히 무릎 꿇고 지혜를 구한다", "두 여자가 같은 아기를 두고 자기 아이라고 주장하며 솔로몬 앞에 선다", "솔로몬은 칼을 가져오라고 이야기하고, 한 여인이 격하게 놀란다", "솔로몬이 울며 아기를 살려 달라 한 여자가 참 어머니라고 판결하고 아기를 그 여자에게 돌려준다"]'::jsonb, '[["solomon", "god"], ["solomon"], ["solomon"], ["solomon"]]'::jsonb, ARRAY['solomon', 'god']::text[], '[{"book": "왕상", "from": "3:1", "to": "3:28"}]'::jsonb, -967, -967, 'approx', 25, 'monarchy_solomon_temple_fall', '솔로몬 시대: 지혜와 성전, 타락', 3, 'lm_mon_jerusalem', 'published'),
    ('era_divided_kingdom', '아달랴와 요아스: 숨겨진 왕', '아달랴의 폭력 속에서도 요아스는 성전에 숨겨지고, 여호야다는 언약을 세워 다윗 왕조를 다시 드러낸다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「아달랴와 요아스」를 다룹니다.', '["예루살렘 왕궁이 공포에 휩싸이고, 아달랴가 왕가 사람들을 없애라고 명령해 병사들이 왕궁 안을 장악하는 장면. 피와 시신은 보이지 않으며, 한쪽 깊은 성전 방에는 아기 요아스가 유모와 아하시야의 누이 여호세바와 함께 조용히 숨어있다", "왕궁 말 다니는 길에서 군대가 아달랴를 붙잡아 끌어내고 심판하는 장면. 아달랴는 옷을 찢고 절망하지만, 피와 상처와 시신의 세부 묘사는 보이지 않는다", "여호야다 제사장이 왕과 백성 앞에서 여호와와 언약을 맺게 하고, 백성들이 바알 신전으로 몰려가 우상과 제단을 무너뜨리는 장면. 폭력의 세부 묘사는 보이지 않고 바알 신전 파괴가 중심이다", "일곱 살 유다 왕 요아스가 왕관과 율법책을 받고 왕으로 세워지며, 여호야다 제사장과 백성들이 박수치고 나팔을 불며 기뻐하는 장면"]'::jsonb, '["아달랴가 왕가 사람들을 없애라고 지시하고 아기 요아스는 유모에 의해 숨겨진다", "왕궁 말 다니는 길에서 군대가 아달랴를 붙잡아 끌어내고 심판한다", "여호야다 제사장이 왕과 백성 앞에서 여호와와 언약을 맺게 한다", "일곱 살 유다 왕 요아스가 왕관과 율법책을 받고 왕으로 세워진다"]'::jsonb, '[["joash_judah", "athaliah"], ["athaliah"], ["jehoiada"], ["joash_judah", "jehoiada"]]'::jsonb, ARRAY['athaliah', 'joash_judah', 'jehoiada']::text[], '[{"book": "왕하", "from": "11:1", "to": "11:20"}]'::jsonb, -841, -835, 'approx', 25, 'divided_two_kingdoms_north_fall', '두 왕국의 흔들림과 북이스라엘의 몰락', 4, 'lm_div_jerusalem_athaliah_joash', 'published'),
    ('era_patriarch', '요셉이 팔리다: 구덩이와 은', '시기는 요셉을 구덩이에 던지고 끝내 종으로 팔아넘긴다.', '족장 시대는 아브라함, 이삭, 야곱, 요셉의 가족 이야기가 중심입니다. 이 이야기는 「요셉이 팔리다」를 다룹니다.', '["형들이 요셉의 채색옷을 빼앗고 그를 물 없는 구덩이로 밀어 넣으며, 요셉은 두려움으로 손을 뻗는다. 피와 직접 폭력은 보이지 않는다", "형들의 손에 은 조각이 쥐어지고, 멀리서는 17세 안팎의 어린 요셉이 상인들의 낙타 행렬 쪽으로 끌려가며 뒤돌아본다. 르우벤은 옷을 찢으며 슬퍼한다", "붉게 물든 요셉의 채색옷을 형들이 야곱에게 전달하고, 늙은 야곱은 슬퍼 통곡한다"]'::jsonb, '["형들이 요셉의 채색옷을 빼앗고 요셉을 구덩이로 밀어 넣는다", "형들은 은조각에 요셉을 상인들에게 팔아 넘긴다", "붉게 물든 요셉의 채색옷을 전달받은 야곱이 슬퍼한다"]'::jsonb, '[["joseph"], ["joseph", "judah", "reuben"], ["jacob"]]'::jsonb, ARRAY['joseph', 'judah', 'jacob', 'reuben']::text[], '[{"book": "창", "from": "37:12", "to": "37:36"}]'::jsonb, -1915, -1915, 'approx', 25, 'patriarch_joseph_egypt', '요셉: 애굽으로 이어진 구원', 3, 'lm_pat_dothan', 'published'),
    ('era_nt_apostolic', '2차 전도 여행: 아덴 아레오바고 설교', '우상으로 가득한 아덴에서 바울은 아레오바고에 서서 알지 못하는 하나님과 부활을 전한다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「차 전도 여행」을 다룹니다.', '["바울이 우상으로 가득한 아덴 거리를 보고 마음이 격분한 얼굴로 회당과 시장에서 변론한다", "철학자들이 호기심과 비웃음이 섞인 표정으로 바울을 아레오바고로 데려간다", "바울이 알지 못하는 신에게 절하는 자들을 책망하며 죽음에서 부활하신 예수를 담대하게 전한다", "부활을 듣고 어떤 사람은 조롱하지만 몇 사람은 깊이 생각하는 얼굴로 바울을 가까이한다"]'::jsonb, '["바울이 우상으로 가득한 아덴 거리를 보고 마음이 격분한 얼굴로 회당과 시장에서 변론한다", "철학자들이 호기심과 비웃음이 섞인 표정으로 바울을 아레오바고로 데려간다", "바울이 알지 못하는 신에게 절하는 자들을 책망하며 죽음에서 부활하신 예수를 담대하게 전한다", "부활을 듣고 어떤 사람은 조롱하지만 몇 사람은 깊이 생각한다"]'::jsonb, '[["paul"], ["paul"], ["paul"], ["paul"]]'::jsonb, ARRAY['paul']::text[], '[{"book": "행", "from": "17:16", "to": "17:34"}]'::jsonb, 51, 51, 'approx', 26, 'paul_second_journey', '바울의 2차 전도 여행', 3, 'lm_nt_ap_athens', 'published'),
    ('era_nt_post_apostolic', '거짓 선생과 주의 날', '베드로는 거짓 선생을 경계하고 주의 날을 기다리며 거룩하게 살라고 권면한다.', '베드로후서는 베드로가 거짓 교사와 재림 조롱에 흔들릴 수 있던 성도들에게 사도적 가르침을 기억시키려 쓴 편지입니다. 이 이야기는 「거짓 선생과 주의 날」을 다룹니다.', '["60대의 베드로가 성도들에게 보내는 편지. 내용은 악한 무리가 하나님을 모독하다가 멸망당하는 모습", "60대의 베드로가 성도들에게 보내는 편지. 내용은 탐욕스러운 교사가 돈주머니와 화려한 옷을 자랑하지만 어둠이 그들 위에 가득한 모습", "60대의 베드로가 성도들에게 보내는 편지. 내용은 하늘에서 큰 불이 내려와 모두 불사르며 신실한 성도들은 보호받는 모습"]'::jsonb, '["베드로가 악한 무리가 하나님께 멸망당할 것을 말한다", "베드로가 돈주머니와 화려한 옷을입은 자들의 어두움 대해 말한다", "재림의 날 큰 불이 내려와 모두 불사르며 신실한 성도들은 보호받을 것임을 말한다"]'::jsonb, '[["peter"], ["peter"], ["peter"]]'::jsonb, ARRAY['peter']::text[], '[{"book": "벧후", "from": "2:9", "to": "3:18"}]'::jsonb, 66, 66, 'approx', 26, 'next_generation_suffering_church', '다음 세대와 고난받는 교회', 4, 'lm_nt_post_asia_minor_network', 'published'),
    ('era_nt_public_ministry', '변화산 사건', '예수님의 영광이 산 위에서 드러나고 모세와 엘리야가 함께 나타나며 제자들은 하늘의 음성을 듣는다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「변화산 사건」을 다룹니다.', '["예수님이 베드로와 야고보와 요한을 데리고 높은 산에 오르신다", "예수님의 얼굴과 옷이 빛나고 모세와 엘리야가 함께 나타난다. 제자들은 이를 보며 놀란다", "산에서 내려오며 즐거워하는 제자들에게 예수님이 본 것을 말하지 말라 하신다. 예수님을 손가락을 입에 대며 말하지 말라는 제스처를 취하신다"]'::jsonb, '["예수님이 베드로와 야고보와 요한을 데리고 높은 산에 오르신다", "예수님의 얼굴과 옷이 빛나고 모세와 엘리야가 함께 제자들 앞에 나타난다", "산에서 내려오며 즐거워하는 제자들에게 예수님이 본 것을 말하지 말라 하신다"]'::jsonb, '[["jesus", "peter", "james_zebedee", "john"], ["jesus", "moses", "elijah"], ["jesus", "peter", "james_zebedee", "john"]]'::jsonb, ARRAY['jesus', 'peter', 'james_zebedee', 'john', 'moses', 'elijah']::text[], '[{"book": "마", "from": "17:1", "to": "17:13"}, {"book": "막", "from": "9:2", "to": "9:13"}, {"book": "눅", "from": "9:28", "to": "9:36"}]'::jsonb, 29, 29, 'approx', 26, 'journey_teaching_to_jerusalem', '길 위의 가르침과 예루살렘으로', 3, 'lm_nt_pm_mt_transfiguration', 'published'),
    ('era_patriarch', '보디발의 집: 성실과 누명', '요셉은 유혹을 거절하지만 누명을 쓰고 감옥으로 내려간다.', '족장 시대는 아브라함, 이삭, 야곱, 요셉의 가족 이야기가 중심입니다. 이 이야기는 「보디발의 집」을 다룹니다.', '["종으로 팔려 온 요셉이 보디발의 이집트 저택에서 곡식 창고와 열쇠를 정리하고, 보디발은 그에게 집안 일을 맡기며 신뢰하는 표정으로 서 있다", "이집트 저택의 방 안, 화려한 침상 가장자리에 앉은 여인이 종 요셉을 향해 손짓하고, 요셉은 문가 앞에 서서 몸을 뒤로 물리며 두 손을 가슴 앞에 들어 단호히 거절하는 표정", "여자가 요셉의 겉옷을 붙잡아 천이 손에 남고, 요셉은 문 밖으로 급히 도망가며 하나님 앞에 죄짓지 않겠다는 단호한 얼굴이다. 선정적 장면은 없다", "감옥에 갇힌 종 요셉이 어두운 감옥 안에서 죄수들에게 물과 빵을 나누고 일을 정리하며, 간수는 그를 신뢰하는 표정으로 바라본다"]'::jsonb, '["종으로 팔려 온 요셉이 보디발에게 인정받아 집을 관리하게 된다", "화려한 침상에서 보디발의 아내가 종 요셉을 유혹한다", "요셉은 보디발의 아내에게서 도망가다가 옷이 찢어진다", "감옥에 갇힌 종 요셉은 하나님이 함께하사 감옥에 있는 모든 일을 맡게 된다"]'::jsonb, '[["potiphar", "joseph"], ["joseph"], ["joseph"], ["joseph"]]'::jsonb, ARRAY['joseph', 'potiphar']::text[], '[{"book": "창", "from": "39:1", "to": "39:23"}]'::jsonb, -1910, -1909, 'approx', 26, 'patriarch_joseph_egypt', '요셉: 애굽으로 이어진 구원', 3, 'lm_pat_unknown', 'published'),
    ('era_monarchy', '성전 건축: 손으로 짓는 집', '솔로몬은 오랜 준비 끝에 성전을 건축한다.', '통일왕국 시대는 사울, 다윗, 솔로몬이 이스라엘 전체를 다스리던 시기입니다. 이 이야기는 「성전 건축」을 다룹니다.', '["솔로몬이 두로 왕 히람에게 성전 건축에 쓸 백향목과 잣나무 재목을 제공해 달라고 요청하고, 히람이 기뻐하며 재목을 보내 주기로 하는 장면, 그 말의 뜻을 보여 주는 글자 없는 말풍선 안에는 거대한 왕궁이 백향목과 잣나무로 지어질 것을 보여줌", "예루살렘 성전 터에서 솔로몬의 건축자들과 히람의 건축자들이 함께 돌과 목재로 성전을 열심히 건축하는 장면", "으리으리한 성전이 완성되어 금빛 장식과 높은 기둥이 빛나고, 솔로몬이 성전 앞에서 기뻐하며 하나님께 감사하는 장면"]'::jsonb, '["솔로몬이 두로 왕 히람에게 성전 건축에 쓸 백향목과 잣나무 재목을 제공해 달라고 요청한다", "예루살렘 성전 터에서 솔로몬의 건축자들과 히람의 건축자들이 함께 돌과 목재로 성전을 열심히 건축한다", "으리으리한 성전이 완성되어 금빛 장식과 높은 기둥이 빛난다"]'::jsonb, '[["solomon"], [], ["solomon"]]'::jsonb, ARRAY['solomon']::text[], '[{"book": "왕상", "from": "5:1", "to": "6:38"}]'::jsonb, -966, -959, 'approx', 26, 'monarchy_solomon_temple_fall', '솔로몬 시대: 지혜와 성전, 타락', 3, 'lm_mon_jerusalem', 'published'),
    ('era_exodus', '요단강 도하: 물이 멈추다', '이스라엘은 요단강을 건너며 약속의 땅에 들어선다.', '출애굽과 광야 여정은 이스라엘이 애굽을 떠나 시내산과 광야를 지나는 시기입니다. 이 이야기는 「요단강 도하」를 다룹니다.', '["여호수아가 언약궤를 멘 제사장들에게 요단강 앞에 서라고 지시하고, 제사장들은 엄숙한 흰 제사장 옷과 궤의 채를 붙든 채 물가로 나아간다", "제사장들의 발이 요단강 물에 닿자 강물이 위쪽에서 멈추고, 백성은 놀람과 경외로 마른 강바닥을 바라본다", "언약궤를 멘 제사장들이 강 한가운데 서 있는 동안 이스라엘 백성이 가족과 짐을 이끌고 마른 땅을 건넌다", "열두 지파 대표들이 강바닥에서 돌 열두 개를 들어 올리고, 여호수아는 길갈에 세울 기념을 설명하듯 손짓한다. 돌에는 글자가 없다"]'::jsonb, '["여호수아가 언약궤를 멘 제사장들에게 요단강 앞에 서라고 지시한다", "제사장들의 발이 요단강 물에 닿자 강물이 위쪽에서 멈추다", "언약궤를 멘 제사장들과 이스라엘 백성이 마른 땅을 건넌다", "열두 지파 대표들이 강바닥에서 돌 열두 개를 들어 올리다"]'::jsonb, '[["joshua"], [], [], ["joshua"]]'::jsonb, ARRAY['joshua']::text[], '[{"book": "수", "from": "3:1", "to": "4:24"}]'::jsonb, -1406, -1406, 'approx', 26, 'exodus_canaan_joshua', '가나안 입성과 여호수아', 3, 'lm_jud_jericho', 'published')
)
insert into events (era_id, title, summary, background_context, story_scenes, scene_captions, scene_characters, character_codes, bible_refs, start_year, end_year, time_precision, story_index, unit_code, unit_title, unit_order, landmark_id, status)
select
  e.id,
  s.title,
  s.summary,
  s.background_context,
  s.story_scenes,
  s.scene_captions,
  s.scene_characters,
  s.character_codes,
  s.bible_refs,
  s.start_year,
  s.end_year,
  s.time_precision,
  s.story_index,
  s.unit_code,
  s.unit_title,
  s.unit_order,
  lm.id,
  s.status
from seed_events s
join eras e on e.code = s.era_code
join landmarks lm on lm.code = s.landmark_code
on conflict (era_id, story_index) do update set
  title = excluded.title,
  summary = excluded.summary,
  background_context = excluded.background_context,
  story_scenes = excluded.story_scenes,
  scene_captions = excluded.scene_captions,
  scene_characters = excluded.scene_characters,
  character_codes = excluded.character_codes,
  bible_refs = excluded.bible_refs,
  start_year = excluded.start_year,
  end_year = excluded.end_year,
  time_precision = excluded.time_precision,
  unit_code = excluded.unit_code,
  unit_title = excluded.unit_title,
  unit_order = excluded.unit_order,
  landmark_id = excluded.landmark_id,
  status = excluded.status
;

with seed_events (era_code, title, summary, background_context, story_scenes, scene_captions, scene_characters, character_codes, bible_refs, start_year, end_year, time_precision, story_index, unit_code, unit_title, unit_order, landmark_code, status) as (
  values
    ('era_divided_kingdom', '요아스의 성전 보수와 배교', '요아스는 여호야다의 교훈 아래 성전을 보수하지만, 말년에는 우상과 폭력으로 하나님 앞에서 무너진다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「요아스의 성전 보수와 배교」를 다룹니다.', '["어린 유다 왕 요아스가 예루살렘 성전의 무너지고 낡은 곳을 보며 보수를 명령하지만, 성전의 갈라진 벽과 부서진 돌은 그대로 남아 있고 일꾼들은 아직 움직이지 않는 장면", "서른 살쯤 된 유다 왕 요아스가 대제사장 여호야다를 불러 성전 보수를 다시 명령하고, 성전 오른쪽 문 입구에는 구멍 뚫린 큰 궤가 놓이며 백성들이 기쁘게 은을 넣는 장면", "성전의 무너진 곳이 보수되고 새 돌과 목재로 견고해졌으며, 서른 살쯤 된 유다 왕 요아스가 여호야다와 함께 완성된 성전을 바라보며 만족하는 장면", "세월이 흐른 뒤 유다 왕 요아스가 예루살렘 성전에 아세라 목상과 우상들을 들이고, 여호야다의 아들 선지자 스가랴가 책망하자 사람들이 성전 뜰에서 스가랴를 향해 돌을 드는 장면. 죽음의 순간과 피는 직접 보이지 않는다"]'::jsonb, '["어린 유다 왕 요아스가 예루살렘 성전의 무너지고 낡은 곳을 보며 보수를 명령한다", "서른 살쯤 된 유다 왕 요아스가 대제사장 여호야다를 불러 성전 보수를 다시 명령하고 헌금을 모은다", "성전의 무너진 곳이 보수되고 새 돌과 목재로 견고해졌다", "세월이 흐른 뒤 유다 왕 요아스가 예루살렘 성전에 아세라 목상과 우상들을 들인다"]'::jsonb, '[["joash_judah"], ["joash_judah", "jehoiada"], ["joash_judah", "jehoiada"], ["joash_judah"]]'::jsonb, ARRAY['joash_judah', 'jehoiada']::text[], '[{"book": "왕하", "from": "12:1", "to": "12:16"}, {"book": "대하", "from": "24:1", "to": "24:22"}]'::jsonb, -835, -800, 'approx', 26, 'divided_two_kingdoms_north_fall', '두 왕국의 흔들림과 북이스라엘의 몰락', 4, 'lm_div_jerusalem_joash_temple', 'published'),
    ('era_nt_apostolic', '2차 전도 여행: 고린도 사역과 아굴라와 브리스길라', '고린도에서 바울은 아굴라와 브리스길라와 함께 일하며 복음을 전하고 주님의 격려 속에 오래 머문다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「차 전도 여행」을 다룹니다.', '["바울이 고린도에서 아굴라와 브리스길라를 만나 같은 장막 일을 하며 서로 반가운 얼굴로 협력한다", "바울이 안식일마다 회당에서 강론하고 반대가 거세지자 단호한 표정으로 이방인에게 향한다고 말한다", "밤 환상 속에서 주께서 두려워하지 말라 하시자 바울의 지친 얼굴에 새 용기가 떠오른다", "유대인들이 바울을 갈리오 법정으로 끌고 가지만(법정 앞에는 법정임을 표시하기 위해 디케 여신상 있음) 바울은 침착하고 아굴라와 브리스길라는 걱정스러운 얼굴로 지켜본다"]'::jsonb, '["바울이 고린도에서 아굴라와 브리스길라를 만나 같은 장막 일을 하며 서로 반가운 얼굴로 협력한다", "바울이 안식일마다 회당에서 강론하고 반대가 거세지지만 단호히 이방인에게 향한다고 말한다", "밤 환상 속에서 주께서 두려워하지 말라고 말씀하시며 바울에게 힘주신다", "유대인들이 바울을 갈리오 법정으로 끌고 가지만 바울은 침착하게 간다"]'::jsonb, '[["paul", "aquila", "priscilla"], ["paul"], ["paul"], ["paul", "aquila", "priscilla"]]'::jsonb, ARRAY['paul', 'aquila', 'priscilla']::text[], '[{"book": "행", "from": "18:1", "to": "18:17"}]'::jsonb, 51, 52, 'approx', 27, 'paul_second_journey', '바울의 2차 전도 여행', 3, 'lm_nt_ap_corinth', 'published'),
    ('era_nt_public_ministry', '귀신 들린 아이 치유', '제자들이 고치지 못한 아이를 예수님이 고치시고 믿음과 기도의 필요를 가르치신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「귀신 들린 아이 치유」를 다룹니다.', '["산 아래에서 율법학자들과 예수님의 제자들 사이에 논쟁이 벌어지고 한 아버지가 절박하게 기다린다", "아버지가 귀신 들린 아이의 어깨를 붙들고 예수님 앞에 무릎 꿇으며, 아이는 땅에서 뒹굴고 입에는 하얀 거품이 있다. 주변에는 사람들이 지켜본다", "예수님이 더러운 영을 꾸짖으시고 아이를 붙들어 일으키신다. 아이는 회복된 모습이다. 이를 주변 사람들이 지켜본다", "제자들이 조용히 묻자 예수님은 기도와 믿음의 길을 가르치신다. 예수님의 말풍선에는 기도하는 모습이 있다"]'::jsonb, '["산 아래에서 율법학자들과 예수님의 제자들 사이에 논쟁이 벌어지고 한 아버지가 절박하게 기다린다", "아버지가 귀신 들린 아이의 어깨를 붙들고 예수님 앞에 무릎 꿇는다", "예수님이 더러운 영을 꾸짖으시고 아이를 붙들어 일으키신다", "예수님은 기도와 믿음의 길을 가르치신다"]'::jsonb, '[["andrew", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["jesus"], ["jesus"], ["jesus", "andrew", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"]]'::jsonb, ARRAY['jesus', 'peter', 'andrew', 'james_zebedee', 'john', 'philip', 'bartholomew', 'matthew', 'thomas', 'james_alphaeus', 'thaddaeus', 'simon_zealot', 'judas']::text[], '[{"book": "마", "from": "17:14", "to": "17:21"}, {"book": "막", "from": "9:14", "to": "9:29"}, {"book": "눅", "from": "9:37", "to": "9:43"}]'::jsonb, 29, 29, 'approx', 27, 'journey_teaching_to_jerusalem', '길 위의 가르침과 예루살렘으로', 3, 'lm_nt_pm_mt_transfiguration', 'published'),
    ('era_patriarch', '바로의 꿈: 총리 요셉', '바로의 꿈을 해석한 요셉은 애굽의 총리로 세워진다.', '족장 시대는 아브라함, 이삭, 야곱, 요셉의 가족 이야기가 중심입니다. 이 이야기는 「바로의 꿈」을 다룹니다.', '["바로가 왕궁 침상에서 살진 소와 마른 소의 꿈을 꾸고 놀라 깨어나며, 애굽식 왕관과 얇은 아마포 침구가 보인다", "요셉이 풍년과 흉년을 대비하는 저장 계획을 설명하자 바로와 신하들이 놀라 듣고, 곡식 이삭과 저장 창고 모형이 보인다. 글자는 없다", "바로가 요셉을 애굽 총리로 세우고, 요셉이 애굽 총리의 세마포 옷과 금 목걸이를 받고 얼굴에는 책임감과 하나님의 섭리에 대한 경외감이 함께 보인다"]'::jsonb, '["바로가 살진 소와 마른 소, 좋은 이삭과 시든 이삭의 꿈을 꾸고 놀라 깨어나다", "바로와 신하들이 요셉의 꿈 해석을 놀라 듣는다", "바로가 요셉을 애굽 총리로 세운다. 요셉은 반지와 삼베옷, 금목걸이를 받는다"]'::jsonb, '[["pharaoh"], ["pharaoh", "joseph"], ["pharaoh", "joseph"]]'::jsonb, ARRAY['joseph', 'pharaoh']::text[], '[{"book": "창", "from": "41:1", "to": "41:57"}]'::jsonb, -1900, -1900, 'approx', 27, 'patriarch_joseph_egypt', '요셉: 애굽으로 이어진 구원', 3, 'lm_pat_unknown', 'published'),
    ('era_nt_post_apostolic', '생명의 말씀과 빛 가운데 행함', '요한은 처음부터 들은 생명의 말씀을 증언하며 빛 가운데 행하고 서로 사랑하라고 가르친다.', '요한일서는 요한이 예수님의 성육신을 부정하는 가르침과 공동체 분열을 겪던 교회들에게 참 믿음을 분별하게 한 편지입니다. 이 이야기는 「생명의 말씀과 빛 가운데 행함」을 다룹니다.', '["80대 노년의 요한이 에베소 성도들에게 보내는 편지. 내용은 예수님의 빛 가운데 거하는 성도들의 모습과 저 멀리 죄와 거짓이 분리된 장면", "80대 노년의 요한이 에베소 성도들에게 보내는 편지. 내용은 빛 가운데 있는 사람들은 십자가와 함께 기뻐하는 모습이고 어둠 아래 있는 사람들은 눈을 가리고 허둥지둥하는 모습", "80대 노년의 요한이 에베소 성도들에게 보내는 편지. 내용은 하나님의 빛이 세상의 정욕과 자랑을 이기는 모습"]'::jsonb, '["요한은 하나님은 빛이시며 예수의 피가 우리를 깨끗하게 해주심에 대해 이야기한다", "요한은 하나님의 말씀을 지키는 자들에게 하나님의 사랑이 이루어짐을 이야기한다", "요한이 육신의 탐욕과 안모가의 정욕과 세상의 자랑을 경계할 것을 이야기한다"]'::jsonb, '[["john"], ["john"], ["john"]]'::jsonb, ARRAY['john']::text[], '[{"book": "요일", "from": "1:1", "to": "2:17"}]'::jsonb, 90, 90, 'approx', 27, 'next_generation_suffering_church', '다음 세대와 고난받는 교회', 4, 'lm_nt_post_ephesus', 'published'),
    ('era_monarchy', '솔로몬: 이방의 경탄부터 타락까지', '솔로몬의 지혜와 영화는 이방을 놀라게 했지만, 말년의 타락은 왕국의 균열을 예고했다.', '통일왕국 시대는 사울, 다윗, 솔로몬이 이스라엘 전체를 다스리던 시기입니다. 이 이야기는 「솔로몬」을 다룹니다.', '["스바 여왕이 낙타 행렬과 많은 향품, 보석, 금을 가지고 예루살렘에 도착하고, 솔로몬이 궁정 앞에서 맞이하는 장면", "솔로몬의 성과 궁전 안에 금은보화와 귀한 그릇들이 가득 쌓여 있고, 솔로몬은 화려한 보좌 곁에서 부유한 왕국을 바라보는 장면", "솔로몬이 다른 나라 왕비들을 궁정으로 들이고, 그들이 가져온 작은 우상들이 성전과 궁전 주변에 조금씩 채워지는 장면", "금은보화와 우상들이 가득한 성전 안에 하나님의 거룩한 빛이 엄중하게 임하고, 큰 글자 없는 말풍선 안에는 성전과 왕국의 영광이 황폐해지는 경고 그림이 담긴 장면"]'::jsonb, '["스바 여왕이 낙타 행렬과 많은 향품, 보석, 금을 가지고 예루살렘에 도착한다", "솔로몬의 성과 궁전 안에 금은보화와 귀한 그릇들이 가득 쌓여 있다", "솔로몬의 지혜와 영화는 이방을 놀라게 했지만, 솔로몬은 다른 나라 왕비들을 궁에 들인다", "금은보화와 우상들이 가득한 성전 안에 하나님의 거룩한 빛이 엄중하게 임한다"]'::jsonb, '[["solomon"], ["solomon"], ["solomon"], ["god", "solomon"]]'::jsonb, ARRAY['solomon', 'god']::text[], '[{"book": "왕상", "from": "10:1", "to": "11:13"}]'::jsonb, -950, -950, 'approx', 27, 'monarchy_solomon_temple_fall', '솔로몬 시대: 지혜와 성전, 타락', 3, 'lm_mon_jerusalem', 'published'),
    ('era_exodus', '여리고: 침묵의 행진', '상식을 깨는 순종의 행진 끝에 성벽이 무너진다.', '출애굽과 광야 여정은 이스라엘이 애굽을 떠나 시내산과 광야를 지나는 시기입니다. 이 이야기는 「여리고」를 다룹니다.', '["하나님의 영광이 여호수아 앞에 임하고, 큰 글자 없는 말풍선 안에는 6일 동안 조용히 여리고 성을 돌다가 7일째 양뿔 나팔과 큰 함성으로 성벽이 무너지는 상징 그림이 담겨 있다", "여호수아와 양뿔 나팔을 든 제사장들, 언약궤를 멘 제사장들이 앞서고, 뒤에는 군사들이 여리고 성벽 주변을 침묵 속에 한 바퀴 도는 장면", "일곱째 날 여호수아의 신호에 맞춰 제사장들이 양뿔 나팔을 길게 불고 군사들이 여리고 성을 향해 크게 외치자, 여리고 성벽이 무너지는 장면, 그 말의 뜻을 보여 주는 글자 없는 말풍선 안에는 무너지는 성벽을 뒤로하고 죄에서 돌이켜 피하는 사람들이 보이는 장면이 작은 그림처럼 보인다", "무너진 여리고 성벽 사이로 여호수아와 군사들이 질서 있게 들어가 성을 점령하는 장면. 폭력이나 시신은 직접 보이지 않는다"]'::jsonb, '["하나님이 여호수아에게 6일동안 돌고 7일때 함성을 말씀하신다", "여호수아와 양뿔 나팔을 든 제사장들, 언약궤를 멘 제사장들이 여리고성을 돈다", "7일 때 함성과 나팔 소리에 여리고 성벽이 무너진다", "무너진 여리고 성벽 사이로 여호수아와 군사들이 들어가 성을 점령한다"]'::jsonb, '[["god", "joshua"], ["joshua"], ["joshua"], ["joshua"]]'::jsonb, ARRAY['god', 'joshua']::text[], '[{"book": "수", "from": "6:1", "to": "6:20"}]'::jsonb, -1406, -1406, 'approx', 27, 'exodus_canaan_joshua', '가나안 입성과 여호수아', 3, 'lm_jud_jericho', 'published'),
    ('era_divided_kingdom', '여호아하스와 요아스: 엘리사의 마지막 화살', '북이스라엘은 여전히 우상을 따르지만, 하나님은 긍휼로 숨통을 열어 주시고 엘리사는 마지막까지 구원의 표징을 전한다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「여호아하스와 요아스」를 다룹니다.', '["북이스라엘 왕 여호아하스가 사마리아 왕궁에서 아세라 목상과 금송아지 우상 앞에 서 있고, 하늘 위에는 하나님의 거룩한 빛이 엄중하게 비쳐 진노를 나타내는 장면", "북이스라엘 왕 요아스가 왕이 되어 사마리아 왕궁 안에 금송아지와 우상들을 그대로 두고 섬기며, 백성들도 어두운 표정으로 그 죄를 따르는 장면", "병들어 누워 쉬고 있는 늙은 엘리사에게 북이스라엘 왕 요아스가 찾아와 얼굴에 눈물을 흘리고, 엘리사의 지시에 따라 동쪽 창문으로 화살을 쏘는 장면", "전경에는 엘리사가 장사된 무덤이 조용히 보이고, 먼 배경에는 북이스라엘 왕 요아스가 아람과의 전쟁에서 세 번 승리해 빼앗긴 성읍들을 회복하는 장면. 시신이나 피는 보이지 않는다"]'::jsonb, '["북이스라엘 왕 여호아하스가 사마리아 왕궁에서 아세라 목상과 금송아지 우상 앞에 서 있다", "북이스라엘 왕 요아스가 왕이 되어 사마리아 왕궁 안에 금송아지와 우상들을 그대로 두고 섬긴다", "병들어 누워있는 늙은 엘리사에게 북이스라엘 왕 요아스가 찾아와 지시에 따라 화살을 쏜다", "엘리사가 장사된 무덤이 조용히 보인다"]'::jsonb, '[["jehoahaz_israel", "god"], ["jehoash_israel"], ["jehoash_israel", "elisha"], ["jehoash_israel"]]'::jsonb, ARRAY['jehoahaz_israel', 'jehoash_israel', 'elisha', 'god']::text[], '[{"book": "왕하", "from": "13:1", "to": "13:25"}]'::jsonb, -814, -782, 'approx', 27, 'divided_two_kingdoms_north_fall', '두 왕국의 흔들림과 북이스라엘의 몰락', 4, 'lm_div_samaria_jehoahaz_jehoash', 'published'),
    ('era_nt_apostolic', '2차 전도 여행: 겐그레아와 에베소 경유, 안디옥 귀환', '바울은 겐그레아와 에베소를 거쳐 가이사랴와 안디옥으로 돌아가며 다음 사역의 문을 남긴다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「차 전도 여행」을 다룹니다.', '["바울이 형제들과 작별하고 아굴라와 브리스길라와 함께 배에 오르며 얼굴에는 아쉬움과 기대가 함께 있다", "겐그레아에서 바울이 서원을 따라 머리를 깎고 조용하지만 결심한 표정으로 여정을 이어 간다", "에베소 회당 사람들이 더 머물라 청하지만 바울은 하나님의 뜻이면 돌아오겠다고 진지하게 약속한다", "바울이 가이사랴를 거쳐 안디옥으로 내려가고 아굴라와 브리스길라는 에베소 사역을 맡아 남는다"]'::jsonb, '["바울이 형제들과 작별하고 아굴라와 브리스길라와 함께 배에 오른다", "겐그레아에서 바울이 서원을 따라 머리를 깎고 여정을 이어간다", "에베소 회당 사람들이 더 머물라 청하지만 바울은 하나님의 뜻이면 돌아오겠다고 약속한다", "바울이 가이사랴를 거쳐 안디옥으로 내려가고 아굴라와 브리스길라는 에베소 사역을 맡아 남는다"]'::jsonb, '[["paul", "aquila", "priscilla"], ["paul"], ["paul"], ["paul", "aquila", "priscilla"]]'::jsonb, ARRAY['paul', 'aquila', 'priscilla']::text[], '[{"book": "행", "from": "18:18", "to": "18:22"}]'::jsonb, 52, 52, 'approx', 28, 'paul_second_journey', '바울의 2차 전도 여행', 3, 'lm_nt_ap_ephesus', 'published'),
    ('era_nt_public_ministry', '두 번째 수난 예고와 제자들의 논쟁', '예수님은 두 번째로 죽음과 부활을 예고하시고, 제자들에게 어린아이처럼 낮아지는 큰 자의 길을 가르치신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「두 번째 수난 예고와 제자들의 논쟁」을 다룹니다.', '["갈릴리를 지나는 길에서 예수님이 제자들에게 다시 고난과 부활을 예고하시고, 제자들은 먼지 묻은 길 위에서 서로 눈치를 보며 이해하지 못한 채 긴장한다", "제자들은 말씀을 이해하지 못한 채 서로 누가 큰지를 조용히 논쟁한다. 말풍선 안에는 큰자와 작은자의 실루엣이 보인다", "가버나움 집 안에서 예수님이 어린아이를 가운데 세우시고 제자들은 부끄러움과 배움의 얼굴로 바라본다"]'::jsonb, '["갈릴리를 지나는 길에서 예수님이 제자들에게 다시 고난과 부활을 예고하신다", "제자들은 말씀을 이해하지 못한 채 서로 누가 큰지를 조용히 논쟁한다", "가버나움 집 안에서 예수님이 어린아이를 가운데 세우시고 제자들에게 말씀하신다"]'::jsonb, '[["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"]]'::jsonb, ARRAY['jesus', 'peter', 'andrew', 'james_zebedee', 'john', 'philip', 'bartholomew', 'matthew', 'thomas', 'james_alphaeus', 'thaddaeus', 'simon_zealot', 'judas']::text[], '[{"book": "마", "from": "17:22", "to": "18:5"}, {"book": "막", "from": "9:30", "to": "9:37"}, {"book": "눅", "from": "9:43", "to": "9:48"}]'::jsonb, 29, 29, 'approx', 28, 'journey_teaching_to_jerusalem', '길 위의 가르침과 예루살렘으로', 3, 'lm_nt_pm_capernaum', 'published'),
    ('era_nt_post_apostolic', '밧모섬에서 본 영광의 그리스도', '요한은 밧모섬에서 영광 가운데 계신 그리스도를 보고 일곱 교회에 전할 말씀을 받는다.', '요한계시록은 요한이 밧모섬에서 받은 계시를 소아시아 일곱 교회에 전하도록 기록한 책입니다. 이 이야기는 「밧모섬에서 본 영광의 그리스도」를 다룹니다.', '["노년의 요한이 나팔같은 큰 소리와 강한 빛 앞에 놀라 엎드리고, 예수님은 위엄 있고 자비로운 표정으로 그에게 손을 내밀어 두려워하지 말라는 듯 다가온다", "노년의 요한이 떨리는 고개를 들어보니 촛대들 사이에 인자 같은 분이 긴 옷과 가슴에 금띠를 띠고 머리는 흰색이며 오른 손에 일곱 별을 들고 얼굴을 해가 비추는 모습"]'::jsonb, '["요한이 나팔같은 큰 소리와 강한 예수의 빛 앞에 놀라 엎드린다", "요한이 고개를 들어보니 촛대들 사이에 인자 같은 분이 긴 옷과 가슴에 금띠를 띠고 계신 모습을 본다"]'::jsonb, '[["john", "jesus"], ["john"]]'::jsonb, ARRAY['john']::text[], '[{"book": "계", "from": "1:9", "to": "1:20"}]'::jsonb, 95, 95, 'approx', 28, 'patmos_seven_churches', '밧모섬과 일곱 교회', 5, 'lm_nt_post_patmos', 'published'),
    ('era_exodus', '아간: 감춘 것이 드러나다', '숨긴 탐욕이 공동체의 패배로 드러나고, 정리가 시작된다.', '출애굽과 광야 여정은 이스라엘이 애굽을 떠나 시내산과 광야를 지나는 시기입니다. 이 이야기는 「아간」을 다룹니다.', '["여호수아가 아이 성 함락을 위해 군사 3000명을 올려보냈지만, 군사들이 패배하고 놀란 표정으로 이스라엘 진영에 돌아오는 모습", "여호수아가 하나님 앞에 엎드려 기도하고, 하나님의 영광에서 나온 큰 글자 없는 말풍선 안에는 이스라엘 가운데 범죄를 저지른 사람이 있어 제비를 뽑아 찾아내야 함을 상징하는 그림이 담겨 있다", "아간이 제비에서 뽑혀 떨며 서 있고, 그의 장막 앞에는 숨겨 두었던 은과 금이 드러나며, 여호수아가 불같이 화를 내는 장면"]'::jsonb, '["여호수아가 아이 성 함락을 위해 군사 3000명을 올려보냈지만 패배한다", "여호수아가 하나님 앞에 엎드려 기도하고 하나님은 감춘 것을 말씀하신다", "아간이 제비에서 뽑히고, 그의 장막 앞에는 숨겨 두었던 것들이 드러나다"]'::jsonb, '[["joshua"], ["god", "joshua"], ["joshua", "achan"]]'::jsonb, ARRAY['god', 'joshua', 'achan']::text[], '[{"book": "수", "from": "7:1", "to": "7:26"}]'::jsonb, -1406, -1406, 'approx', 28, 'exodus_canaan_joshua', '가나안 입성과 여호수아', 3, 'lm_jud_ai', 'published'),
    ('era_patriarch', '요셉의 정체 공개: 울음의 방', '요셉은 더 이상 참지 못하고 형제들에게 자신을 드러낸다.', '족장 시대는 아브라함, 이삭, 야곱, 요셉의 가족 이야기가 중심입니다. 이 이야기는 「요셉의 정체 공개」를 다룹니다.', '["요셉이 총리의 겉모습 일부를 내려놓고 자신을 밝히며, 형들은 믿기 어려운 얼굴로 뒤로 물러선다. 그 말의 뜻을 보여 주는 글자 없는 말풍선 안에는 총리 옷 일부를 내려놓은 요셉과 어린 시절 형제들이 함께 서 있던 모습이 작은 그림처럼 보인다", "총리 차림의 요셉이 베냐민을 끌어안고 울고, 유다와 형들은 뒤에서 죄책감과 안도감이 섞인 얼굴로 그 모습을 바라본다"]'::jsonb, '["요셉이 총리의 겉모습 일부를 내려놓고 자신을 밝히다", "요셉은 베냐민을 끌어안고 울고 모두 놀란다"]'::jsonb, '[["joseph", "benjamin", "judah", "reuben"], ["joseph", "benjamin", "judah", "reuben"]]'::jsonb, ARRAY['joseph', 'benjamin', 'judah', 'reuben']::text[], '[{"book": "창", "from": "45:1", "to": "45:15"}]'::jsonb, -1885, -1885, 'approx', 28, 'patriarch_joseph_egypt', '요셉: 애굽으로 이어진 구원', 3, 'lm_pat_egypt_court', 'published'),
    ('era_divided_kingdom', '요아스의 최후: 하사엘과 반역', '요아스의 배교 뒤 아람의 압박이 찾아오고, 그는 성전의 보물을 내어 주지만 결국 신하들의 반역으로 무너진다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「요아스의 최후」를 다룹니다.', '["아람 군대가 유다와 예루살렘을 향해 쳐들어오고, 유다 왕 요아스가 전투와 혼란 속에서 크게 다쳐 신하들의 부축을 받는 장면. 피와 상처의 세부 묘사는 보이지 않는다", "부상당한 유다 왕 요아스가 성전의 거룩한 물건들과 왕궁의 금을 하사엘에게 보내고, 아람 왕 하사엘은 예물을 받아 만족한 표정으로 군대를 돌려 떠나는 장면", "밤의 왕궁 침실, 부상당한 유다 왕 요아스가 왕관과 왕복 일부를 곁에 둔 채 침상에 누워 있다. 왕궁 문은 안에서 몰래 닫혀 있고, 두 신하가 서로 비밀 신호를 주고받으며 겉옷 속에 단검을 숨긴 채 침상 쪽으로 다가온다. 호위병 한 명은 뇌물을 받은 듯 시선을 돌리고, 요아스는 반역을 눈치채고 크게 놀라 몸을 일으키려 한다."]'::jsonb, '["아람 군대가 쳐들어오고 요아스가 부상을 입는다", "부상당한 유다 왕 요아스가 성전의 거룩한 물건들과 왕궁의 금을 아람 왕 하사엘에게 보낸다", "밤의 왕궁 침실, 요아스의 신복들이 반역한다"]'::jsonb, '[["joash_judah"], ["joash_judah"], ["joash_judah"]]'::jsonb, ARRAY['joash_judah']::text[], '[{"book": "왕하", "from": "12:17", "to": "12:21"}, {"book": "대하", "from": "24:23", "to": "24:27"}]'::jsonb, -796, -796, 'approx', 28, 'divided_two_kingdoms_north_fall', '두 왕국의 흔들림과 북이스라엘의 몰락', 4, 'lm_div_jerusalem_joash_last', 'published'),
    ('era_nt_apostolic', '3차 전도 여행: 아볼로와 브리스길라와 아굴라', '바울은 다시 교회들을 굳게 하고, 에베소에서는 브리스길라와 아굴라가 아볼로에게 하나님의 도를 더 정확히 풀어 준다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「차 전도 여행」을 다룹니다.', '["바울이 안디옥을 떠나 갈라디아와 브루기아를 지나며 제자들을 북돋워준다", "아볼로가 에베소 회당에서 열심 있는 표정으로 예수에 관해 자세히 말한다", "브리스길라와 아굴라가 아볼로를 따로 데려가 온유하지만 분명한 얼굴로 하나님의 도를 더 정확히 풀어 준다"]'::jsonb, '["바울이 안디옥을 떠나 갈라디아와 브루기아를 지나며 제자들을 북돋워준다", "아볼로가 에베소 회당에서 예수에 관해 말한다", "브리스길라와 아굴라가 아볼로를 따로 데려가 하나님의 도를 더 정확히 풀어 준다"]'::jsonb, '[["paul"], ["aquila", "priscilla"], ["aquila", "priscilla"]]'::jsonb, ARRAY['paul', 'aquila', 'priscilla']::text[], '[{"book": "행", "from": "18:23", "to": "18:28"}]'::jsonb, 53, 53, 'approx', 29, 'paul_third_journey', '바울의 3차 전도 여행', 4, 'lm_nt_ap_antioch_syria', 'published'),
    ('era_patriarch', '고센 정착: 만남과 눈물', '요셉은 야곱을 맞이하고, 이스라엘은 고센에 자리 잡는다.', '족장 시대는 아브라함, 이삭, 야곱, 요셉의 가족 이야기가 중심입니다. 이 이야기는 「고센 정착」을 다룹니다.', '["고센 들판 길 위, 애굽 총리 요셉이 흰 세마포 겉옷과 얇은 금 목걸이를 단정히 하고 작은 전차를 타고 야곱의 가족을 맞으러 달려간다", "고센 들판 입구, 흰 세마포 옷과 얇은 금 목걸이를 한 애굽 총리 요셉이 흰 수염의 늙은 야곱을 두 팔로 끌어안고 눈물을 흘린다", "애굽 궁정 안, 왕관을 쓴 바로와 흰 수염의 야곱이 서로 마주 서 있고, 흰 세마포 옷과 얇은 금 목걸이를 한 총리 요셉은 두 사람 사이 옆쪽에서 조용히 안내한다"]'::jsonb, '["요셉이 병거를 갖추고 이스라엘을 만나러 고센으로 간다", "야곱과 요셉이 끌어안고 기쁨을 만끽한다", "애굽 궁정 안, 바로에게 요셉이 야곱을 소개하고 야곱과 가족들은 고센에 정착한다"]'::jsonb, '[["joseph"], ["jacob", "joseph"], ["pharaoh", "jacob", "joseph"]]'::jsonb, ARRAY['jacob', 'joseph', 'pharaoh']::text[], '[{"book": "창", "from": "46:28", "to": "47:12"}]'::jsonb, -1880, -1879, 'approx', 29, 'patriarch_joseph_egypt', '요셉: 애굽으로 이어진 구원', 3, 'lm_pat_goshen', 'published'),
    ('era_divided_kingdom', '아마샤와 북이스라엘 요아스: 교만한 도전', '아마샤는 에돔을 이긴 뒤 교만하게 북이스라엘에 도전하지만, 예루살렘 성벽과 성전 보물까지 잃는다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「아마샤와 북이스라엘 요아스」를 다룹니다.', '["스물다섯 살에 왕이 된 남유다 아마샤가 소금 골짜기 전투에서 에돔 군대를 물리치고 승리하는 장면. 전투는 먼 거리로 보이며 피와 시신은 직접 보이지 않는다", "승리에 취한 아마샤가 북이스라엘 왕 요아스에게 싸우자고 도전하고, 요아스는 사신 앞에서 가시나무와 백향목의 비유를 말하듯 경고하는 장면. 말풍선은 그림으로만 표현되고 글자는 없다", "벧세메스 근처 전투에서 아마샤와 유다 군대가 북이스라엘 요아스의 군대에게 패해 급히 도망가는 장면. 패배와 혼란은 보이지만 피와 시신은 보이지 않는다", "북이스라엘 왕 요아스가 예루살렘 성벽 일부를 허물고 성전과 왕궁의 금과 은, 사람들을 사마리아로 데려가는 장면. 아마샤는 포로처럼 무너진 표정으로 서 있고 폭력 묘사는 절제한다"]'::jsonb, '["스물다섯 살에 왕이 된 남유다 아마샤가 소금 골짜기 전투에서 에돔 군대를 물리치고 승리한다", "승리에 취한 아마샤가 북이스라엘 왕 요아스에게 싸우자고 도전한다", "벧세메스 근처 전투에서 아마샤와 유다 군대가 북이스라엘 요아스의 군대에게 패해 급히 도망간다", "북이스라엘에 패배한 아마샤는 예루살렘 성벽과 성전 보물까지 잃는다"]'::jsonb, '[["amaziah_judah"], ["amaziah_judah", "jehoash_israel"], ["amaziah_judah", "jehoash_israel"], ["amaziah_judah", "jehoash_israel"]]'::jsonb, ARRAY['amaziah_judah', 'jehoash_israel']::text[], '[{"book": "왕하", "from": "14:1", "to": "14:15"}]'::jsonb, -796, -790, 'approx', 29, 'divided_two_kingdoms_north_fall', '두 왕국의 흔들림과 북이스라엘의 몰락', 4, 'lm_div_salt_valley_beth_shemesh', 'published'),
    ('era_exodus', '아이 성 정복: 다시 일어서다', '하나님은 실패 뒤 다시 길을 여시고, 이스라엘은 말씀대로 아이 성을 차지한 뒤 제단을 쌓는다.', '출애굽과 광야 여정은 이스라엘이 애굽을 떠나 시내산과 광야를 지나는 시기입니다. 이 이야기는 「아이 성 정복」을 다룹니다.', '["하나님의 영광이 여호수아 앞에 임하고 하나님의 말풍선에는 여호수아와 군대가 아이성을 차지하는 장면", "여호수아와 이스라엘 군대가 하나님의 지시대로 아이 성을 차지하는 장면. 전투의 긴장감은 보이지만 폭력이나 시신은 직접 보이지 않는다", "여호수아가 아이 성 근처 에발산 쪽에서 다듬지 않은 돌로 제단을 쌓고 번제와 화목제를 드리며, 백성은 조용한 감사와 경외로 둘러선다. 피와 도살 장면은 보이지 않는다"]'::jsonb, '["하나님이 여호수아에게 성을 주실 것을 약속하신다", "여호수아와 이스라엘 군대가 하나님의 지시대로 아이 성을 차지한다", "여호수아가 아이 성 근처 에발산 쪽에서 돌로 제단을 쌓고 번제와 화목제를 드린다"]'::jsonb, '[["god", "joshua"], ["god", "joshua"], ["god", "joshua"]]'::jsonb, ARRAY['god', 'joshua']::text[], '[{"book": "수", "from": "8:1", "to": "8:35"}]'::jsonb, -1406, -1406, 'approx', 29, 'exodus_canaan_joshua', '가나안 입성과 여호수아', 3, 'lm_jud_ai', 'published'),
    ('era_nt_post_apostolic', '일곱 교회에 보내는 말씀', '부활하신 그리스도께서 소아시아 일곱 교회에 칭찬과 책망, 회개와 이김의 약속을 전하신다.', '요한계시록은 요한이 밧모섬에서 받은 계시를 소아시아 일곱 교회에 전하도록 기록한 책입니다. 이 이야기는 「일곱 교회에 보내는 말씀」을 다룹니다.', '["노년의 요한이 유배자의 거친 망토를 입고 두루마리를 품은 채 일곱 교회를 대표하는 서로 다른 성도들을 바라보며, 각 교회에 전할 칭찬과 책망의 무게 때문에 엄숙한 표정을 짓는다", "노년의 요한의 편지에는 성도들이 범죄를 저지르고 있는 모습(음행과 우상숭배)", "노년의 요한의 편지에는 성도들위에 촛대가 화난 빛을 비추고 성도들은 두려워 떨고 있는 모습", "노년의 요한의 편지에는 성도들이 차지도 않고 뜨겁지도 않게 신앙생활을 하고 있는 모습과 회개를 촉구하는 모습"]'::jsonb, '["요한이 일곱 교회에 칭찬과 책망 회개와 이김을 전한다", "요한이 버가모 교회에 우상의 가르침을 버리고 회개를 촉구한다", "요한이 첫사랑을 버린 에베소 교회를 책망하고 회개를 촉구한다", "요한이 라오디게아 교회를 향해 차거나 뜨겁게 신앙생활 할 것을 촉구한다"]'::jsonb, '[["john"], ["john"], ["jesus"], ["john"]]'::jsonb, ARRAY['john', 'jesus']::text[], '[{"book": "계", "from": "2:1", "to": "3:22"}]'::jsonb, 95, 95, 'approx', 29, 'patmos_seven_churches', '밧모섬과 일곱 교회', 5, 'lm_nt_post_ephesus', 'published'),
    ('era_nt_public_ministry', '주기도문과 기도 가르침', '예수님은 제자들에게 하나님을 아버지로 부르며 기도하는 법과 끈질기게 구하는 믿음을 가르치신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「주기도문과 기도 가르침」을 다룹니다.', '["제자들이 예수님께 기도를 가르쳐 달라고 조심스럽게 청한다", "예수님이 하늘 아버지의 이름과 나라와 뜻을 구하는 기도를 가르치신다, 그 말의 뜻을 보여 주는 글자 없는 말풍선 안에는 하늘을 향한 빈 손과 보호받는 사람들이 보이는 장면이 작은 그림처럼 보인다"]'::jsonb, '["제자들이 예수님께 기도를 가르쳐 달라고 조심스럽게 청한다", "예수님이 하늘 아버지의 이름과 나라와 뜻을 구하는 기도를 가르치신다"]'::jsonb, '[["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["jesus"]]'::jsonb, ARRAY['jesus', 'peter', 'andrew', 'james_zebedee', 'john', 'philip', 'bartholomew', 'matthew', 'thomas', 'james_alphaeus', 'thaddaeus', 'simon_zealot', 'judas']::text[], '[{"book": "마", "from": "6:9", "to": "6:13"}, {"book": "눅", "from": "11:1", "to": "11:13"}]'::jsonb, 29, 30, 'approx', 29, 'journey_teaching_to_jerusalem', '길 위의 가르침과 예루살렘으로', 3, 'lm_nt_pm_mt_beatitudes', 'published'),
    ('era_nt_apostolic', '3차 전도 여행: 에베소에서 전함', '에베소에서 바울은 성령을 가르치고 두란노 서원에서 말씀을 전하며 주의 말씀이 힘 있게 퍼진다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「차 전도 여행」을 다룹니다.', '["바울이 안수하자 그들이 성령을 받고 말하며 주변 사람들은 놀라움과 경외심으로 바라본다", "두란노 서원에서 바울이 날마다 가르치고 듣는 사람들은 집중한 얼굴로 말씀에 귀 기울인다", "어떤 이들이 예수의 이름으로 악한 영에 빠진 사람을 쫓아내려 하자 그가 달려드는 모습. 악한 영에 빠진 사람은 얼굴이 검정 빛이고, 말풍선에는 악한영이 예수님과 바울을 두려워 하는 그림이 있다", "마술 책들이 사람들 앞에서 불태워지고 회개한 이들의 얼굴에는 두려움과 해방감이 함께 드러난다"]'::jsonb, '["바울이 안수하자 그들이 성령을 받고 말하고 주변 사람들이 놀란다", "두란노 서원에서 바울이 날마다 가르치고 듣는 사람들은 집중한 얼굴로 말씀에 귀 기울인다", "어떤 이들이 예수의 이름으로 악한 영에 빠진 사람을 쫓아내려 하자 그가 달려든다", "마술 책들이 사람들 앞에서 불태워지고 회개한다"]'::jsonb, '[["paul"], ["paul"], ["paul", "jesus"], ["paul"]]'::jsonb, ARRAY['paul']::text[], '[{"book": "행", "from": "19:1", "to": "19:20"}]'::jsonb, 53, 55, 'approx', 30, 'paul_third_journey', '바울의 3차 전도 여행', 4, 'lm_nt_ap_ephesus', 'published'),
    ('era_exodus', '기브온 전투: 해와 달이 머물다', '여호수아가 기브온을 돕는 전투에서 하나님은 우박과 긴 낮으로 승리를 이루신다.', '출애굽과 광야 여정은 이스라엘이 애굽을 떠나 시내산과 광야를 지나는 시기입니다. 이 이야기는 「기브온 전투」를 다룹니다.', '["아도니세덱과 헤브론, 야르뭇, 라기스, 에글론의 왕들이 지도와 성읍 모형을 가운데 두고 모여 여호수아를 칠 계획을 짜는 모습. 이름표나 글자는 보이지 않는다", "여호수아가 이스라엘 군대와 함께 전투에서 이기고, 하나님의 영광이 하늘에서 도망하는 군사들 쪽으로 큰 우박을 내리는 장면. 폭력이나 시신은 직접 보이지 않는다"]'::jsonb, '["아도니세덱과 헤브론, 야르뭇, 라기스, 에글론의 왕들이 여호수아를 칠 계획을 짠다", "하나님이 적군을 혼란케하시고 우박을 내리시고 해를 지지않게 하셔서 여호수아가 전투에서 이긴다"]'::jsonb, '[[], ["god", "joshua"]]'::jsonb, ARRAY['god', 'joshua']::text[], '[{"book": "수", "from": "10:1", "to": "10:15"}]'::jsonb, -1406, -1406, 'approx', 30, 'exodus_canaan_joshua', '가나안 입성과 여호수아', 3, 'lm_exo_gibeon_battle', 'published'),
    ('era_patriarch', '야곱의 축복: 열두 아들', '야곱은 마지막 순간 아들들을 불러 각 지파의 길을 예언적으로 선언한다.', '족장 시대는 아브라함, 이삭, 야곱, 요셉의 가족 이야기가 중심입니다. 이 이야기는 「야곱의 축복」을 다룹니다.', '["침상 앞, 흰수염의 눈이 어둡고 늙은 야곱이 팔을 어긋맞겨 오른손을 어린 에브라임의 머리에 얹고 왼손을 므낫세의 머리에 얹으며, 흰 세마포 옷과 얇은 금 목걸이를 한 총리 요셉은 놀란 얼굴로 야곱의 손을 조심히 바로잡으려 하지만 야곱은 맞다고 하는 장면", "넓은 애굽 집 안, 흰수염의 눈이 어둡고 늙은 야곱 앞에 열두 아들(흰 세마포 옷과 얇은 금 목걸이를 한 총리 요셉을 포함한 중년의 남자들)이 반원으로 둘러섰고 야곱이 한사람씩 축복하는 모습", "흰수염의 눈이 어둡고 늙은 야곱이 침대에 발을 올려놓고 숨을 거두고, 열두 아들(흰 세마포 옷과 얇은 금 목걸이를 한 총리 요셉을 중년의 남자들)이 흐느낀다"]'::jsonb, '["야곱은 마지막 순간 요셉의 아들들에게 팔을 어긋맞겨 축복한다", "야곱은 마지막 순간 아들들을 불러 각 지파의 길을 예언적으로 선언한다", "야곱이 침대에서 숨을 거두고 가족들은 슬퍼한다"]'::jsonb, '[["joseph", "jacob"], ["joseph", "jacob"], ["joseph", "jacob"]]'::jsonb, ARRAY['jacob', 'joseph']::text[], '[{"book": "창", "from": "48:1", "to": "48:22"}, {"book": "창", "from": "49:1", "to": "49:33"}]'::jsonb, -1860, -1860, 'approx', 30, 'patriarch_joseph_egypt', '요셉: 애굽으로 이어진 구원', 3, 'lm_pat_unknown', 'published'),
    ('era_divided_kingdom', '여로보암 2세와 왕위 전환: 회복과 그림자', '북이스라엘은 여로보암 2세 때 영토를 회복하지만 악에서 떠나지 않고, 남유다는 아마샤 뒤에 어린 아사랴가 왕위에 오른다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「여로보암 2세와 왕위 전환」을 다룹니다.', '["북이스라엘 왕 요아스가 죽은 뒤 여로보암 2세가 사마리아에서 새 왕으로 세워지고, 신하들이 왕관과 왕복을 들고 서 있지만 배경에는 금송아지 우상이 희미하게 보이는 장면", "남유다 왕 아마샤가 예루살렘의 반역을 피해 라기스로 도망갔으나 그곳에서 반역자들에게 붙잡혀 죽음을 맞는 장면. 죽음의 순간과 피와 시신의 세부 묘사는 보이지 않는다", "열여섯 살 아사랴, 곧 웃시야가 아마샤를 대신해 남유다 왕으로 세워지고, 어린 왕은 슬픈 표정으로 왕관을 받으며 백성들은 조용히 바라보는 장면", "여로보암 2세가 전쟁에서 여러 번 승리하여 북이스라엘의 국경을 크게 회복하고, 지도 위에는 하맛 어귀에서 아라바 바다까지 넓어진 경계가 그림으로 표현되는 장면. 글자는 보이지 않는다"]'::jsonb, '["북이스라엘 왕 요아스가 죽은 뒤 여로보암 2세가 사마리아에서 새 왕으로 세워지지만 우상은 여전하다", "아마샤가 반역을 피해 도망가지만 최후를 맞는다", "열여섯 살 아사랴, 곧 웃시야가 아마샤를 대신해 남유다 왕으로 세워진다", "여로보암 2세가 전쟁에서 여러 번 승리하여 북이스라엘의 국경을 크게 회복한다"]'::jsonb, '[["jeroboam_ii"], ["amaziah_judah"], ["uzziah"], ["jeroboam_ii"]]'::jsonb, ARRAY['jeroboam_ii', 'amaziah_judah', 'uzziah']::text[], '[{"book": "왕하", "from": "14:16", "to": "14:29"}]'::jsonb, -793, -753, 'approx', 30, 'divided_two_kingdoms_north_fall', '두 왕국의 흔들림과 북이스라엘의 몰락', 4, 'lm_div_samaria_jeroboam_ii', 'published')
)
insert into events (era_id, title, summary, background_context, story_scenes, scene_captions, scene_characters, character_codes, bible_refs, start_year, end_year, time_precision, story_index, unit_code, unit_title, unit_order, landmark_id, status)
select
  e.id,
  s.title,
  s.summary,
  s.background_context,
  s.story_scenes,
  s.scene_captions,
  s.scene_characters,
  s.character_codes,
  s.bible_refs,
  s.start_year,
  s.end_year,
  s.time_precision,
  s.story_index,
  s.unit_code,
  s.unit_title,
  s.unit_order,
  lm.id,
  s.status
from seed_events s
join eras e on e.code = s.era_code
join landmarks lm on lm.code = s.landmark_code
on conflict (era_id, story_index) do update set
  title = excluded.title,
  summary = excluded.summary,
  background_context = excluded.background_context,
  story_scenes = excluded.story_scenes,
  scene_captions = excluded.scene_captions,
  scene_characters = excluded.scene_characters,
  character_codes = excluded.character_codes,
  bible_refs = excluded.bible_refs,
  start_year = excluded.start_year,
  end_year = excluded.end_year,
  time_precision = excluded.time_precision,
  unit_code = excluded.unit_code,
  unit_title = excluded.unit_title,
  unit_order = excluded.unit_order,
  landmark_id = excluded.landmark_id,
  status = excluded.status
;

with seed_events (era_code, title, summary, background_context, story_scenes, scene_captions, scene_characters, character_codes, bible_refs, start_year, end_year, time_precision, story_index, unit_code, unit_title, unit_order, landmark_code, status) as (
  values
    ('era_nt_public_ministry', '은혜와 탐심을 비유로 말씀하심', '예수님은 포도원 품꾼, 어리석은 부자, 잃은 양과 잃은 은전, 탕자와 청지기 비유로 은혜와 회개와 재물의 태도를 가르치신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「은혜와 탐심을 비유로 말씀하심」을 다룹니다.', '["예수님이 포도원 품꾼 비유로 먼저 된 자와 나중 된 자의 은혜를 가르치신다. 말풍선에는 포도원 주인이 두 사람에게 1 데나리온씩을 분배하는 모습", "한 사람이 유산 문제를 꺼내자 예수님이 어리석은 부자의 비유로 탐심을 경계하신다", "세리와 죄인들이 가까이 오는 자리에서 예수님이 잃은 양과 잃은 은전을 비유로 말씀하신다. 말풍선에는 잃은 양을 찾아서 기뻐하는 목자의 모습", "예수님이 집을 떠난 아들 비유를 말씀하신다. 말풍선 안에는 집으로 빈털터리가 되어 돌아온 아이를 부자 아빠가 안아주며 기뻐하는 모습"]'::jsonb, '["예수님이 포도원 품꾼 비유로 먼저 된 자와 나중 된 자의 은혜를 가르치신다", "예수님이 어리석은 부자의 비유로 탐심을 경계하신다", "세리와 죄인들이 가까이 오는 자리에서 예수님이 잃은 양과 잃은 은전을 비유로 말씀하신다", "예수님이 집을 떠난 아들 비유를 말씀하신다"]'::jsonb, '[["jesus"], ["jesus"], ["jesus"], ["jesus"]]'::jsonb, ARRAY['jesus']::text[], '[{"book": "마", "from": "20:1", "to": "20:16"}, {"book": "눅", "from": "12:13", "to": "12:21"}, {"book": "눅", "from": "15:1", "to": "16:18"}]'::jsonb, 30, 32, 'approx', 30, 'journey_teaching_to_jerusalem', '길 위의 가르침과 예루살렘으로', 3, 'lm_nt_pm_perea', 'published'),
    ('era_nt_apostolic', '3차 전도 여행: 에베소 아데미 소동', '에베소에서 아데미 신전과 은장색들의 이익 문제가 소동이 되고, 성읍 서기관이 무리를 진정시킨다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「차 전도 여행」을 다룹니다.', '["에베소 작업장 앞에서 은장색 데메드리오가 작은 신전 모형들을 든 직공들을 모아 분노한 얼굴로 바울의 전도 때문에 장사가 위태롭다고 선동한다", "에베소 극장에 큰 소동이 일어나고 사람들은 격앙된 얼굴로 아데미를 외치며 바울의 동행자 가이오와 아리스다고에게 몰려든다. 바울은 사람들의 만류로 극장에 못 들어가지 못하고 밖에 머문다", "시청 서기관이 무리를 진정시키고 화난 무리들을 극장에서 해산시킨다"]'::jsonb, '["데메드리오가 에베소 직공들을 모아 바울 때문에 장사가 위태롭다고 선동한다", "에베소 극장에 큰 소동이 일어나고 사람들은 격앙된 얼굴로 아데미를 외치며 가이오와 아리스다고에게 몰려든다", "시청 서기관이 무리를 진정시키고 화난 무리들을 극장에서 해산시킨다"]'::jsonb, '[["paul"], ["paul"], ["paul"]]'::jsonb, ARRAY['paul']::text[], '[{"book": "행", "from": "19:21", "to": "19:41"}]'::jsonb, 55, 55, 'approx', 31, 'paul_third_journey', '바울의 3차 전도 여행', 4, 'lm_nt_ap_ephesus', 'published'),
    ('era_nt_public_ministry', '부자 청년', '부자 청년이 영생을 묻지만 재물을 내려놓지 못하고, 예수님은 하나님께는 모든 것이 가능하다고 가르치신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「부자 청년」을 다룹니다.', '["한 부자 청년이 예수님께 달려와 영생을 얻으려면 무엇을 해야 하는지 묻는다", "예수님이 계명과 이웃 사랑을 짚으시며 부족한 한 가지를 말씀하신다", "청년이 재물을 내려놓지 못해 근심하며 물러가고 예수님은 슬프게 바라보신다", "제자들이 놀라자 예수님은 하나님께는 모든 것이 가능하다고 가르치신다"]'::jsonb, '["부자 청년이 예수님께 달려와 영생을 얻으려면 무엇을 해야 하는지 묻는다", "예수님이 계명과 이웃 사랑을 짚으시며 부족한 한 가지를 말씀하신다", "청년이 재물을 내려놓지 못해 근심하며 물러가고 예수님은 슬프게 바라보신다", "예수님은 하나님께는 모든 것이 가능하다고 가르치신다"]'::jsonb, '[["jesus"], ["jesus"], ["jesus"], ["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"]]'::jsonb, ARRAY['jesus', 'peter', 'andrew', 'james_zebedee', 'john', 'philip', 'bartholomew', 'matthew', 'thomas', 'james_alphaeus', 'thaddaeus', 'simon_zealot', 'judas']::text[], '[{"book": "마", "from": "19:16", "to": "19:30"}, {"book": "막", "from": "10:17", "to": "10:31"}, {"book": "눅", "from": "18:18", "to": "18:30"}]'::jsonb, 32, 32, 'approx', 31, 'journey_teaching_to_jerusalem', '길 위의 가르침과 예루살렘으로', 3, 'lm_nt_pm_perea', 'published'),
    ('era_exodus', '여호수아의 마지막 권면: 언약을 붙들라', '늙은 여호수아는 백성에게 하나님만 섬기라고 당부하고, 언약의 증거를 세운 뒤 사명을 마친다.', '출애굽과 광야 여정은 이스라엘이 애굽을 떠나 시내산과 광야를 지나는 시기입니다. 이 이야기는 「여호수아의 마지막 권면」을 다룹니다.', '["늙은 흰 머리 여호수아가 장로들을 불러 하나님이 우리를 인도하셨음을 말하고, 큰 글자 없는 말풍선 안에는 전쟁의 승리와 제비 뽑아 땅을 나눈 그림이 담겨 있다", "늙은 흰 머리 여호수아가 백성 앞에서 절대 우상을 섬기거나 악한 일을 하면 안 된다고 말하고, 큰 글자 없는 말풍선 안에는 깨진 우상과 하나님께 돌아서는 백성의 상징 그림이 담겨 있다", "늙은 흰 머리 여호수아가 하나님의 행하심이 적힌 율법책을 기록하고, 큰 돌을 가져다가 성소 근처 상수리나무 아래 세워 놓는 장면", "늙은 여호수아가 침상에서 조용히 생을 마치고, 백성들이 침상 곁과 장막 밖에서 슬퍼하며 애도하는 장면"]'::jsonb, '["늙은 여호수아가 장로들을 불러 하나님이 우리를 인도하셨음을 말하고 제비로 땅을 나눈다", "흰 머리 여호수아가 백성 앞에서 절대 우상을 섬기거나 악한 일을 하면 안 된다고 말한다", "흰 머리 여호수아가 하나님의 행하심이 적힌 율법책을 기록한다", "여호수아가 조용히 생을 마치고, 백성들이 침상 곁과 장막 밖에서 슬퍼하며 애도한다"]'::jsonb, '[["joshua"], ["joshua"], ["god", "joshua"], ["joshua"]]'::jsonb, ARRAY['god', 'joshua']::text[], '[{"book": "수", "from": "23:1", "to": "24:30"}]'::jsonb, -1390, -1390, 'approx', 31, 'exodus_canaan_joshua', '가나안 입성과 여호수아', 3, 'lm_exo_shechem_oak', 'published'),
    ('era_divided_kingdom', '요나: 도망과 바다의 표징', '하나님은 요나에게 니느웨로 가라 하시지만, 요나는 다시스로 도망하다가 큰 폭풍과 물고기 표징을 통해 하나님의 부르심을 피할 수 없음을 배운다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「요나」를 다룹니다.', '["요나가 하나님의 빛 앞에서 선지자 겉옷을 붙잡고 서 있고 요나는 불편하고 두려운 얼굴이다", "요나가 욥바 항구에서 다시스로 가는 배에 오르며 뱃삯 주머니를 건네고, 뱃사람들은 밧줄과 돛을 준비하며 요나는 뒤돌아보지 않으려 한다. 글자는 없다", "큰 폭풍 속에서 뱃사람들이 제비를 뽑고 요나가 부끄러운 얼굴로 자신을 가리키며, 배는 기울고 파도는 높지만 사람의 부상은 보이지 않는다", "요나가 바다에 던져진 뒤 폭풍이 잦아들고, 멀리 큰 물고기가 물 위로 떠오르며 요나를 삼키려 다가온다. 잔혹하거나 무서운 입속 장면은 보이지 않는다"]'::jsonb, '["요나가 하나님의 명령에 불편하고 두려워 한다", "요나가 욥바 항구에서 다시스로 가는 배에 오르며 뱃삯 주머니를 건네다", "큰 폭풍 속에서 뱃사람들이 제비를 뽑고 요나가 부끄러운 얼굴로 자신임을 밝힌다", "요나가 바다에 던져진 뒤 폭풍이 잦아든다, 멀리 큰 물고기가 물 위로 떠오르며 요나를 삼키려 다가온다"]'::jsonb, '[["jonah", "god"], ["jonah"], ["jonah"], ["jonah"]]'::jsonb, ARRAY['jonah', 'god']::text[], '[{"book": "욘", "from": "1:1", "to": "1:17"}]'::jsonb, -760, -760, 'approx', 31, 'divided_two_kingdoms_north_fall', '두 왕국의 흔들림과 북이스라엘의 몰락', 4, 'lm_div_joppa_jonah', 'published'),
    ('era_nt_apostolic', '3차 전도 여행: 마게도냐와 헬라 방문', '에베소 소동 뒤 바울은 마게도냐와 헬라를 방문해 제자들을 권면하고 음모를 피해 다시 마게도냐로 돌아간다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「차 전도 여행」을 다룹니다.', '["소동이 그친 뒤 바울이 제자들을 불러 권면하고 작별하며 얼굴에는 걱정과 사랑이 함께 보인다", "헬라에서 석 달을 머문 바울이 유대인들의 음모를 알고 신중한 표정으로 여정을 바꾼다", "바울의 동역자들이 여러 도시에서 모여 드로아를 향해 먼저 가고 바울은 결심한 얼굴로 뒤따른다"]'::jsonb, '["소동이 그친 뒤 바울이 제자들을 불러 권면하고 작별한다", "헬라에서 석 달을 머문 바울이 유대인들의 음모를 알고 여정을 바꾼다", "바울의 동역자들이 여러 도시에서 모여 드로아를 향해 먼저 가고 바울은 뒤따른다"]'::jsonb, '[["paul"], ["paul"], ["paul", "timothy"]]'::jsonb, ARRAY['paul', 'timothy']::text[], '[{"book": "행", "from": "20:1", "to": "20:6"}]'::jsonb, 56, 57, 'approx', 32, 'paul_third_journey', '바울의 3차 전도 여행', 4, 'lm_nt_ap_philippi', 'published'),
    ('era_nt_public_ministry', '세 번째 수난 예고', '예수님은 예루살렘으로 올라가며 고난과 죽음과 부활을 세 번째로 예고하신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「세 번째 수난 예고」를 다룹니다.', '["예루살렘으로 올라가는 길에서 예수님이 열두 제자를 따로 부르신다", "예수님이 인자가 넘겨지고 조롱과 채찍질과 죽임을 당할 것을 말씀하신다, 그 말의 뜻을 보여 주는 글자 없는 말풍선 안에는 고난의 길과 어두운 언덕에 십자가와 채찍이 있는 모습", "예수님이 사흘 만에 다시 살아날 것을 덧붙이시지만 제자들은 이해하지 못한다"]'::jsonb, '["예루살렘으로 올라가는 길에서 예수님이 열두 제자를 따로 부르신다", "예수님이 인자가 넘겨지고 조롱과 채찍질과 죽임을 당할 것을 말씀하신다", "예수님은 예루살렘으로 올라가며 고난과 죽음과 부활을 세 번째로 예고하신다"]'::jsonb, '[["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["jesus"], ["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"]]'::jsonb, ARRAY['jesus', 'peter', 'andrew', 'james_zebedee', 'john', 'philip', 'bartholomew', 'matthew', 'thomas', 'james_alphaeus', 'thaddaeus', 'simon_zealot', 'judas']::text[], '[{"book": "마", "from": "20:17", "to": "20:19"}, {"book": "막", "from": "10:32", "to": "10:34"}, {"book": "눅", "from": "18:31", "to": "18:34"}]'::jsonb, 33, 33, 'approx', 32, 'journey_teaching_to_jerusalem', '길 위의 가르침과 예루살렘으로', 3, 'lm_nt_pm_perea', 'published'),
    ('era_divided_kingdom', '요나: 니느웨 회개와 하나님의 긍휼', '요나는 니느웨에 심판을 외치고, 니느웨 사람들이 회개하자 하나님은 그 성을 아끼시며 분노한 요나에게 긍휼을 가르치신다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「요나」를 다룹니다.', '["요나가 다시 하나님의 빛 앞에 서고 요나는 먼지 묻은 여행복으로 이번에는 순종하려는 얼굴이다, 하나님의 빛에서 나오는 글자 없는 말풍선 안에는 어두운 길에서 돌아서 밝은 길로 걷는 사람들이 보이는 장면이 작은 그림처럼 보인다", "니느웨 성문 안에서 요나가 사람들에게 심판을 외치며 손을 들고 사람들은 놀라 서로를 바라본다, 그 말의 뜻을 보여 주는 글자 없는 말풍선 안에는 니느웨 사람들이 굵은 베옷을 입고 죄에서 돌이키는 장면이 작은 그림처럼 보인다", "니느웨 왕이 왕복을 벗고 굵은 베옷을 입은 채 재 위에 앉아 회개하고, 성 사람들과 짐승들도 먹기를 멈춘 듯 조용히 서 있다. 글자는 보이지 않는다", "요나가 성 밖 초막 그늘 아래 화난 얼굴로 앉아 있고 박넝쿨은 시들어 있으며, 그 말의 뜻을 보여 주는 글자 없는 말풍선 안에는 어두운 길에서 돌아서 밝은 길로 걷는 사람들이 보이는 장면이 작은 그림처럼 보인다"]'::jsonb, '["요나가 다시 하나님의 빛 앞에 서고 요나는 하나님의 말씀을 듣는다", "니느웨 성문 안에서 요나가 사람들에게 심판을 외치며 손을 들고 사람들은 놀라 서로를 바라본다", "니느웨 왕이 왕복을 벗고 굵은 베옷을 입은 채 재 위에 앉아 회개한다", "요나가 성 밖 초막 그늘 아래 화난 얼굴로 앉아 있고 박넝쿨은 시들어 있다"]'::jsonb, '[["jonah", "god"], ["jonah"], ["jonah"], ["jonah", "god"]]'::jsonb, ARRAY['jonah', 'god']::text[], '[{"book": "욘", "from": "3:1", "to": "4:11"}]'::jsonb, -760, -760, 'approx', 32, 'divided_two_kingdoms_north_fall', '두 왕국의 흔들림과 북이스라엘의 몰락', 4, 'lm_mon_nineveh', 'published'),
    ('era_nt_apostolic', '3차 전도 여행: 드로아의 유두고 사건', '드로아에서 바울이 밤늦게까지 말씀을 전하던 중 유두고가 떨어지지만 다시 살아나 큰 위로가 된다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「차 전도 여행」을 다룹니다.', '["주간 첫날 밤 성도들이 떡을 떼려고 모이고 바울은 떠나기 전 진지한 얼굴로 오래 말씀을 전한다", "창에 걸터앉은 유두고가 졸다가 삼층에서 떨어지고 바울과 사람들은 공포와 충격의 얼굴로 달려간다", "바울이 내려가 유두고를 안고 생명이 있다고 말하자 긴장한 얼굴들이 놀라움으로 바뀐다", "성도들이 살아난 유두고를 데리고 올라와 큰 위로를 받고 바울은 떠나서 멀리 뒷모습만 보이는 모습"]'::jsonb, '["주간 첫날 밤 성도들이 떡을 떼려고 모이고 바울은 떠나기 전 오래 말씀을 전한다", "창에 걸터앉은 유두고가 졸다가 삼층에서 떨어지고 바울과 사람들은 공포와 충격에 빠진다", "바울이 내려가 유두고를 안고 생명이 있다고 말하자 유고가 살아난다", "성도들이 살아난 유두고에게 큰 위로를 받고 바울은 떠난다"]'::jsonb, '[["paul"], ["paul"], ["paul"], ["paul"]]'::jsonb, ARRAY['paul']::text[], '[{"book": "행", "from": "20:7", "to": "20:12"}]'::jsonb, 57, 57, 'approx', 33, 'paul_third_journey', '바울의 3차 전도 여행', 4, 'lm_nt_ap_troas', 'published'),
    ('era_nt_public_ministry', '삭개오', '예수님은 여리고에서 삭개오를 부르시고 그의 집에 머무시며 잃어버린 자를 찾아 구원하러 오셨음을 보이신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「삭개오」를 다룹니다.', '["여리고 길가에 큰 무리가 모이고, 키 작은 부유한 세리장 삭개오가 값비싼 겉옷 자락을 붙잡은 채 돌무화과나무 위로 다급히 올라간다", "예수님이 나무 아래에서 멈추어 올려다보시고, 삭개오는 나뭇가지 사이에서 놀람과 기쁨이 섞인 얼굴로 예수님을 바라본다", "삭개오가 기뻐하며 예수님을 자기 집으로 모시고, 주변 사람들은 세리장의 화려한 집 앞에서 못마땅한 표정으로 수군거린다", "삭개오가 돈주머니와 장부를 내려놓고 가난한 이들을 향해 나눔을 약속하며, 예수님은 따뜻한 얼굴로 그 집에 임한 구원을 선포하신다"]'::jsonb, '["키 작은 부유한 세리장 삭개오가 무화과나무 위로 다급히 올라간다", "예수님이 나무 아래에서 멈추어 올려다보시고, 삭개오에게 내려오라 하신다", "삭개오가 기뻐하며 예수님을 자기 집으로 모시고, 주변 사람들은 못마땅해한다", "삭개오가 돈주머니와 장부를 내려놓고 가난한 이들을 향해 나눔을 약속하고 예수님은 구원을 말씀하신다"]'::jsonb, '[[], ["jesus"], ["jesus"], ["jesus"]]'::jsonb, ARRAY['jesus']::text[], '[{"book": "눅", "from": "19:1", "to": "19:10"}]'::jsonb, 33, 33, 'approx', 33, 'journey_teaching_to_jerusalem', '길 위의 가르침과 예루살렘으로', 3, 'lm_nt_pm_jericho', 'published'),
    ('era_divided_kingdom', '웃시야의 강성함과 교만: 성전 문 앞의 나병', '웃시야는 하나님의 도우심으로 강성해지지만, 교만하여 제사장의 일을 넘보다가 나병으로 낮아진다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「웃시야의 강성함과 교만」을 다룹니다.', '["웃시야, 곧 아사랴가 블레셋과 전쟁하여 가드와 야브네와 아스돗 성들을 무너뜨리고 승리하는 장면. 전투는 먼 거리로 보이며 피와 시신은 보이지 않는다", "여러 나라 사람들이 웃시야에게 조공을 바치고, 웃시야는 예루살렘 성벽 굽이에 망대들을 세워 나라를 굳게 하며, 주변에는 잘 훈련된 군대와 방패와 창이 정돈되어 있는 장면", "성전 문 앞에서 제사장 아사랴와 제사장들이 웃시야를 막으며 왕이 직접 분향하면 안 된다고 손짓하고, 웃시야는 향로를 들고 제사장들에게 분노해 손가락질하며 호통치는 장면", "웃시야 왕의 이마에 나병이 나타나고 그는 괴로워하며 성전에서 물러나 별궁에서 홀로 지내다가 말년을 맞는 장면. 병은 상징적으로만 표현하고 혐오스럽거나 자세한 피부 묘사는 피한다"]'::jsonb, '["웃시야, 곧 아사랴가 블레셋과 전쟁하여 가드와 야브네와 아스돗 성들을 무너뜨리고 승리한다", "여러 나라 사람들이 웃시야에게 조공을 바치고, 예루살렘은 강성해진다", "성전 문 앞에서 제사장 아사랴와 제사장들이 웃시야를 막으며 왕이 직접 분향하면 안 된다고 손짓한다", "교만해진 웃시야는 제사장의 일을 넘보다가 나병으로 낮아진다"]'::jsonb, '[["uzziah"], ["uzziah"], ["uzziah"], ["uzziah", "god"]]'::jsonb, ARRAY['uzziah', 'god']::text[], '[{"book": "왕하", "from": "15:1", "to": "15:7"}, {"book": "대하", "from": "26:1", "to": "26:23"}]'::jsonb, -792, -740, 'approx', 33, 'divided_two_kingdoms_north_fall', '두 왕국의 흔들림과 북이스라엘의 몰락', 4, 'lm_div_jerusalem_uzziah', 'published'),
    ('era_nt_apostolic', '3차 전도 여행: 밀레도에서 에베소 장로들과 작별', '바울은 밀레도에서 에베소 장로들을 불러 자신의 사역과 장차 올 위험을 말하고 눈물로 작별한다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「차 전도 여행」을 다룹니다.', '["바울이 밀레도에 에베소 장로들을 부르고 장로들은 걱정과 존경이 담긴 얼굴로 모인다", "밀레도 바닷가에서 바울이 눈물 어린 얼굴로 두 손을 모으고, 장로들은 결박과 환난의 예고를 들으며 슬프게 둘러선다"]'::jsonb, '["바울이 밀레도에 에베소 장로들을 부르고 장로들은 모인다", "밀레도 바닷가에서 바울이 눈물 어린 얼굴로 두 손을 모으고 장로들은 결박과 환난의 예고를 듣늗다"]'::jsonb, '[["paul"], ["paul"]]'::jsonb, ARRAY['paul']::text[], '[{"book": "행", "from": "20:13", "to": "20:38"}]'::jsonb, 57, 57, 'approx', 34, 'paul_third_journey', '바울의 3차 전도 여행', 4, 'lm_nt_ap_miletus', 'published'),
    ('era_nt_public_ministry', '나사로를 살리심', '예수님은 자신이 부활이요 생명이라고 선포하시고 죽은 나사로를 무덤에서 불러내신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「나사로를 살리심」을 다룹니다.', '["베다니의 마르다와 마리아가 나사로의 죽음으로 슬퍼하고 예수님이 도착하신다", "예수님이 마르다에게 자신이 부활이요 생명이라고 말씀하신다", "예수님이 무덤 앞에서 눈물을 보이시고 돌을 옮기게 하신다", "예수님이 큰 소리로 부르시자 나사로가 수의 천을 감은 채 무덤에서 나오고, 주변 사람들은 놀라 뒤로 물러서며 기뻐한다"]'::jsonb, '["베다니의 마르다와 마리아가 나사로의 죽음으로 슬퍼하고 예수님이 도착하신다", "예수님이 마르다에게 자신이 부활이요 생명이라고 말씀하신다", "예수님이 무덤 앞에서 돌을 옮기게 하신다", "나사로가 수의 천을 감은 채 무덤에서 나온다"]'::jsonb, '[["jesus", "martha", "mary"], ["jesus", "martha"], ["jesus"], ["jesus", "lazarus"]]'::jsonb, ARRAY['jesus', 'lazarus', 'martha', 'mary']::text[], '[{"book": "요", "from": "11:1", "to": "11:44"}]'::jsonb, 32, 33, 'approx', 34, 'journey_teaching_to_jerusalem', '길 위의 가르침과 예루살렘으로', 3, 'lm_nt_pm_bethany', 'published'),
    ('era_divided_kingdom', '북이스라엘 말기 왕들: 반역의 연쇄', '북이스라엘 말기에는 왕들이 악에서 떠나지 못하고, 반역과 앗수르의 압박 속에서 왕위가 빠르게 흔들린다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「북이스라엘 말기 왕들」을 다룹니다.', '["상하 2단 분할 장면: 위 칸에는 북이스라엘 왕 스가랴가 왕좌 옆에 서 있고 신하 살룸이 반역하여 다가오는 모습, 아래 칸에는 한 달 왕 살룸이 왕좌에 앉아 있다가 디르사에서 올라온 므나헴의 반역을 맞는 모습. 피와 시신은 보이지 않는다", "상하 2단 분할 장면: 위 칸에는 므나헴이 사마리아 성전 안 우상들 앞에서 악하게 섬기는 모습, 아래 칸에는 앗수르 군대가 북이스라엘을 압박하자 므나헴이 비굴한 표정으로 은을 넘기고 앗수르 군대가 물러나는 모습", "북이스라엘 왕 브가히야가 왕관을 쓴 채 우상을 섬기고 있는 왕궁 안으로, 군대 장관 베가가 군인 복장과 지휘관 망토를 입고 반역자들과 들어와 왕권을 빼앗는 장면. 브가히야는 크게 놀란 얼굴로 뒤로 물러나고, 공격의 순간은 직접 보이지 않으며 피와 시신은 보이지 않는다", "베가가 북이스라엘 왕이 되어 왕관을 쓰고 우상들 앞에 서 있고, 한쪽에서는 신하 호세아가 왕관 없이 신하 복장을 하고 어두운 표정으로 반역을 준비해 베가의 왕권이 무너질 것을 암시하는 장면. 호세아는 아직 왕이 아니며 피와 시신은 보이지 않는다"]'::jsonb, '["스가랴와 살룸이 반역으로 왕좌를 잃고 이어 므나헴이 반역한다", "북이스라엘 므나헴이 앗수르 군대에게 은을 넘긴다", "브가히야가 왕관을 쓴 채 우상을 섬기고 군대 장관 베가 반역을 일으킨다", "베가가 북이스라엘 왕이 되어 왕관을 쓰고 우상들 앞에 서 있고 호세아가 반역을 준비한다"]'::jsonb, '[["zechariah_king", "shallum", "menahem"], ["menahem"], ["pekahiah", "pekah"], ["pekah", "hoshea_king"]]'::jsonb, ARRAY['zechariah_king', 'shallum', 'menahem', 'pekahiah', 'pekah', 'hoshea_king']::text[], '[{"book": "왕하", "from": "15:8", "to": "15:31"}]'::jsonb, -753, -732, 'approx', 34, 'divided_two_kingdoms_north_fall', '두 왕국의 흔들림과 북이스라엘의 몰락', 4, 'lm_div_samaria_late_kings', 'published'),
    ('era_nt_apostolic', '3차 전도 여행: 두로와 가이사랴를 거쳐 예루살렘으로', '바울은 여러 항구를 지나 가이사랴에 이르고, 아가보의 예언에도 예루살렘으로 갈 뜻을 굽히지 않는다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「차 전도 여행」을 다룹니다.', '["먼지 묻은 여행 망토의 바울 일행이 배를 갈아타며 항구들을 지나고, 제자들은 아쉬운 얼굴로 해변에서 무릎 꿇어 함께 기도한다", "가이사랴에서 전도자 빌립의 집에 머물고 바울은 피곤하지만 평안한 얼굴로 형제들과 교제한다", "예언자 아가보가 바울의 띠로 자기 손발을 묶어서 바울이 잡혀갈거라고 예언하고, 성도들이 눈물로 바울의 예루살렘행을 말리고 바울은 고난을 각오한 얼굴로 선다", "바울이 주 예수의 이름을 위해 죽을 것도 각오했다고 말하고 모두 주의 뜻을 받아들이며 무거운 얼굴로 잠잠해진다"]'::jsonb, '["바울 일행이 배를 갈아타며 항구들을 지나고 제자들과 무릎 꿇어 함께 기도한다", "가이사랴에서 전도자 빌립의 집에 머물고 바울은 피곤하지만 형제들과 교제한다", "아가보가 바울의 띠로 자기 손발을 묶어서 바울이 잡혀갈거라고 예언하고 성도들은 바울의 예루살렘행을 말린다", "바울이 주 예수의 이름을 위해 죽을 것도 각오했다고 말하고 모두 주의 뜻을 받아들인다"]'::jsonb, '[["paul"], ["paul", "philip_evangelist"], ["paul"], ["paul"]]'::jsonb, ARRAY['paul', 'philip_evangelist']::text[], '[{"book": "행", "from": "21:1", "to": "21:16"}]'::jsonb, 57, 57, 'approx', 35, 'paul_third_journey', '바울의 3차 전도 여행', 4, 'lm_nt_ap_caesarea_maritima', 'published'),
    ('era_nt_public_ministry', '베다니에서 향유 부음', '베다니에서 한 여인이 예수님께 값비싼 향유를 붓고, 예수님은 그 일이 자신의 장례를 준비한 아름다운 일이라고 말씀하신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「베다니에서 향유 부음」을 다룹니다.', '["베다니 식탁에서 예수님과 나사로가 앉아 있고 마르다가 음식 그릇을 들고 섬기며, 방 안 사람들은 감사와 경외로 조용히 바라본다", "마리아가 깨뜨린 향유 옥합을 들고 예수님의 발에 값비싼 향유를 붓고 머리털로 닦으며, 향유 냄새 속에서 겸손히 엎드린다", "유다가 돈궤를 움켜쥔 채 향유를 가리키며 낭비라고 항의하고, 방 안 사람들은 향유 냄새 가득한 식탁 옆에서 불편하게 굳어 선다", "예수님이 그 여인의 일을 장례를 준비한 아름다운 일로 받아 주신다"]'::jsonb, '["베다니 식탁에서 예수님과 나사로가 앉아 있고 마르다가 음식 그릇을 들고 섬긴다", "마리아가 깨뜨린 향유 옥합을 들고 예수님의 발에 값비싼 향유를 붓고 머리털로 닦는다", "유다가 돈궤를 움켜쥔 채 향유를 가리키며 낭비라고 항의한다", "예수님이 그 여인의 일을 장례를 준비한 아름다운 일로 받아 주신다"]'::jsonb, '[["jesus", "lazarus", "martha"], ["mary", "jesus"], ["judas"], ["jesus", "mary"]]'::jsonb, ARRAY['jesus', 'mary', 'martha', 'lazarus', 'judas']::text[], '[{"book": "마", "from": "26:6", "to": "26:13"}, {"book": "막", "from": "14:3", "to": "14:9"}, {"book": "요", "from": "12:1", "to": "12:8"}]'::jsonb, 33, 33, 'approx', 35, 'journey_teaching_to_jerusalem', '길 위의 가르침과 예루살렘으로', 3, 'lm_nt_pm_bethany', 'published'),
    ('era_divided_kingdom', '요담: 윗문을 세운 정직한 왕', '요담은 하나님 앞에서 바른 길을 걸으며 성전 윗문을 세우지만, 백성의 부패는 여전히 남아 있다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「요담」을 다룹니다.', '["유다 왕 요담이 예루살렘 성전 윗문을 건축하도록 명령하고, 석공과 일꾼들이 높은 문과 돌벽을 세우며 요담은 경건하고 책임감 있는 표정으로 공사를 살피는 장면, 그 말의 뜻을 보여 주는 글자 없는 말풍선 안에는 무너진 성벽과 성전 돌들이 다시 세워지는 장면이 작은 그림처럼 보인다", "유다 왕 요담이 성전에서 하나님께 겸손히 예배드리고 성전 쪽에는 맑은 거룩한 빛이 비치지만, 멀리 백성들은 작은 산당과 우상 앞에서 여전히 부패하게 섬기는 장면"]'::jsonb, '["유다 왕 요담이 예루살렘 성전 윗문을 건축하도록 명령한다", "유다 왕 요담이 성전에서 하나님께 겸손히 예배드리고 성전 쪽에는 맑은 거룩한 빛이 비치다"]'::jsonb, '[["jotham"], ["jotham", "god"]]'::jsonb, ARRAY['jotham', 'god']::text[], '[{"book": "왕하", "from": "15:32", "to": "15:38"}, {"book": "대하", "from": "27:1", "to": "27:9"}]'::jsonb, -750, -735, 'approx', 35, 'divided_two_kingdoms_north_fall', '두 왕국의 흔들림과 북이스라엘의 몰락', 4, 'lm_div_jerusalem_jotham_gate', 'published'),
    ('era_nt_apostolic', '예루살렘 도착과 야고보 방문', '바울은 예루살렘에 도착해 야고보와 장로들을 만나 이방 사역을 보고하고 정결 예식에 참여한다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「예루살렘 도착과 야고보 방문」을 다룹니다.', '["바울 일행이 예루살렘에 도착하자 형제들이 반가운 얼굴로 영접하고 긴 여정의 피로가 풀린다", "바울이 야고보와 장로들 앞에서 하나님이 이방인 가운데 하신 일을 차분하고 감사한 얼굴로 보고한다", "장로들이 유대인 신자들의 오해를 설명하며 정결 예식에 바울에게 참여하라고 신중한 얼굴로 권한다", "바울이 네 사람과 함께 성전에 들어가 결심한 표정으로 정결 예식을 직접 치른다"]'::jsonb, '["바울 일행이 예루살렘에 도착하자 형제들이 기쁘게 영접한다", "바울이 야고보와 장로들 앞에서 하나님이 이방인 가운데 하신 일을 차분하고 감사한 얼굴로 보고한다", "장로들이 유대인 신자들의 오해를 설명하며 정결 예식에 바울에게 참여하라고 신중한 얼굴로 권한다", "바울이 네 사람과 함께 성전에 들어가 결심한 표정으로 정결 예식을 직접 치른다"]'::jsonb, '[["paul"], ["paul", "james"], ["paul", "james"], ["paul"]]'::jsonb, ARRAY['paul', 'james']::text[], '[{"book": "행", "from": "21:17", "to": "21:26"}]'::jsonb, 57, 57, 'approx', 36, 'paul_arrest_rome_witness', '바울의 체포와 로마 복음 전파', 5, 'lm_nt_ap_jerusalem', 'published'),
    ('era_nt_public_ministry', '예루살렘 입성과 성전 정화', '예수님은 나귀를 타고 예루살렘에 입성하시고 성전을 기도의 집으로 회복시키시며 성전 정화의 의미를 드러내신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「예루살렘 입성과 성전 정화」를 다룹니다.', '["예수님이 나귀를 타고 예루살렘으로 들어오시고 무리가 겉옷과 종려나무 가지를 편다", "예수님이 예루살렘과 백성들을 보시며 평화의 길을 알지 못하는 성을 두고 우신다. 예수님의 말풍선에는 사람들이 눈을 가리고 뒤돌아 서있고, 예수님은 십자가에 달리시는 모습", "성전 뜰에서 예수님이 장사하는 이들을 내쫓고 기도의 집을 더럽히지 말라 하신다."]'::jsonb, '["예수님이 나귀를 타고 예루살렘으로 들어오시고 무리가 겉옷과 종려나무 가지를 편다", "예수님이 예루살렘과 백성들을 보시며 평화의 길을 알지 못하는 성을 두고 우신다", "성전 뜰에서 예수님이 장사하는 이들을 내쫓고 기도의 집을 더럽히지 말라 하신다"]'::jsonb, '[["jesus"], ["jesus"], ["jesus"]]'::jsonb, ARRAY['jesus']::text[], '[{"book": "마", "from": "21:1", "to": "21:17"}, {"book": "막", "from": "11:1", "to": "11:19"}, {"book": "눅", "from": "19:28", "to": "19:48"}]'::jsonb, 33, 33, 'approx', 36, 'passion_week', '고난주간', 4, 'lm_nt_pm_jerusalem', 'published'),
    ('era_divided_kingdom', '이사야의 소명: 거룩한 보좌의 환상', '이사야는 거룩하신 하나님의 보좌 환상 앞에서 자신의 죄를 깨닫고, 정결하게 된 뒤 보내심에 응답한다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「이사야의 소명」을 다룹니다.', '["이사야의 큰 글자 없는 생각 풍선 안에 보이는 환상: 밝은 하나님의 보좌 앞에 이사야 6장 그대로의 스랍들이 정면 구도로 서 있고, 각 스랍의 날개는 정확히 여섯 개만 보인다. 위쪽 한 쌍의 날개 2개는 얼굴과 눈 위를 교차해 완전히 가리고, 아래쪽 한 쌍의 날개 2개는 다리와 발 위를 교차해 가리며, 가운데 한 쌍의 날개 2개만 좌우로 크게 펼쳐져 날 수 있는 모습이다. 날개가 임의로 흩어지거나 추가되지 않는다. 두려워 떠는 이사야에게 한 스랍이 제단에서 가져온 핀 숯을 들고 날아와 이사야의 입술에 조심스럽게 대며 죄가 사해졌음을 상징한다. 숯은 작은 빛으로만 보이고 화상이나 상처는 보이지 않는다", "이사야의 큰 글자 없는 생각 풍선 안에 보이는 환상: 밝은 하나님의 보좌 앞에 이사야가 손을 들며 제가 가겠다고 저를 선택해달라고 외치는 듯한 장면", "이사야의 큰 글자 없는 생각 풍선 안에 보이는 환상: 하나님이 이사야에게 가서 전하라고 명하시며 밝은 빛이 이사야를 향해 뻗고, 보좌 주변의 스랍들은 성경적 형태가 또렷하게 보인다. 각 스랍은 여섯 날개만 가지며, 위쪽 2개는 얼굴과 눈을 가리고, 아래쪽 2개는 다리와 발을 가리고, 가운데 2개는 좌우로 펼쳐져 날 수 있는 자세다. 날개가 머리 위나 몸 아래에 아무렇게나 붙어 있지 않다. 같은 생각 풍선 안쪽 먼 배경에는 사람들이 귀를 막고 눈을 감아 말씀을 듣지 않는 모습과, 성읍과 집들이 황폐해지는 장면이 상징적으로 보인다. 폭력이나 시신은 보이지 않고, 끝에는 잘린 나무 그루터기에서 작은 새싹이 남아 있는 모습이 희망의 표징처럼 보인다, 그 말의 뜻을 보여 주는 글자 없는 말풍선 안에는 열린 하늘과 밝은 보좌 앞에 사람들이 경외하며 엎드리는 장면이 작은 그림처럼 보인다"]'::jsonb, '["두려워 떠는 이사야에게 한 스랍이 제단에서 가져온 핀 숯을 들고 날아와 이사야의 입술 댄다", "이사야는 하나님의 보좌 앞에 자기가 가겠다며 자처한다", "이사야는 하나님에게 성읍들이 황폐해지고 아무도 살지 않고 황무지가 될 때까지 전하라 함을 듣는다"]'::jsonb, '[["isaiah", "god"], ["isaiah", "god"], ["isaiah", "god"]]'::jsonb, ARRAY['isaiah', 'god']::text[], '[{"book": "사", "from": "6:1", "to": "6:13"}]'::jsonb, -740, -740, 'approx', 36, 'divided_two_kingdoms_north_fall', '두 왕국의 흔들림과 북이스라엘의 몰락', 4, 'lm_div_jerusalem', 'published'),
    ('era_nt_public_ministry', '무화과나무와 예수님의 권위 논쟁', '예수님은 열매 없는 무화과나무 사건을 통해 믿음과 열매를 가르치시고 성전에서 권위에 대한 질문을 받으신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「무화과나무와 예수님의 권위 논쟁」을 다룹니다.', '["제자들이 마른 무화과나무를 보고 놀라자 예수님이 믿음과 기도를 가르치신다", "성전 뜰에서 대제사장들과 장로들이 예수님의 권위가 어디서 왔는지 묻는다", "예수님이 요한의 세례를 되물으시자 지도자들이 대답하지 못한다"]'::jsonb, '["제자들이 마른 무화과나무를 보고 놀라자 예수님이 믿음과 기도를 가르치신다", "성전 뜰에서 대제사장들과 장로들이 예수님의 권위가 어디서 왔는지 묻는다", "예수님이 요한의 세례를 되물으시자 지도자들이 대답하지 못한다"]'::jsonb, '[["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["jesus"], ["jesus"]]'::jsonb, ARRAY['jesus', 'peter', 'andrew', 'james_zebedee', 'john', 'philip', 'bartholomew', 'matthew', 'thomas', 'james_alphaeus', 'thaddaeus', 'simon_zealot', 'judas']::text[], '[{"book": "마", "from": "21:18", "to": "21:27"}, {"book": "막", "from": "11:20", "to": "11:33"}, {"book": "눅", "from": "20:1", "to": "20:8"}]'::jsonb, 33, 33, 'approx', 37, 'passion_week', '고난주간', 4, 'lm_nt_pm_jerusalem', 'published'),
    ('era_nt_apostolic', '바울의 성전 체포와 증언', '아시아에서 온 유대인들이 바울을 고발해 성전에서 소동이 일어나고, 바울은 히브리 말로 자신의 회심을 증언한다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「바울의 성전 체포와 증언」을 다룹니다.', '["아시아에서 온 유대인들이 바울을 보고 분노한 얼굴로 무리를 선동하며 성전이 소란해진다", "무리가 바울을 붙잡아 끌어내고, 로마 천부장은 갑옷 입은 군사들과 긴장한 얼굴로 달려와 매 맞는 바울을 군중에게서 떼어 낸다", "먼지와 상처가 남은 바울이 층대 위에서 결박된 손을 들어 손짓하자 무리가 잠잠해지고, 그는 침착한 얼굴로 히브리 말 증언을 시작한다"]'::jsonb, '["아시아에서 온 유대인들이 바울을 보고 무리를 선동하며 성전이 소란해진다", "무리가 바울을 붙잡아 끌어내고, 천부장은 군사들과 달려와 매 맞는 바울을 군중에게서 떼어 낸다", "바울이 층대 위에서 결박된 손을 들어 무리를 잠잠케 하고 침착하게 히브리 말 증언을 시작한다"]'::jsonb, '[["paul"], ["paul"], ["paul"]]'::jsonb, ARRAY['paul']::text[], '[{"book": "행", "from": "21:27", "to": "22:21"}]'::jsonb, 57, 57, 'approx', 37, 'paul_arrest_rome_witness', '바울의 체포와 로마 복음 전파', 5, 'lm_nt_ap_jerusalem', 'published'),
    ('era_divided_kingdom', '아하스의 우상과 다메섹 제단', '아하스는 우상과 두려움 속에서 하나님을 의지하지 않고, 끝내 성전에 이방 제단을 들여놓는다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「아하스의 우상과 다메섹 제단」을 다룹니다.', '["유다 왕 아하스가 성전과 예루살렘 안에 바알 우상들을 가득 세우고, 몰렉 우상 앞 제단 화덕의 불길 앞에서 자기 어린 아들을 두 팔로 들어 올린 채 악한 제사를 막 준비하는 장면. 아이는 불길에 닿지 않고 다치거나 묶여 있지 않으며, 몰렉 우상 자체가 불타는 것이 아니라 우상 앞 제단의 불만 타오른다. 하늘에는 하나님의 분노와 심판을 상징하는 차갑고 날카로운 붉은 금빛과 먹구름이 내려온다. 아이에게 해를 입히는 순간은 보이지 않는다", "아람 왕 르신과 북이스라엘 왕 베가의 군대가 예루살렘 성을 에워싸고, 성 안의 아하스는 겁에 질린 얼굴로 성벽 위에서 포위를 바라보는 장면", "이사야가 윗못 수도 끝 길에서 유다 왕 아하스에게 하나님이 도우시니 두려워하지 말라고 엄중히 전하지만, 아하스는 시선을 피하며 하나님을 의지하지 않겠다는 완고한 표정으로 거절하는 장면", "아하스가 예루살렘 성전 안에서 여호와의 제단(언약궤가 보이는)을 뒤쪽 구석으로 밀어 두고, 그 앞 중앙에는 다메섹에서 본 이방 제단을 크고 화려하게 새로 세워 그 제단에 제사를 드리는 장면. 뒤쪽 여호와의 제단은 단순한 청동 제단과 희미한 금빛으로 작고 밀려난 듯 보이고, 앞쪽 다메섹 제단은 검붉은 돌, 이방 장식 문양, 짙은 연기와 붉은 불빛으로 확연히 다르게 보인다. 아하스는 악하고 고집스러운 얼굴로 이방 제단 앞에 서 있고, 성전 위에는 하나님이 기뻐하지 않으시는 심판을 상징하는 날카로운 붉은 빛이 내려온다"]'::jsonb, '["유다 왕 아하스가 성전과 예루살렘 안에 바알 우상들을 가득 세우고 아이도 제사로 드린다", "아람 왕 르신과 북이스라엘 왕 베가의 군대가 예루살렘 성을 에워싸고 아하스는 겁에 질려있다", "이사야가 윗못 수도 끝 길에서 유다 왕 아하스에게 하나님이 도우시니 두려워하지 말라고 엄중히 전한다", "아하스가 성전에서 여호와의 제단을 밀어 두고 다메섹 제단에 제사한다"]'::jsonb, '[["ahaz", "god"], ["ahaz", "pekah"], ["ahaz", "isaiah", "god"], ["ahaz", "god"]]'::jsonb, ARRAY['ahaz', 'pekah', 'isaiah', 'god']::text[], '[{"book": "왕하", "from": "16:1", "to": "16:20"}, {"book": "대하", "from": "28:1", "to": "28:27"}, {"book": "사", "from": "7:3", "to": "7:12"}]'::jsonb, -735, -732, 'approx', 37, 'divided_two_kingdoms_north_fall', '두 왕국의 흔들림과 북이스라엘의 몰락', 4, 'lm_div_jerusalem_ahaz_altars', 'published'),
    ('era_nt_public_ministry', '두 아들, 악한 농부, 혼인잔치 비유', '예수님은 세 비유로 회개하지 않는 지도자들을 책망하시고 하나님 나라의 초청과 심판을 가르치신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「두 아들, 악한 농부, 혼인잔치 비유」를 다룹니다.', '["예수님이 두 아들의 비유로 말보다 순종이 중요함을 성전 뜰에서 가르치신다. 말풍선에는 세리와 여자들이 엎드려 순종하는 모습", "예수님이 굳은 얼굴의 지도자들에게 말씀하신다. 말풍선에는 악한 농부들이 몽둥이를 들고 포도원 주인의 종을 밀어 넘어뜨리는 장면", "예수님이 혼인잔치 비유를 말씀하신다. 말풍선에는 예식장에 초대받은 사람들이 오지 않아 화난 주최자의 모습"]'::jsonb, '["예수님이 두 아들의 비유로 말보다 순종이 중요함을 성전 뜰에서 가르치신다", "예수님이 지도자들에게 악한 농부에 대해 말씀하신다", "예수님이 혼인잔치 비유를 말씀하신다"]'::jsonb, '[["jesus"], ["jesus"], ["jesus"]]'::jsonb, ARRAY['jesus']::text[], '[{"book": "마", "from": "21:28", "to": "22:14"}, {"book": "막", "from": "12:1", "to": "12:12"}, {"book": "눅", "from": "20:9", "to": "20:19"}]'::jsonb, 33, 33, 'approx', 38, 'passion_week', '고난주간', 4, 'lm_nt_pm_jerusalem', 'published')
)
insert into events (era_id, title, summary, background_context, story_scenes, scene_captions, scene_characters, character_codes, bible_refs, start_year, end_year, time_precision, story_index, unit_code, unit_title, unit_order, landmark_id, status)
select
  e.id,
  s.title,
  s.summary,
  s.background_context,
  s.story_scenes,
  s.scene_captions,
  s.scene_characters,
  s.character_codes,
  s.bible_refs,
  s.start_year,
  s.end_year,
  s.time_precision,
  s.story_index,
  s.unit_code,
  s.unit_title,
  s.unit_order,
  lm.id,
  s.status
from seed_events s
join eras e on e.code = s.era_code
join landmarks lm on lm.code = s.landmark_code
on conflict (era_id, story_index) do update set
  title = excluded.title,
  summary = excluded.summary,
  background_context = excluded.background_context,
  story_scenes = excluded.story_scenes,
  scene_captions = excluded.scene_captions,
  scene_characters = excluded.scene_characters,
  character_codes = excluded.character_codes,
  bible_refs = excluded.bible_refs,
  start_year = excluded.start_year,
  end_year = excluded.end_year,
  time_precision = excluded.time_precision,
  unit_code = excluded.unit_code,
  unit_title = excluded.unit_title,
  unit_order = excluded.unit_order,
  landmark_id = excluded.landmark_id,
  status = excluded.status
;

with seed_events (era_code, title, summary, background_context, story_scenes, scene_captions, scene_characters, character_codes, bible_refs, start_year, end_year, time_precision, story_index, unit_code, unit_title, unit_order, landmark_code, status) as (
  values
    ('era_nt_apostolic', '로마 시민권과 산헤드린 변론', '바울은 로마 시민권으로 매질을 피하고 산헤드린 앞에서 부활 소망을 말한 뒤 주님의 격려를 받는다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「로마 시민권과 산헤드린 변론」을 다룹니다.', '["무리가 바울을 죽이라고 외치고 천부장이 채찍질하려 하자 바울은 긴장 속에서도 침착한 얼굴로 로마 시민권을 밝힌다", "바울이 부활 소망 때문에 심문받는다고 말하자 바리새인과 사두개인이 서로 격한 얼굴로 다툰다", "그날 밤 주께서 바울 곁에 서서 담대하라 하시고 바울은 외로움 속에서도 새 용기를 얻은 얼굴로 앉아 있다"]'::jsonb, '["무리가 바울을 죽이라고 외치고 천부장이 채찍질하려 하자 바울은 로마 시민권을 밝힌다", "바울이 부활 소망 때문에 심문받는다고 말하자 바리새인과 사두개인이 격하게 반대한다", "그날 밤 주께서 바울 곁에 서서 담대하라 하시고 바울은 새 용기를 얻는다"]'::jsonb, '[["paul"], ["paul"], ["paul"]]'::jsonb, ARRAY['paul']::text[], '[{"book": "행", "from": "22:22", "to": "23:11"}]'::jsonb, 57, 57, 'approx', 38, 'paul_arrest_rome_witness', '바울의 체포와 로마 복음 전파', 5, 'lm_nt_ap_jerusalem', 'published'),
    ('era_divided_kingdom', '아하스와 임마누엘: 믿음의 징조', '아하스는 두 왕의 위협 앞에서 흔들리지만, 하나님은 이사야를 통해 굳게 믿으라는 말씀과 임마누엘의 징조를 주신다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「아하스와 임마누엘」을 다룹니다.', '["아람 왕 르신의 군대와 북이스라엘 베가의 군대가 함께 예루살렘을 위협한다는 소식이 아하스 왕에게 전해지고, 아하스 왕과 백성의 마음이 숲이 바람에 흔들리듯 왕궁 안에서 두려워 떨고 있다", "아하스가 이사야 앞에서 망설이며 뒤로 물러나고, 손은 왕복을 붙잡고 눈치를 보며 하나님께 징조를 구하지 않겠다는 태도를 보인다. 뒤편에는 사람의 정치 계산과 군사 동맹을 상징하는 작은 지도와 병사 그림이 있고, 하늘의 빛은 외면당한다", "하나님의 빛이 이사야를 통해 아하스에게 임마누엘의 징조를 전한다. 큰 글자 없는 말풍선 안에는 젊은 여인이 아기를 안고 있고, 아기 곁에는 뻐터와 꿀, 악을 버리고 선을 택하는 두 길의 상징, 멀리 두 왕의 땅이 비어 가는 그림이 함께 보인다"]'::jsonb, '["아람 왕 르신의 군대와 북이스라엘 베가의 군대가 함께 예루살렘을 위협한다는 소식이 아하스 왕에게 전해진다", "아하스가 하나님께 구하지 않겠다며 사람에 의지하려 하는 모습이 보인다", "하나님의 빛이 이사야를 통해 아하스에게 임마누엘의 징조를 전한다"]'::jsonb, '[["ahaz"], ["isaiah", "ahaz"], ["god", "isaiah", "ahaz"]]'::jsonb, ARRAY['isaiah', 'ahaz', 'god']::text[], '[{"book": "사", "from": "7:1", "to": "7:25"}]'::jsonb, -735, -735, 'approx', 38, 'divided_two_kingdoms_north_fall', '두 왕국의 흔들림과 북이스라엘의 몰락', 4, 'lm_div_jerusalem', 'published'),
    ('era_nt_apostolic', '바울 암살 음모와 가이사랴 이송', '바울을 죽이려는 음모가 드러나자 천부장은 군사 호위를 붙여 밤중에 바울을 가이사랴로 보낸다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「바울 암살 음모와 가이사랴 이송」을 다룹니다.', '["유대인들이 바울을 죽이기 전에는 먹지도 마시지도 않겠다고 맹세하며 음모를 꾸민다", "바울의 생질이 걱정스러운 얼굴로 천부장에게 몰래 들어가 암살 계획을 알린다", "천부장이 군사와 기병을 준비시키고, 결박된 바울은 밤중에 긴장하지만 침착한 얼굴로 로마 호위를 받으며 가이사랴로 떠난다", "가이사랴에서 벨릭스가 편지를 읽고, 결박된 바울은 헤롯 궁 안에서 지켜지며 다음 재판을 기다린다"]'::jsonb, '["유대인들이 바울을 죽이기 전에는 먹지도 마시지도 않겠다고 맹세하며 음모를 꾸민다", "바울의 생질이 걱정스러운 얼굴로 천부장에게 몰래 들어가 암살 계획을 알린다", "천부장은 군사 호위를 붙여 밤중에 바울을 가이사랴로 보낸다", "가이사랴에서 벨릭스가 편지를 읽는다, 결박된 바울은 헤롯 궁 안에서 지켜지며 다음 재판을 기다린다"]'::jsonb, '[["paul"], ["paul"], ["paul"], ["paul"]]'::jsonb, ARRAY['paul']::text[], '[{"book": "행", "from": "23:12", "to": "23:35"}]'::jsonb, 57, 57, 'approx', 39, 'paul_arrest_rome_witness', '바울의 체포와 로마 복음 전파', 5, 'lm_nt_ap_caesarea_maritima', 'published'),
    ('era_nt_public_ministry', '세금과 부활과 가장 큰 계명 논쟁', '예수님은 가이사에게 세금 바치는 문제, 부활 논쟁, 가장 큰 계명 질문에 지혜롭게 답하신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「세금과 부활과 가장 큰 계명 논쟁」을 다룹니다.', '["지도자들이 세금 문제로 예수님을 시험하고 예수님은 동전을 보이며 답하신다", "사두개인들이 부활을 두고 묻자 예수님은 살아 있는 자의 하나님을 말씀하신다", "한 서기관이 가장 큰 계명을 묻고 예수님은 하나님 사랑과 이웃 사랑을 밝히신다", "무리가 예수님의 지혜로운 대답에 놀라며 더 이상 쉽게 묻지 못한다"]'::jsonb, '["지도자들이 세금 문제로 예수님을 시험하고 예수님은 동전을 보이며 답하신다", "사두개인들이 부활을 두고 묻자 예수님은 살아 있는 자의 하나님을 말씀하신다", "한 서기관이 가장 큰 계명을 묻고 예수님은 하나님 사랑과 이웃 사랑을 밝히신다", "무리가 예수님의 지혜로운 대답에 놀라며 더 이상 쉽게 묻지 못한다"]'::jsonb, '[["jesus"], ["jesus"], ["jesus"], ["jesus"]]'::jsonb, ARRAY['jesus']::text[], '[{"book": "마", "from": "22:15", "to": "22:40"}, {"book": "막", "from": "12:13", "to": "12:34"}, {"book": "눅", "from": "20:20", "to": "20:40"}]'::jsonb, 33, 33, 'approx', 39, 'passion_week', '고난주간', 4, 'lm_nt_pm_jerusalem', 'published'),
    ('era_divided_kingdom', '호세아의 몰락: 사마리아가 함락되다', '북이스라엘의 마지막 왕 호세아는 앗수르에 반역하다 붙잡히고, 사마리아는 함락되어 백성이 포로로 끌려간다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「호세아의 몰락」을 다룹니다.', '["사마리아 성 밖, 앗수르 왕 살만에셀이 많은 군대와 병거를 이끌고 호세아 왕을 잡으러 올라오고, 성벽 위의 호세아 왕은 두려움과 긴장 속에 바라보는 장면", "앗수르 왕이 호세아 왕의 배반을 알고 그를 붙잡아 어두운 감옥에 가둔 모습. 호세아는 왕복이 흐트러진 채 침울하게 앉아 있고, 피와 폭력은 보이지 않는다", "사마리아 성이 함락되고, 이스라엘 사람들이 가족과 짐을 들고 앗수르 병사들에게 이끌려 먼 앗수르 땅으로 끌려가는 장면. 북이스라엘 왕국이 끝났다는 침통한 분위기이며, 피와 시신은 보이지 않는다"]'::jsonb, '["사마리아 성 밖, 앗수르 왕 살만에셀이 많은 군대와 병거를 이끌고 호세아 왕을 잡으러 올라온다", "앗수르 왕이 호세아 왕의 배반을 알고 그를 붙잡아 어두운 감옥에 가둔다", "북이스라엘의 마지막 왕 호세아는 앗수르에 반역하다 붙잡히고, 사마리아는 함락되어 백성이 포로로 끌려간다"]'::jsonb, '[["hoshea_king"], ["hoshea_king"], []]'::jsonb, ARRAY['hoshea_king']::text[], '[{"book": "왕하", "from": "17:1", "to": "17:6"}]'::jsonb, -724, -722, 'approx', 39, 'divided_two_kingdoms_north_fall', '두 왕국의 흔들림과 북이스라엘의 몰락', 4, 'lm_div_samaria', 'published'),
    ('era_nt_apostolic', '벨릭스 앞 재판', '바울은 벨릭스 앞에서 고발을 반박하고 의와 절제와 심판을 말하지만 벨릭스는 결정을 미룬다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「벨릭스 앞 재판」을 다룹니다.', '["대제사장 편 사람들이 벨릭스 앞에서 바울을 고발하고 바울은 차분하지만 굳은 얼굴로 듣는다", "바울이 하나님과 사람 앞에서 양심을 따라 힘쓴다고 변론하며 당당한 표정으로 서 있다", "벨릭스의 뒤를 이어 베스도가 총독이 되고, 두 해가 지나도록 바울이 감금되어 있지만 그는 낙심보다 인내가 담긴 얼굴로 기다린다"]'::jsonb, '["대제사장 편 사람들이 벨릭스 앞에서 바울을 고발한다", "바울이 하나님과 사람 앞에서 양심을 따라 힘쓴다고 변론한다", "벨릭스의 뒤를 이어 베스도가 총독이 되고, 두 해가 지나도록 바울이 감금된다"]'::jsonb, '[["paul"], ["paul"], ["paul"]]'::jsonb, ARRAY['paul']::text[], '[{"book": "행", "from": "24:1", "to": "24:27"}]'::jsonb, 57, 59, 'approx', 40, 'paul_arrest_rome_witness', '바울의 체포와 로마 복음 전파', 5, 'lm_nt_ap_caesarea_maritima', 'published'),
    ('era_nt_public_ministry', '서기관과 바리새인 책망', '예수님은 외식하는 서기관과 바리새인을 책망하시고 예루살렘을 향한 탄식을 남기신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「서기관과 바리새인 책망」을 다룹니다.', '["예수님이 무리와 제자들에게 말만 하고 행하지 않는 지도자들의 모습을 경계하라 하신다", "예수님이 성전 들에서 자신들이 지도자라 불리는 것을 좋아하는 사람들을 책망하신다", "성전 뜰의 사람들 앞에서 겉은 아름다우나 속은 무너진 신앙의 위험이 드러난다", "예수님이 예루살렘이 황폐하게 될 것임을 선포하신다"]'::jsonb, '["예수님이 무리와 제자들에게 말만 하고 행하지 않는 지도자들의 모습을 경계하라 하신다", "예수님이 성전 들에서 자신들이 지도자라 불리는 것을 좋아하는 사람들을 책망하신다", "성전 뜰의 사람들 앞에서 겉은 아름다우나 속은 무너진 신앙의 위험이 드러난다", "예수님이 예루살렘이 황폐하게 될 것임을 선포하신다"]'::jsonb, '[["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["jesus"], ["jesus"], ["jesus"]]'::jsonb, ARRAY['jesus', 'peter', 'andrew', 'james_zebedee', 'john', 'philip', 'bartholomew', 'matthew', 'thomas', 'james_alphaeus', 'thaddaeus', 'simon_zealot', 'judas']::text[], '[{"book": "마", "from": "23:1", "to": "23:39"}, {"book": "막", "from": "12:38", "to": "12:40"}, {"book": "눅", "from": "20:45", "to": "20:47"}]'::jsonb, 33, 33, 'approx', 40, 'passion_week', '고난주간', 4, 'lm_nt_pm_jerusalem', 'published'),
    ('era_divided_kingdom', '히스기야와 산헤립: 두려움의 편지', '포위 속에서 히스기야는 편지를 성전에 펼치고 하나님께 매달린다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「히스기야와 산헤립」을 다룹니다.', '["앗시리아왕 산헤립이 히스기야에게 조공을 요구하고 히스기야는 은 300달란트와 금 30달란트를 전달하는 비참한 모습", "앗수르 랍사게가 예루살렘 성벽 밖에서 히스기야의 신하들을 조롱하며 손을 치켜들고, 성 안에서 히스기야가 왕복을 찢고 굵은 베옷을 입은 채 하나님께 성전 안에서 예배드리고 하나님의 빛이 조용히 히스기야에게 비친다", "이사야가 성전으로 와서 히스기야에게 하나님의 말씀을 전하는 장면. 이사야의 말풍선에는 하나님이 진노가 적군들에게 임하고 물리치시는 모습", "앗수르 군대가 밤사이 두려움에 흩어진 듯 빈 진영과 쓰러진 장비만 남고, 히스기야와 백성은 성벽 위에서 조용한 경외로 하나님께 감사한다. 시신과 잔혹 묘사는 없다"]'::jsonb, '["앗시리아왕 산헤립이 히스기야에게 조공을 요구하고 히스기야는 은 300달란트와 금 30달란트를 전달한다", "앗수르 랍사게가 예루살렘 성벽 밖에서 조롱하며 손을 치켜들고 히스기야는 기도한다", "이사야가 성전으로 와서 히스기야에게 하나님의 말씀(적군을 물리치심)을 전한다", "앗수르 군대가 밤사이 두려움에 흩어지고 빈 진영과 쓰러진 장비만 남는다"]'::jsonb, '[["hezekiah"], ["hezekiah", "god"], ["isaiah", "hezekiah"], ["hezekiah"]]'::jsonb, ARRAY['hezekiah', 'isaiah']::text[], '[{"book": "왕하", "from": "18:13", "to": "19:37"}, {"book": "사", "from": "37:1", "to": "37:38"}]'::jsonb, -701, -701, 'approx', 40, 'divided_judah_final_fall', '남유다의 마지막 회복과 멸망', 5, 'lm_div_jerusalem', 'published'),
    ('era_nt_public_ministry', '감람산 종말 담화', '예수님은 성전 파괴와 장차 올 환난, 깨어 있음과 충성된 종의 삶을 감람산에서 가르치신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「감람산 종말 담화」를 다룹니다.', '["제자들이 성전의 웅장함을 말하자 예수님은 돌 하나도 남지 않을 날을 예고하신다", "감람산에 앉으신 예수님이 제자들에게 징조와 환난과 인자의 오심을 말씀하신다", "예수님이 무화과나무와 깨어 있는 종의 비유로 준비된 삶을 가르치신다", "예수님이 열 처녀와 달란트와 양과 염소의 비유를 말씀하시고 제자들은 마지막 책임을 무겁게 받아들이는 얼굴로 듣는다"]'::jsonb, '["제자들이 성전의 웅장함을 말하자 예수님은 돌 하나도 남지 않을 날을 예고하신다", "감람산에 앉으신 예수님이 제자들에게 징조와 환난과 인자의 오심을 말씀하신다", "예수님이 무화과나무와 깨어 있는 종의 비유로 준비된 삶을 가르치신다", "예수님은 열 처녀와 달란트와 양과 염소의 비유를 말씀하시고 제자들은 듣는다"]'::jsonb, '[["jesus", "peter", "andrew", "james_zebedee", "john"], ["jesus"], ["jesus"], ["jesus"]]'::jsonb, ARRAY['jesus', 'peter', 'andrew', 'james_zebedee', 'john']::text[], '[{"book": "마", "from": "24:1", "to": "25:46"}, {"book": "막", "from": "13:1", "to": "13:37"}, {"book": "눅", "from": "21:5", "to": "21:38"}]'::jsonb, 33, 33, 'approx', 41, 'passion_week', '고난주간', 4, 'lm_nt_pm_gethsemane', 'published'),
    ('era_nt_apostolic', '베스도 앞 재판과 가이사 상소', '베스도 앞에서 바울은 예루살렘 재판을 거절하고 가이사에게 상소하며, 아그립바가 그의 말을 듣게 된다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「베스도 앞 재판과 가이사 상소」를 다룹니다.', '["유대 지도자들이 베스도에게 바울을 예루살렘으로 보내 달라 요청하고 베스도는 신중한 얼굴로 듣는다", "바울이 가이사랴 법정에서 아무 죄가 없다고 차분히 변론하고 베스도는 날카로운 눈빛으로 심문한다", "베스도가 아그립바 왕에게 바울 사건을 설명하고 아그립바는 호기심 어린 얼굴로 듣기를 원한다"]'::jsonb, '["유대 지도자들이 베스도에게 바울을 예루살렘으로 보내 달라 요청하고 베스도에게 요청한다", "바울이 가이사랴 법정에서 아무 죄가 없다고 차분히 변론하고 베스도는 심문한다", "베스도가 아그립바 왕에게 바울 사건을 설명하고 아그립바는 호기심 어린 얼굴로 듣기를 원한다"]'::jsonb, '[["paul", "festus"], ["paul", "festus"], ["festus", "agrippa"]]'::jsonb, ARRAY['paul', 'festus', 'agrippa']::text[], '[{"book": "행", "from": "25:1", "to": "25:27"}]'::jsonb, 59, 59, 'approx', 41, 'paul_arrest_rome_witness', '바울의 체포와 로마 복음 전파', 5, 'lm_nt_ap_caesarea_maritima', 'published'),
    ('era_divided_kingdom', '히스기야의 병과 바벨론 사신', '회복 이후의 자랑은 또 다른 위기를 예고한다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「히스기야의 병과 바벨론 사신」을 다룹니다.', '["병든 히스기야가 침상에서 얼굴을 벽으로 돌리고 눈물로 기도하는 모습이 보인다", "이사야가 다시 왕궁에 들어와 병든 히스기야에게 회복의 말씀을 전하고, 그 말의 뜻을 보여 주는 글자 없는 말풍선 안에는 병상에서 벽을 향해 기도하는 왕과 하나님이 들으시는 장면이 나온다", "해 그림자가 계단에서 뒤로 물러나는 표징을 히스기야와 신하들이 놀라 바라보고, 이사야는 조용히 하나님의 능력을 가리킨다", "회복된 히스기야가 바벨론 사신들에게 보물창고와 무기고를 모두 보여 주고, 이사야는 뒤에서 근심스러운 얼굴로 그 교만한 선택을 지켜본다"]'::jsonb, '["병든 히스기야가 침상에서 얼굴을 벽으로 돌리고 눈물로 기도하는 모습이 보인다", "이사야가 다시 왕궁에 들어와 병든 히스기야에게 회복의 말씀을 전한다", "해 그림자가 계단에서 뒤로 물러나는 표징을 히스기야와 신하들이 놀라 바라본다", "회복된 히스기야가 바벨론 사신들에게 보물창고와 무기고를 자랑하고, 이사야는 근심한다"]'::jsonb, '[["hezekiah"], ["isaiah", "hezekiah"], ["isaiah", "hezekiah"], ["hezekiah", "isaiah"]]'::jsonb, ARRAY['hezekiah', 'isaiah']::text[], '[{"book": "왕하", "from": "20:1", "to": "20:19"}, {"book": "사", "from": "38:1", "to": "39:8"}]'::jsonb, -700, -700, 'approx', 41, 'divided_judah_final_fall', '남유다의 마지막 회복과 멸망', 5, 'lm_div_jerusalem', 'published'),
    ('era_divided_kingdom', '므낫세의 낮아짐: 포로에서 회개로', '므낫세는 성전을 우상으로 더럽히지만, 포로의 낮아짐 속에서 하나님께 돌이켜 다시 우상을 제거한다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「므낫세의 낮아짐」을 다룹니다.', '["유다 왕 므낫세가 예루살렘 성전 안팎에 우상의 제단들을 세우고, 몰렉 우상 앞 제단 화덕의 불길 앞에서 자기 어린 아들을 제물로 바치려는 악한 의식을 준비하는 장면. 몰렉 우상 자체가 불타는 것이 아니라 우상 앞 제단의 불만 타오르고, 성전 위 하늘에는 하나님의 분노와 심판을 상징하는 차갑고 날카로운 붉은 금빛, 먹구름, 번개 같은 엄중한 빛이 내려온다. 아이의 고통이나 죽음은 직접 보이지 않는다", "앗수르 군대가 므낫세와 그의 군대를 사로잡아, 므낫세의 코에는 포로의 고리와 청동 사슬이 걸려 있고, 그는 패배한 얼굴로 바벨론을 향해 끌려가는 장면. 피와 고문 장면은 보이지 않는다", "하나님의 보호와 응답으로 므낫세가 초라하고 낮아진 모습으로 다시 예루살렘 성문으로 돌아오며, 그는 왕의 교만을 잃고 하나님 앞에 깊이 회개한 표정으로 서 있는 장면", "므낫세가 예루살렘 성전 안의 우상들과 이방 제단들을 치우고 부수며, 백성들도 함께 우상을 버리고 하나님만 섬기도록 돌아서는 장면. 성전에는 회복의 밝은 빛이 비친다"]'::jsonb, '["유다 왕 므낫세가 예루살렘 성전 안팎에 우상의 제단들을 세운다", "앗수르 군대가 므낫세와 그의 군대를 사로잡아, 므낫세의 코에는 포로의 고리와 청동 사슬이 걸려 있다", "하나님의 보호와 응답으로 므낫세가 초라하고 낮아진 모습으로 다시 회개한다", "므낫세가 예루살렘 성전 안의 우상들과 이방 제단들을 치우고 부수다"]'::jsonb, '[["manasseh", "god"], ["manasseh"], ["manasseh", "god"], ["manasseh", "god"]]'::jsonb, ARRAY['manasseh', 'god']::text[], '[{"book": "왕하", "from": "21:1", "to": "21:18"}, {"book": "대하", "from": "33:1", "to": "33:20"}]'::jsonb, -697, -642, 'approx', 42, 'divided_judah_final_fall', '남유다의 마지막 회복과 멸망', 5, 'lm_div_jerusalem_manasseh', 'published'),
    ('era_nt_apostolic', '아그립바 왕 앞 변론', '바울은 아그립바 앞에서 회심과 사명을 증언하고 모든 사람이 자신처럼 되기를 바란다고 말한다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「아그립바 왕 앞 변론」을 다룹니다.', '["아그립바와 베스도가 위엄 있게 앉고 바울은 결박된 손을 들며 침착하고 담대한 얼굴로 변론을 시작한다", "바울이 다메섹 길의 빛과 예수님의 부르심을 말하며 회개의 증언을 진지하게 이어 간다", "베스도가 재판석에서 몸을 앞으로 내밀며 바울을 향해 손을 들고 네가 미쳤다고 말하지만, 바울은 결박된 손을 낮추지 않은 채 침착하게 맞선다", "아그립바가 거의 설득되었다고 말하고 바울은 결박 외에는 모두 자신처럼 되기를 바란다는 간절한 얼굴을 보인다"]'::jsonb, '["아그립바와 베스도가 위엄 있게 앉고 바울은 결박된 손을 들며 침착하고 담대한 얼굴로 변론을 시작한다", "바울이 다메섹 길의 빛과 예수님의 부르심을 말하며 회개의 증언을 진지하게 이어 간다", "베스도가 재판석에서 몸을 앞으로 내밀며 바울을 향해 손을 들고 네가 미쳤다고 말한다", "바울은 아그립바 앞에서 회심과 사명을 증언하고 모든 사람이 자신처럼 되기를 바란다고 말한다"]'::jsonb, '[["paul", "agrippa", "festus"], ["paul"], ["paul", "festus"], ["paul", "agrippa"]]'::jsonb, ARRAY['paul', 'festus', 'agrippa']::text[], '[{"book": "행", "from": "26:1", "to": "26:32"}]'::jsonb, 59, 59, 'approx', 42, 'paul_arrest_rome_witness', '바울의 체포와 로마 복음 전파', 5, 'lm_nt_ap_caesarea_maritima', 'published'),
    ('era_nt_public_ministry', '유다의 배신과 마지막 만찬', '유다는 예수님을 넘길 마음을 품고, 예수님은 마지막 만찬에서 새 언약과 섬김, 사랑과 보혜사 약속을 가르치신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「유다의 배신과 마지막 만찬」을 다룹니다.', '["유다가 어두운 뜰에서 대제사장들과 몰래 만나 은전 주머니를 바라보며 예수님을 넘길 기회를 의논하고, 얼굴에는 망설임과 탐욕이 함께 비친다", "예수님이 허리에 수건을 두르고 물대야 앞에 무릎 꿇어 제자들의 먼지 묻은 발을 씻기시며, 제자들은 당황과 부끄러움으로 서로를 바라본다", "유월절 다락방의 낮은 식탁에서 예수님이 예수님을 팔 자가 있다고 말하자 제자들이 놀라며 쳐다본다. 유다 위에는 어두운 영이 있다.", "유다가 떠난 뒤 예수님이 남은 제자들을 위해 위로와 기도를 남기시고, 기름등잔 아래 제자들은 슬픔과 사랑이 뒤섞인 얼굴로 듣는다"]'::jsonb, '["유다가 어두운 뜰에서 대제사장들과 몰래 만나 은전 주머니를 바라보며 예수님을 넘길 기회를 의논한다", "예수님이 허리에 수건을 두르고 물대야 앞에 무릎 꿇어 제자들의 먼지 묻은 발을 씻기시다", "유월절 다락방의 낮은 식탁에서 예수님이 예수님을 팔 자가 있다고 말하자 제자들이 놀라며 쳐다본다", "유다가 떠난 뒤 예수님이 남은 제자들을 위해 위로와 기도를 남기시다"]'::jsonb, '[["judas"], ["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot", "judas"], ["jesus", "judas"], ["jesus"]]'::jsonb, ARRAY['jesus', 'judas', 'peter', 'andrew', 'james_zebedee', 'john', 'philip', 'bartholomew', 'matthew', 'thomas', 'james_alphaeus', 'thaddaeus', 'simon_zealot']::text[], '[{"book": "마", "from": "26:14", "to": "26:30"}, {"book": "막", "from": "14:10", "to": "14:26"}, {"book": "눅", "from": "22:3", "to": "22:38"}, {"book": "요", "from": "13:1", "to": "13:38"}]'::jsonb, 33, 33, 'approx', 42, 'passion_week', '고난주간', 4, 'lm_nt_pm_jerusalem', 'published'),
    ('era_nt_public_ministry', '겟세마네 기도와 체포', '예수님은 겟세마네에서 아버지의 뜻에 자신을 맡기시고, 유다의 배신과 무리의 체포를 순순히 맞으신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「겟세마네 기도와 체포」를 다룹니다.', '["겟세마네 동산의 밤, 예수님이 베드로와 야고보와 요한을 가까이 데리고 몹시 슬퍼하는 얼굴로 깨어 있으라 하시고 세 제자는 무거운 눈꺼풀로 힘겨워한다", "예수님이 올리브나무 아래 홀로 엎드려 땀과 눈물이 맺힌 얼굴로 아버지의 뜻이 이루어지기를 간절히 기도하신다", "유다가 횃불과 몽둥이와 칼을 든 무리를 이끌고 와 입맞춤으로 예수님을 넘기고, 제자들은 잠에서 깨어 두려움에 뒤로 물러선다", "베드로가 칼을 든 손을 멈춘 채 서 있고, 예수님은 차분하고 단호한 얼굴로 칼을 거두게 하시며 자신을 잡으러 온 사람들에게 순순히 나아가신다"]'::jsonb, '["겟세마네 동산에서 예수님은 기도하시고 제자들은 졸고 있다", "예수님은 겟세마네에서 아버지의 뜻에 자신을 맡기는 기도를 하신다", "유다가 횃불과 몽둥이와 칼을 든 무리를 이끌고 와 입맞춤으로 예수님을 넘긴다", "베드로가 칼을 든 손을 예수님은 멈추신다"]'::jsonb, '[["jesus", "peter", "james_zebedee", "john"], ["jesus"], ["judas", "jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "thomas", "james_alphaeus", "thaddaeus", "simon_zealot"], ["jesus", "peter"]]'::jsonb, ARRAY['jesus', 'peter', 'james_zebedee', 'john', 'judas', 'andrew', 'philip', 'bartholomew', 'matthew', 'thomas', 'james_alphaeus', 'thaddaeus', 'simon_zealot']::text[], '[{"book": "마", "from": "26:36", "to": "26:56"}, {"book": "막", "from": "14:32", "to": "14:52"}, {"book": "눅", "from": "22:39", "to": "22:53"}, {"book": "요", "from": "18:1", "to": "18:12"}]'::jsonb, 33, 33, 'approx', 43, 'passion_week', '고난주간', 4, 'lm_nt_pm_gethsemane', 'published'),
    ('era_nt_apostolic', '로마행 항해와 폭풍', '바울은 로마로 가는 배에서 큰 폭풍을 만나지만 하나님의 약속을 붙들고 사람들을 격려하며 모두 살아남는다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「로마행 항해와 폭풍」을 다룹니다.', '["바울이 죄수들과 함께 로마행 배에 오르고 백부장과 선원들은 긴 항해를 앞두고 조심스러운 얼굴이다", "유라굴로 광풍이 배를 덮치자 선원들과 죄수들은 두려움에 질린 얼굴로 짐을 바다에 던진다", "바울이 하나님의 사자가 전한 약속을 말하며 두려워하지 말라고 담대한 얼굴로 사람들을 격려한다", "배가 부서지는 가운데 바울과 사람들, 군사들이 널조각을 붙잡고 물로 뛰어들어 육지에 다다른다"]'::jsonb, '["바울이 죄수들과 함께 로마행 배에 오르고 백부장과 선원들은 긴 항해를 준비한다", "유라굴로 광풍이 배를 덮치자 선원들과 죄수들이 짐을 바다에 던진다", "바울이 하나님의 사자가 전한 약속을 말하며 두려워하지 말라고 사람들을 격려한다", "배가 부서지는 가운데 바울과 사람들, 군사들이 널조각을 붙잡고 물로 뛰어들어 육지에 다다른다"]'::jsonb, '[["paul"], ["paul"], ["paul"], ["paul"]]'::jsonb, ARRAY['paul']::text[], '[{"book": "행", "from": "27:1", "to": "27:44"}]'::jsonb, 59, 60, 'approx', 43, 'paul_arrest_rome_witness', '바울의 체포와 로마 복음 전파', 5, 'lm_nt_ap_crete', 'published'),
    ('era_divided_kingdom', '아몬: 짧은 악의 통치', '아몬은 아버지의 악한 길을 따르지만 회개하지 않고, 짧은 통치 끝에 반역으로 무너진다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「아몬」을 다룹니다.', '["유다 왕 아몬이 예루살렘 성전 안에서 우상들 앞에 서서 완고한 표정으로 섬기고, 주변 신하들은 불안하게 바라보는 장면", "예루살렘 왕궁 안에서 아몬이 자기 신하들의 배신을 당해 쓰러지는 긴장된 장면. 공격의 순간과 피와 상처와 시신의 세부 묘사는 보이지 않는다"]'::jsonb, '["유다 왕 아몬이 예루살렘 성전 안에서 우상들 앞에 서다", "예루살렘 왕궁 안에서 아몬이 자기 신하들에게 배신을 당해 쓰러진다"]'::jsonb, '[["amon_judah"], ["amon_judah"]]'::jsonb, ARRAY['amon_judah']::text[], '[{"book": "왕하", "from": "21:19", "to": "21:26"}, {"book": "대하", "from": "33:21", "to": "33:25"}]'::jsonb, -642, -640, 'approx', 43, 'divided_judah_final_fall', '남유다의 마지막 회복과 멸망', 5, 'lm_div_jerusalem_amon', 'published'),
    ('era_nt_apostolic', '몰타 난파와 로마 사역', '바울은 몰타에서 보호를 받고 병자를 고친 뒤 로마에 도착해 담대히 하나님 나라와 예수님을 전한다.', '사도행전 시대는 예루살렘 교회에서 시작해 지중해 지역으로 이어진 시기입니다. 이 이야기는 「몰타 난파와 로마 사역」을 다룹니다.', '["몰타 섬 사람들이 바닷물에 젖은 바울 일행을 불쌍히 여겨 불을 피워 주고, 모두 지친 얼굴로 몸을 녹인다", "독사가 바울의 손에 매달리지만 바울이 침착하게 떨쳐 버리자 섬 사람들은 두려움과 놀라움으로 바라본다", "몰타의 집 안에서 바울이 보블리오의 아버지 머리에 손을 얹어 기도하고, 병자는 침상에서 힘을 얻어 일어나며 가족들이 기뻐 다가온다", "로마 셋집에서 나이 든 바울이 결박 중에도 담대한 얼굴로 방문객들에게 하나님 나라와 주 예수 그리스도를 가르친다"]'::jsonb, '["몰타 섬 사람들이 바닷물에 젖은 바울 일행을 불쌍히 여겨 불을 피워 준다", "독사가 바울의 손에 매달리지만 침착하게 떨쳐 버리고 섬 사람들은 놀라움으로 바라본다", "몰타의 집 안에서 바울이 보블리오의 아버지 머리에 손을 얹어 기도하고 병자가 낫는다", "로마 셋집에서 바울이 결박 중에도 담대한 얼굴로 방문객들에게 하나님 나라와 주 예수 그리스도를 가르친다"]'::jsonb, '[["paul"], ["paul"], ["paul"], ["paul"]]'::jsonb, ARRAY['paul']::text[], '[{"book": "행", "from": "28:1", "to": "28:31"}]'::jsonb, 60, 62, 'approx', 44, 'paul_arrest_rome_witness', '바울의 체포와 로마 복음 전파', 5, 'lm_nt_ap_rome', 'published'),
    ('era_nt_public_ministry', '베드로의 부인', '베드로는 대제사장의 뜰에서 세 번 예수님을 모른다고 부인하고 닭 울음 뒤에 통곡한다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「베드로의 부인」을 다룹니다.', '["예수님이 붙잡혀 가신 뒤 베드로가 멀찍이 따라 대제사장의 뜰로 들어간다", "대제사장의 뜰 뒷편에서 베드로가 사람들의 질문 앞에서 예수님을 모른다고 부인한다", "세 번째 부인 뒤 닭이 울고 베드로가 대제사장의 뜰에서 잡혀가는 예수님과 멀리서 눈이 마주친다", "대제사장의 뜰 바깥 어두운 골목에서 베드로가 외투로 얼굴을 감싸고 무너진 마음으로 통곡한다"]'::jsonb, '["예수님이 붙잡혀 가신 뒤 베드로가 멀찍이 따라 대제사장의 뜰로 들어간다", "대제사장의 뜰 뒷편에서 베드로가 사람들의 질문 앞에서 예수님을 모른다고 부인한다", "세 번째 부인 뒤 닭이 울고 베드로가 대제사장의 뜰에서 잡혀가는 예수님과 멀리서 눈이 마주친다", "대제사장의 뜰 바깥 어두운 골목에서 베드로가 외투로 얼굴을 감싸고 무너진 마음으로 통곡한다"]'::jsonb, '[["peter"], ["peter"], ["peter", "jesus"], ["peter"]]'::jsonb, ARRAY['jesus', 'peter']::text[], '[{"book": "마", "from": "26:69", "to": "26:75"}, {"book": "막", "from": "14:66", "to": "14:72"}, {"book": "눅", "from": "22:54", "to": "22:62"}, {"book": "요", "from": "18:15", "to": "18:27"}]'::jsonb, 33, 33, 'approx', 44, 'passion_week', '고난주간', 4, 'lm_nt_pm_jerusalem', 'published'),
    ('era_divided_kingdom', '요시야의 개혁: 율법책을 찾다', '어린 나이에 왕이 된 요시야는 여호와의 길을 따르고, 발견된 율법책 앞에서 회개하며 유다의 우상 숭배를 정리한다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「요시야의 개혁」을 다룹니다.', '["8살의 어린 요시야가 예루살렘에서 왕으로 세워지고, 다윗의 길을 따라 여호와 보시기에 정직히 행하자 하나님이 기뻐하시는 따뜻한 영광의 빛이 어린 왕과 왕궁 위에 임하는 장면", "왕위 18년, 약 26세의 요시야 왕이 미장공과 목수와 건축자들에게 성전 보수를 맡긴 가운데, 대제사장 힐기야가 성전 안에서 오래 잊힌 율법책 두루마리를 발견하고 놀라는 장면", "서기관 사반이 율법책을 약 26세의 요시야 왕 앞에서 읽어 주자, 요시야가 눈물로 옷을 찢으며 하나님께 부르짖고, 신하들은 충격을 받아 조용히 서 있는 장면, 그 말의 뜻을 보여 주는 글자 없는 말풍선 안에는 펼친 두루마리와 말씀을 듣고 밝은 길로 걷는 사람들이 보이는 장면이 작은 그림처럼 보인다", "약 26세의 요시야 왕이 백성들 앞에서 율법책을 낭독하고 언약을 세우며, 주변에서는 군사들과 제사장들이 바알 신상과 아세라 목상을 부수어 성전 밖으로 치우는 장면. 피와 폭력은 보이지 않고, 글자는 읽히지 않는다"]'::jsonb, '["8살의 어린 요시야가 예루살렘에서 왕으로 세워진다", "26세 요시야 왕이 성전 보수 도중 오래 잊힌 율법책을 찾고 놀란다", "서기관 사반이 율법책을 읽고 요시야가 옷을 찢으며 하나님을 부르짖는다", "요시야가 율법책을 백성 앞에서 낭독하고 우상을 제거한다"]'::jsonb, '[["josiah"], ["josiah"], ["josiah"], ["josiah"]]'::jsonb, ARRAY['josiah']::text[], '[{"book": "왕하", "from": "22:1", "to": "22:13"}, {"book": "왕하", "from": "23:1", "to": "23:21"}]'::jsonb, -622, -622, 'approx', 44, 'divided_judah_final_fall', '남유다의 마지막 회복과 멸망', 5, 'lm_div_jerusalem', 'published'),
    ('era_divided_kingdom', '여호아하스: 애굽으로 끌려간 왕', '요시야 뒤에 세워진 여호아하스는 짧게 악을 행하고, 바로 느고에게 붙잡혀 애굽으로 끌려간다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「여호아하스」를 다룹니다.', '["스물세 살 유다 왕 여호아하스가 왕이 되어 예루살렘 성전 안에 작은 우상들을 세우고 악한 길을 택하며, 젊은 왕의 얼굴에는 불안한 교만이 보이는 장면", "바로 느고의 애굽 군사들이 여호아하스를 붙잡아 데려가고, 여호아하스는 침울한 표정으로 예루살렘을 떠나며 주변 백성들은 두려워하는 장면. 피와 폭력의 세부 묘사는 보이지 않는다"]'::jsonb, '["스물세 살 유다 왕 여호아하스가 왕이 되어 예루살렘 성전 안에 작은 우상들을 세우고 악한 길을 택한다", "바로 느고의 애굽 군사들이 여호아하스를 붙잡아 데려간다"]'::jsonb, '[["jehoahaz_judah"], ["jehoahaz_judah"]]'::jsonb, ARRAY['jehoahaz_judah']::text[], '[{"book": "왕하", "from": "23:31", "to": "23:35"}, {"book": "대하", "from": "36:2", "to": "36:4"}]'::jsonb, -609, -609, 'approx', 45, 'divided_judah_final_fall', '남유다의 마지막 회복과 멸망', 5, 'lm_div_jerusalem_jehoahaz_judah', 'published'),
    ('era_nt_public_ministry', '유대 지도자들 앞 재판', '예수님은 유대 지도자들 앞에서 거짓 증언과 모욕을 받으시고 자신이 하나님의 아들임을 증언하신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「유대 지도자들 앞 재판」을 다룹니다.', '["예수님이 손이 묶인 채 대제사장의 집 안뜰로 끌려가고, 지도자들은 밤중의 기름등잔 아래 엄숙하고 적대적인 얼굴로 모인다", "대제사장들, 율법학자들, 장로들은 화가 나서 예수님을 추궁하고 예수님은 자신이 하나님의 아들이심을 말씀하신다", "대제사장들, 율법학자들, 장로들은 예수님에게 손가락질 하며 대답을 요구하고 예수님은 말씀하신다. 말풍선에는 예수님이 구름 위 권능의 보좌 오른편에 앉아있는 모습", "사람들이 눈을 가리고 예수님을 조롱하며 때리지만, 예수님은 상처 입은 얼굴로 고난을 묵묵히 견디신다"]'::jsonb, '["예수님이 손이 묶인 채 대제사장의 집 안뜰로 끌려간다", "대제사장들과 율법학자들이 예수님을 추궁하고 예수님은 자신이 하나님의 아들이심을 말씀하신다", "대제사장들, 율법학자들, 장로들에게 예수님은 구름 위 권능의 보좌 오른편에 앉을 것임을 말씀하신다", "사람들이 눈을 가리고 예수님을 조롱하며 때리다, 예수님은 상처 입은 얼굴로 고난을 묵묵히 견디신다"]'::jsonb, '[["jesus"], ["jesus"], ["jesus"], ["jesus"]]'::jsonb, ARRAY['jesus']::text[], '[{"book": "마", "from": "26:57", "to": "26:68"}, {"book": "막", "from": "14:53", "to": "14:65"}, {"book": "눅", "from": "22:63", "to": "22:71"}, {"book": "요", "from": "18:12", "to": "18:24"}]'::jsonb, 33, 33, 'approx', 45, 'passion_week', '고난주간', 4, 'lm_nt_pm_jerusalem', 'published'),
    ('era_nt_public_ministry', '빌라도 앞 재판', '예수님은 빌라도와 헤롯 앞에서 심문을 받으시고, 무리의 요구 속에 십자가형에 넘겨지신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「빌라도 앞 재판」을 다룹니다.', '["새벽에 결박된 예수님이 로마식 관저의 빌라도 앞에 서고, 종교 지도자들은 피곤하지만 분노한 얼굴로 고발을 이어 간다", "빌라도가 총독의 망토를 걸치고 재판석에서 예수님께 왕인지 묻지만, 예수님은 매 맞은 뒤에도 차분히 진리를 증언하신다", "대제사장들이 빌라도에게 소리쳐서 바라바를 놓아주라고 요구하고, 빌라도는 의아하다는 표정을 지으며 바라바를 풀어주고 예수를 계속 묶어 놓으라고 한다", "빌라도가 잘모르겠다는 제스쳐를 취하면서 무리의 요구대로 상처 입은 예수님을 십자가 형에 처하라고 한다"]'::jsonb, '["새벽에 결박된 예수님이 로마식 관저의 빌라도 앞에 서고 종교 지도자들이 고발을 이어간다", "빌라도가 예수님께 왕인지 묻고 예수님은 그렇다고 말씀하신다", "대제사장들이 빌라도에게 소리쳐서 바라바를 놓아주라고 요구한다", "빌라도가 잘모르겠다는 제스쳐를 취하면서 무리의 요구대로 상처 입은 예수님을 그들에게 넘기신다"]'::jsonb, '[["jesus", "pilate"], ["jesus", "pilate"], ["pilate", "jesus"], ["pilate", "jesus"]]'::jsonb, ARRAY['jesus', 'pilate', 'herod']::text[], '[{"book": "마", "from": "27:11", "to": "27:26"}, {"book": "막", "from": "15:1", "to": "15:15"}, {"book": "눅", "from": "23:1", "to": "23:25"}, {"book": "요", "from": "18:28", "to": "19:16"}]'::jsonb, 33, 33, 'approx', 46, 'passion_week', '고난주간', 4, 'lm_nt_pm_jerusalem', 'published'),
    ('era_divided_kingdom', '여호야김과 첫 포로: 다니엘이 끌려가다', '애굽이 세운 여호야김은 악을 행하고, 바벨론의 압박 속에서 성전 기물과 다니엘을 포함한 젊은 포로들이 바벨론으로 끌려간다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「여호야김과 첫 포로」를 다룹니다.', '["애굽 왕 바로 느고가 스물다섯 살의 엘리야김을 유다 왕으로 세우고 이름을 여호야김으로 바꾸게 하며, 여호야김은 왕관을 받지만 얼굴에는 불안과 욕망이 섞여 있는 장면", "유다 왕 여호야김이 예루살렘 성전과 왕궁 주변에서 우상을 섬기며 하나님 앞에 악을 행하고, 위쪽에는 하나님의 진노를 상징하는 엄중한 빛이 비치는 장면", "여호야김이 바벨론 왕의 군대 앞에서 쇠사슬에 묶이고, 성전의 금 기구들과 함께 유다 백성들이 포로로 끌려가며, 그 무리 속에는 어린 다니엘과 세 친구가 두려움 속에서도 믿음을 지키는 표정으로 서 있는 장면. 피와 폭력은 보이지 않는다"]'::jsonb, '["애굽 왕 바로 느고가 스물다섯 살의 엘리야김을 유다 왕으로 세운다", "유다 왕 여호야김이 예루살렘 성전과 왕궁 주변에서 우상을 섬기며 하나님 앞에 악을 행한다", "여호야김과 다니엘 일행이 성전 금 기구들과 함께 바벨론으로 끌려간다"]'::jsonb, '[["jehoiakim"], ["jehoiakim", "god"], ["jehoiakim", "daniel"]]'::jsonb, ARRAY['jehoiakim', 'daniel', 'god']::text[], '[{"book": "왕하", "from": "23:36", "to": "24:7"}, {"book": "대하", "from": "36:4", "to": "36:8"}, {"book": "단", "from": "1:1", "to": "1:2"}]'::jsonb, -609, -605, 'approx', 46, 'divided_judah_final_fall', '남유다의 마지막 회복과 멸망', 5, 'lm_div_jerusalem_jehoiakim_first_exile', 'published')
)
insert into events (era_id, title, summary, background_context, story_scenes, scene_captions, scene_characters, character_codes, bible_refs, start_year, end_year, time_precision, story_index, unit_code, unit_title, unit_order, landmark_id, status)
select
  e.id,
  s.title,
  s.summary,
  s.background_context,
  s.story_scenes,
  s.scene_captions,
  s.scene_characters,
  s.character_codes,
  s.bible_refs,
  s.start_year,
  s.end_year,
  s.time_precision,
  s.story_index,
  s.unit_code,
  s.unit_title,
  s.unit_order,
  lm.id,
  s.status
from seed_events s
join eras e on e.code = s.era_code
join landmarks lm on lm.code = s.landmark_code
on conflict (era_id, story_index) do update set
  title = excluded.title,
  summary = excluded.summary,
  background_context = excluded.background_context,
  story_scenes = excluded.story_scenes,
  scene_captions = excluded.scene_captions,
  scene_characters = excluded.scene_characters,
  character_codes = excluded.character_codes,
  bible_refs = excluded.bible_refs,
  start_year = excluded.start_year,
  end_year = excluded.end_year,
  time_precision = excluded.time_precision,
  unit_code = excluded.unit_code,
  unit_title = excluded.unit_title,
  unit_order = excluded.unit_order,
  landmark_id = excluded.landmark_id,
  status = excluded.status
;

with seed_events (era_code, title, summary, background_context, story_scenes, scene_captions, scene_characters, character_codes, bible_refs, start_year, end_year, time_precision, story_index, unit_code, unit_title, unit_order, landmark_code, status) as (
  values
    ('era_nt_public_ministry', '십자가', '예수님은 골고다에서 십자가에 못 박혀 죽으시고, 마지막까지 용서와 구원을 이루신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「십자가」를 다룹니다.', '["채찍질과 조롱 뒤 지친 예수님이 십자가를 지고 골고다로 향하시고, 로마 군인들과 울며 따라가는 사람들이 좁은 길을 메운다", "예수님이 두 행악자 사이에 십자가에 달리시고, 군인들은 아래에서 옷을 나누며 무리와 지도자들은 조롱과 두려움이 섞인 얼굴로 바라본다", "십자가 아래에서 나이 든 어머니 마리아와 사랑하는 제자 요한, 막달라 마리아가 눈물로 서 있고, 예수님은 어머니와 제자를 서로에게 맡기신다", "예수님이 숨을 거두시자 하늘이 어두워지고 땅이 흔들리며, 로마 백부장과 지켜보던 사람들은 두려움과 경외로 뒤로 물러선다"]'::jsonb, '["채찍질과 조롱 뒤 지친 예수님이 십자가를 지고 골고다로 향하신다", "예수님이 두 행악자 사이에 십자가에 달리시다", "십자가 아래에서 나이 든 어머니 마리아와 사랑하는 제자 요한, 막달라 마리아가 눈물을 흘린다", "예수님이 숨을 거두시자 하늘이 어두워지고 땅이 흔들린다"]'::jsonb, '[["jesus"], ["jesus"], ["jesus", "mary", "john", "mary_magdalene"], ["jesus"]]'::jsonb, ARRAY['jesus', 'mary', 'john', 'mary_magdalene']::text[], '[{"book": "마", "from": "27:32", "to": "27:56"}, {"book": "막", "from": "15:21", "to": "15:41"}, {"book": "눅", "from": "23:26", "to": "23:49"}, {"book": "요", "from": "19:16", "to": "19:37"}]'::jsonb, 33, 33, 'approx', 47, 'passion_week', '고난주간', 4, 'lm_nt_pm_golgotha', 'published'),
    ('era_divided_kingdom', '예레미야의 경고: 칠십 년의 포로', '예레미야는 유다가 말씀을 듣지 않았기에 바벨론을 섬기게 되지만, 정한 때가 차면 바벨론도 심판받을 것이라고 선포한다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「예레미야의 경고」를 다룹니다.', '["예레미야 선지자가 유다 백성 앞에서 엄중히 말하고, 그 말의 뜻을 보여 주는 글자 없는 말풍선 안에는 잘못된 길에서 돌이키라는 경고와 멈춰 선 사람들이 보이는 장면이 작은 그림처럼 보인다", "예레미야 선지자가 울지 않고 곧게 서서 한 손을 들어 백성들에게 담대하고 단호하게 선포하는 장면. 큰 글자 없는 말풍선 안에는 칠십 년 뒤 바벨론 왕이 왕좌에서 무너지고, 바벨론 성읍과 높은 성벽이 하나님의 처벌로 붕괴되는 상징 그림이 선명하게 보인다. 피와 시신은 보이지 않는다"]'::jsonb, '["예레미야가 백성들에게 70년 동안 바벨론을 섬기게 될 것을 말한다", "예레미야 선지자가 백성들에게 70년 뒤 바벨론 왕좌가 무너질 것을 말한다"]'::jsonb, '[["jeremiah"], ["jeremiah"]]'::jsonb, ARRAY['jeremiah']::text[], '[{"book": "렘", "from": "25:1", "to": "25:14"}]'::jsonb, -605, -605, 'approx', 47, 'divided_judah_final_fall', '남유다의 마지막 회복과 멸망', 5, 'lm_div_jerusalem', 'published'),
    ('era_nt_public_ministry', '빈 무덤과 여인들', '안식 후 첫날 여인들이 빈 무덤을 발견하고, 부활하신 예수님은 막달라 마리아에게 나타나신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「빈 무덤과 여인들」을 다룹니다.', '["새벽 어스름에 막달라 마리아와 여인들이 향품 항아리를 품고 무덤으로 향하는 모습 무덤 입구 돌문은 저 멀리 열린 채로 보인다", "무덤 돌이 굴려져 있고 흰 옷의 천사들이 빈 무덤 곁에서 부활 소식을 알리며, 여인들은 두려움과 기쁨으로 몸을 숙인다", "베드로와 요한이 숨 가쁘게 달려와 빈 무덤의 세마포와 머리 수건을 보고, 놀람과 깨달음이 섞인 얼굴로 서로를 바라본다", "동산 무덤가에서 부활하신 예수님이 막달라 마리아를 이름으로 부르시고, 그녀는 눈물에서 기쁨으로 바뀐 얼굴로 돌아본다"]'::jsonb, '["새벽 어스름에 막달라 마리아와 여인들이 향품 항아리를 품고 무덤으로 향한다", "무덤 돌이 굴려져 있고 흰 옷의 천사들이 빈 무덤 곁에서 부활 소식을 알린다", "베드로와 요한이 숨 가쁘게 달려와 빈 무덤의 세마포와 머리 수건을 본다", "동산 무덤가에서 부활하신 예수님이 막달라 마리아를 이름으로 부르시다"]'::jsonb, '[["mary_magdalene"], ["mary_magdalene"], ["peter", "john"], ["jesus", "mary_magdalene"]]'::jsonb, ARRAY['jesus', 'mary_magdalene', 'peter', 'john']::text[], '[{"book": "마", "from": "28:1", "to": "28:10"}, {"book": "막", "from": "16:1", "to": "16:8"}, {"book": "눅", "from": "24:1", "to": "24:12"}, {"book": "요", "from": "20:1", "to": "20:18"}]'::jsonb, 33, 33, 'approx', 48, 'resurrection_ascension', '부활과 승천', 5, 'lm_nt_pm_jerusalem', 'published'),
    ('era_divided_kingdom', '새 언약의 약속: 마음에 새기다', '예레미야는 무너진 백성에게 회복과 새 언약을 전하며, 하나님이 말씀을 마음에 새기실 날을 바라보게 한다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「새 언약의 약속」을 다룹니다.', '["예레미야가 백성들에게 회복의 약속을 말하고, 큰 글자 없는 말풍선 안에는 이스라엘 백성들이 소고를 들고 춤추며, 포도나무 열매를 먹고, 모두가 기뻐하는 모습이 보인다", "예레미야가 백성들에게 말하고, 큰 글자 없는 말풍선 안에는 하나님이 보내신 선한 목자가 양 떼를 모아 안전하게 지키는 모습이 보인다", "예레미야가 백성들에게 강하게 말하고, 큰 글자 없는 말풍선 안에는 하나님이 타락한 예루살렘 백성들에게 돌아오라고 부르시며 회개를 촉구하는 상징 그림이 보인다. 백성들은 우상에서 돌아서려는 모습이다", "예레미야가 백성들에게 새 언약을 말하고, 큰 글자 없는 말풍선 안에는 하나님의 빛이 백성들의 마음 가운데 율법을 새기고 서 있는 모습이 보인다"]'::jsonb, '["예레미야가 백성들에게 회복의 약속을 말한다", "예레미야가 백성들에게 하나님이 보내신 선한 목자에 대해 말한다", "예레미야가 백성들에게 백성들은 우상에서 돌아서서 회개를 촉구한다", "예레미야가 백성들에게 새 언약을 말하고 백성들의 마음에 율법이 새겨진다"]'::jsonb, '[["jeremiah"], ["jeremiah"], ["jeremiah"], ["jeremiah"]]'::jsonb, ARRAY['jeremiah']::text[], '[{"book": "렘", "from": "31:1", "to": "31:40"}]'::jsonb, -587, -587, 'approx', 48, 'divided_judah_final_fall', '남유다의 마지막 회복과 멸망', 5, 'lm_div_jerusalem', 'published'),
    ('era_divided_kingdom', '불태워진 두루마리: 말씀을 거부하다', '예레미야의 말씀이 바룩의 두루마리에 기록되어 낭독되지만, 여호야김은 말씀을 잘라 불태우며 거부한다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「불태워진 두루마리」를 다룹니다.', '["실내에서 예레미야 선지자가 바룩에게 하나님의 말씀을 전하고, 바룩은 낮은 책상 앞에서 예레미야가 말하는 내용을 긴 두루마리에 정성껏 적는 장면, 그 말의 뜻을 보여 주는 글자 없는 말풍선 안에는 펼친 성경 두루마리를 살피며 말씀을 확인하는 장면이 작은 그림처럼 보인다", "성전 뜰 앞에서 바룩이 두루마리를 펼쳐 백성들에게 선포하고, 사람들은 긴장한 표정으로 귀 기울인다. 두루마리에는 읽을 수 있는 글자가 보이지 않는다, 그 말의 뜻을 보여 주는 글자 없는 말풍선 안에는 펼친 성경 두루마리를 살피며 말씀을 확인하는 장면이 작은 그림처럼 보인다", "겨울 왕궁 안, 여후디가 여호야김 왕 앞에서 두루마리를 읽고, 여호야김은 사악하고 완고한 얼굴로 작은 칼로 두루마리를 잘라 화롯불에 넣는다. 불은 두루마리만 태우고 사람에게 번지지 않는다"]'::jsonb, '["실내에서 예레미야 선지자가 바룩에게 하나님의 말씀을 전하고 바룩은 적는다", "성전 뜰 앞에서 바룩이 두루마리를 펼쳐 백성들에게 선포한다", "여후디가 여호야김 왕에게 바룩의 두루마리를 읽고 여호야김은 칼로 두루마리를 잘라 화롯불에 넣는다"]'::jsonb, '[["jeremiah"], [], ["jehoiakim"]]'::jsonb, ARRAY['jeremiah', 'jehoiakim']::text[], '[{"book": "렘", "from": "36:1", "to": "36:26"}]'::jsonb, -605, -604, 'approx', 49, 'divided_judah_final_fall', '남유다의 마지막 회복과 멸망', 5, 'lm_div_jerusalem', 'published'),
    ('era_nt_public_ministry', '엠마오로 가는 두 제자', '부활하신 예수님은 엠마오로 가는 두 제자와 동행하시며 성경을 풀어 주시고 떡을 떼실 때 자신을 알아보게 하신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「엠마오로 가는 두 제자」를 다룹니다.', '["글로바와 다른 한 제자가 여행용 망토를 걸치고 예루살렘을 떠나 엠마오 길을 걸으며, 어깨가 처진 채 십자가 일을 슬퍼하며 이야기한다", "부활하신 예수님이 가까이 오셔서 먼지 묻은 길을 함께 걸으시지만, 두 제자는 근심 어린 얼굴로 그분을 알아보지 못한다", "예수님이 길가에서 모세와 선지자의 글을 가리키듯 손짓하며 그리스도에 관한 말씀을 풀어 주시고, 두 제자는 마음이 뜨거워지는 표정으로 듣는다", "엠마오 집 식탁에서 예수님이 떡을 떼실 때 두 제자의 눈이 열리고, 그들은 놀라움과 기쁨으로 곧 예루살렘으로 돌아갈 채비를 한다"]'::jsonb, '["글로바와 다른 한 제자가 여행용 망토를 걸치고 예루살렘을 떠나 엠마오 길을 걷는다", "부활하신 예수님이 가까이 오셔서 먼지 묻은 길을 함께 걸으시다", "예수님이 길가에서 모세와 선지자의 글을 가리키듯 그리스도에 관한 말씀을 풀어 주시다", "엠마오 집 식탁에서 예수님이 떡을 떼실 때 두 제자의 눈이 열리다"]'::jsonb, '[[], ["jesus"], ["jesus"], ["jesus"]]'::jsonb, ARRAY['jesus']::text[], '[{"book": "눅", "from": "24:13", "to": "24:35"}]'::jsonb, 33, 33, 'approx', 49, 'resurrection_ascension', '부활과 승천', 5, 'rgn_judea', 'published'),
    ('era_divided_kingdom', '여호야긴의 포로: 성전 금 기구가 깨어지다', '여호야긴 때 예루살렘은 바벨론에 굴복하고, 왕과 에스겔을 포함한 백성이 포로로 끌려가며 시드기야가 마지막 왕으로 세워진다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「여호야긴의 포로」를 다룹니다.', '["열여덟 살 유다 왕 여호야긴이 왕이 되었지만 예루살렘 성전 안에서 우상 앞에 서서 악한 길을 택하고, 젊은 왕의 얼굴에는 불안하고 미숙한 표정이 보이는 장면", "여호야긴과 어머니와 신하들, 에스겔과 많은 백성들이 바벨론 포로로 끌려가며 예루살렘 성문을 떠나는 장면. 에스겔은 젊은 제사장 같은 모습으로 슬프지만 하나님을 바라보는 표정이다", "느부갓네살 왕의 군사들이 예루살렘 성전에서 금 기구들을 꺼내어 산산조각 내고 바벨론으로 가져가며, 성전 안은 텅 비고 무거운 분위기가 되는 장면. 피와 폭력은 보이지 않는다", "느부갓네살 왕이 맛다니야를 시드기야라는 이름의 남유다 왕으로 세우고, 시드기야는 왕관을 받지만 슬프고 두려운 얼굴로 서 있는 장면"]'::jsonb, '["열여덟 살 유다 왕 여호야긴이 왕이 되었지만 예루살렘 성전 안에서 우상 앞에 서서 악한 길을 택한다", "여호야긴과 제사장 에스겔과 많은 백성들이 바벨론 포로로 끌려간다", "느부갓네살 왕의 군사들이 예루살렘 성전에서 금 기구들을 꺼내어 산산조각 내고 바벨론으로 가져간다", "느부갓네살 왕이 맛다니야를 시드기야라는 이름의 남유다 왕으로 세운다"]'::jsonb, '[["jehoiachin"], ["jehoiachin", "ezekiel"], [], ["zedekiah"]]'::jsonb, ARRAY['jehoiachin', 'ezekiel', 'zedekiah']::text[], '[{"book": "왕하", "from": "24:8", "to": "24:17"}, {"book": "대하", "from": "36:9", "to": "36:10"}, {"book": "겔", "from": "1:1", "to": "1:3"}]'::jsonb, -597, -597, 'approx', 50, 'divided_judah_final_fall', '남유다의 마지막 회복과 멸망', 5, 'lm_div_jerusalem_jehoiachin_exile', 'published'),
    ('era_nt_public_ministry', '제자들에게 나타나심', '부활하신 예수님은 두려워하는 제자들에게 평강을 주시고 도마와 베드로를 회복시키시며 사명을 맡기신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「제자들에게 나타나심」을 다룹니다.', '["문이 굳게 닫힌 방에서 두려워하던 제자들 가운데 부활하신 예수님이 오셔서 손과 옆구리의 상처를 보이시며 평강을 전하신다", "도마가 예수님의 손과 옆구리 상처를 보고 떨리는 손을 가슴에 모으며, 의심이 경배로 바뀐 얼굴로 고백한다", "갈릴리 호수의 새벽, 밤새 고기 잡지 못해 지친 제자들이 빈 그물을 붙잡고 있을 때 예수님이 물가에서 그물을 던지게 하신다", "숯불이 피어 있는 호숫가에서 예수님이 베드로에게 사랑을 물으시고, 베드로는 회한과 회복의 눈빛으로 내 양을 먹이라는 맡김을 듣는다"]'::jsonb, '["문이 굳게 닫힌 방에서 두려워하던 제자들 가운데 부활하신 예수님이 오셔서 손과 옆구리의 상처를 보이시다", "도마가 예수님의 손과 옆구리 상처를 보고 떨리는 손을 가슴에 모은다", "밤새 고기 잡지 못해 지친 제자들이 빈 그물을 붙잡고 있을 때 예수님이 물가에서 그물을 던지게 하신다", "숯불이 피어 있는 호숫가에서 예수님이 베드로에게 사랑하냐 물으시다"]'::jsonb, '[["jesus", "peter", "andrew", "james_zebedee", "john", "philip", "bartholomew", "matthew", "james_alphaeus", "thaddaeus", "simon_zealot"], ["jesus", "thomas"], ["jesus", "peter", "thomas", "bartholomew", "james_zebedee", "john"], ["jesus", "peter"]]'::jsonb, ARRAY['jesus', 'peter', 'john', 'thomas', 'mary_magdalene', 'james_zebedee', 'bartholomew', 'andrew', 'philip', 'matthew', 'james_alphaeus', 'thaddaeus', 'simon_zealot']::text[], '[{"book": "눅", "from": "24:36", "to": "24:49"}, {"book": "마", "from": "28:16", "to": "28:20"}, {"book": "요", "from": "20:19", "to": "21:19"}]'::jsonb, 33, 33, 'approx', 50, 'resurrection_ascension', '부활과 승천', 5, 'lm_nt_pm_jerusalem', 'published'),
    ('era_nt_public_ministry', '대위임령과 승천', '예수님은 모든 민족을 제자로 삼으라는 사명을 주시고 감람산에서 승천하시며 다시 오실 약속을 남기신다.', '복음서의 예수님 이야기는 예수님의 탄생, 공적 사역, 십자가와 부활로 이어집니다. 이 이야기는 「대위임령과 승천」을 다룹니다.', '["갈릴리 산에서 부활하신 예수님이 열한 제자 앞에 서서 하늘과 땅의 모든 권세를 받으셨다고 말씀하시고, 제자들은 경배와 망설임이 섞인 얼굴로 엎드린다", "예수님이 모든 민족을 제자로 삼고 세례를 베풀며 가르치라고 손을 들어 명하시고, 열한 제자는 먼 나라를 향한 사명을 받는 굳은 표정으로 듣는다", "감람산에서 예수님이 하늘로 올려지시고 성령의 권능과 땅끝까지 증인의 사명을 약속하시고, 제자들 예수님을 바라본다"]'::jsonb, '["부활하신 예수님이 제자들 앞에 서서 하늘과 땅의 모든 권세를 받으셨다고 말씀하신다", "예수님이 모든 민족을 제자로 삼고 세례를 베풀며 가르치라고 손을 들어 명하신다", "감람산에서 예수님이 하늘로 올려지시고 성령의 권능과 땅끝까지 증인의 사명을 약속하신다"]'::jsonb, '[["jesus"], ["jesus"], ["jesus"]]'::jsonb, ARRAY['jesus', 'peter', 'john', 'andrew', 'james_zebedee', 'philip', 'bartholomew', 'matthew', 'thomas', 'james_alphaeus', 'thaddaeus', 'simon_zealot']::text[], '[{"book": "마", "from": "28:18", "to": "28:20"}, {"book": "막", "from": "16:15", "to": "16:18"}, {"book": "눅", "from": "24:46", "to": "24:53"}, {"book": "행", "from": "1:6", "to": "1:11"}]'::jsonb, 33, 33, 'approx', 51, 'resurrection_ascension', '부활과 승천', 5, 'lm_nt_pm_gethsemane', 'published'),
    ('era_divided_kingdom', '토굴의 예레미야: 왕에게 전하다', '시드기야 때 예레미야는 거짓 고발로 갇히지만, 왕 앞에서도 바벨론에게 넘겨질 말씀을 굽히지 않는다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「토굴의 예레미야」를 다룹니다.', '["예레미야가 시드기야 왕에게 말하고, 큰 글자 없는 말풍선 안에는 바벨론 군대가 다시 예루살렘으로 돌아와 싸우는 그림이 보인다. 시드기야는 불안한 표정으로 듣는다", "베냐민 성문에서 문지기 우두머리가 예레미야를 향해 배반자라고 소리치고, 예레미야 선지자는 억울하고 단호한 얼굴로 거짓말이라고 맞서 말하는 장면, 그 말의 뜻을 보여 주는 글자 없는 말풍선 안에는 억울한 선지자와 닫힌 성문, 진실을 가리는 손짓이 보이는 장면이 작은 그림처럼 보인다", "예레미야가 어둡고 좁은 토굴 속 감옥에 갇혀 앉아 있지만, 무너지지 않는 믿음으로 조용히 버티는 장면. 피와 폭력은 보이지 않는다", "시드기야 왕이 예레미야를 다시 불러 은밀히 묻고, 예레미야가 시드기야 왕에게 바벨론 왕의 손에 넘겨질 것이라고 전한다. 큰 글자 없는 말풍선 안에는 시드기야가 바벨론 왕 앞에 넘겨지는 상징 그림이 보인다"]'::jsonb, '["예레미야가 시드기야 왕에게 바벨론 군대(갈대아인)가 다시와서 이 성을 불사를 것을 말한다", "베냐민 성문에서 문지기 우두머리가 예레미야를 향해 배반자라고 소리치다", "예레미야가 어둡고 좁은 토굴 속 감옥에 갇혀 앉아 있다", "시드기야 왕이 예레미야를 다시 불러 은밀히 묻고 예레미야는 바벨론에게 넘겨질 것임을 말한다"]'::jsonb, '[["jeremiah", "zedekiah"], ["jeremiah"], ["jeremiah"], ["jeremiah", "zedekiah"]]'::jsonb, ARRAY['jeremiah', 'zedekiah']::text[], '[{"book": "렘", "from": "37:1", "to": "37:21"}]'::jsonb, -588, -588, 'approx', 51, 'divided_judah_final_fall', '남유다의 마지막 회복과 멸망', 5, 'lm_div_jerusalem', 'published'),
    ('era_divided_kingdom', '예루살렘 포위: 왕의 몰락', '포위는 길어지고, 마지막 순간 왕과 도시는 무너진다.', '분열왕국 시대는 솔로몬 이후 남유다와 북이스라엘로 나뉜 시기입니다. 이 이야기는 「예루살렘 포위」를 다룹니다.', '["예루살렘 왕궁 안에서 시드기야가 여호와를 배반하고 작은 우상들을 궁전에 들여놓으며, 백성들이 그 우상들 앞에 엎드려 섬기는 모습", "바벨론 군대가 시드기야가 있는 예루살렘 성을 사방에서 둘러싸고 토성을 쌓아 공격하며, 성벽 위 사람들은 두려워하고 시드기야는 성 안에서 절망하는 장면", "시드기야가 바벨론 군사들에게 붙잡혀 눈에 어두운 안대를 하고 사슬에 묶인 채 바벨론으로 끌려가는 장면. 피와 상처는 직접 보이지 않는다"]'::jsonb, '["예루살렘 왕궁 안에서 시드기야가 여호와를 배반하고 작은 우상들을 궁전에 들여놓는다", "바벨론 군대가 시드기야가 있는 예루살렘 성을 사방에서 둘러싸고 공격한다", "시드기야가 바벨론 군사들에게 붙잡혀 눈에 어두운 안대를 하고 사슬에 묶인 채 바벨론으로 끌려간다"]'::jsonb, '[["zedekiah"], [], ["zedekiah"]]'::jsonb, ARRAY['zedekiah']::text[], '[{"book": "왕하", "from": "24:18", "to": "25:7"}]'::jsonb, -588, -586, 'approx', 52, 'divided_judah_final_fall', '남유다의 마지막 회복과 멸망', 5, 'lm_div_jerusalem', 'published')
)
insert into events (era_id, title, summary, background_context, story_scenes, scene_captions, scene_characters, character_codes, bible_refs, start_year, end_year, time_precision, story_index, unit_code, unit_title, unit_order, landmark_id, status)
select
  e.id,
  s.title,
  s.summary,
  s.background_context,
  s.story_scenes,
  s.scene_captions,
  s.scene_characters,
  s.character_codes,
  s.bible_refs,
  s.start_year,
  s.end_year,
  s.time_precision,
  s.story_index,
  s.unit_code,
  s.unit_title,
  s.unit_order,
  lm.id,
  s.status
from seed_events s
join eras e on e.code = s.era_code
join landmarks lm on lm.code = s.landmark_code
on conflict (era_id, story_index) do update set
  title = excluded.title,
  summary = excluded.summary,
  background_context = excluded.background_context,
  story_scenes = excluded.story_scenes,
  scene_captions = excluded.scene_captions,
  scene_characters = excluded.scene_characters,
  character_codes = excluded.character_codes,
  bible_refs = excluded.bible_refs,
  start_year = excluded.start_year,
  end_year = excluded.end_year,
  time_precision = excluded.time_precision,
  unit_code = excluded.unit_code,
  unit_title = excluded.unit_title,
  unit_order = excluded.unit_order,
  landmark_id = excluded.landmark_id,
  status = excluded.status
;


alter table events enable trigger trg_notify_on_new_event;
commit;
